log() {
  local level="$1"; shift
  local msg="$*"
  local ts
  ts="$(date -u '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null || date)"
  printf '%s [%s] %s\n' "$ts" "$level" "$msg" >&2
  if [[ -n "${LOG_FILE:-}" && -d "$(dirname "$LOG_FILE")" ]]; then
    printf '%s [%s] %s\n' "$ts" "$level" "$msg" >>"$LOG_FILE" 2>/dev/null || true
  fi
}

die() {
  local code="$1"; shift
  log ERROR "$* (exit=${code})"
  exit "$code"
}

# Markers for EXIT-trap silent-success / SIGPIPE guards (set during main/preflight).
_OS_PREFLIGHT_ENTERED=0
_PREFLIGHT_EXIT_GUARD_DONE=0
_CONTROL_FLOW_EVIDENCE_DIR=""
CROSS_RELEASE_TMP=""

maybe_enable_control_flow_debug() {
  # Opt-in only (DP_OFFLINE_DEBUG_CONTROL_FLOW=1). Never dump secrets/key material.
  [[ "${DP_OFFLINE_DEBUG_CONTROL_FLOW:-0}" == "1" ]] || return 0
  local stamp evid
  stamp="$(date -u '+%Y%m%dT%H%M%SZ')"
  evid="$(hostpath ${STATE_ROOT}/evidence/preflight-control-flow/${stamp})"
  mkdir -p "$evid"
  _CONTROL_FLOW_EVIDENCE_DIR="$evid"
  {
    printf 'UTC=%s\n' "$stamp"
    printf 'SCRIPT_PATH=%s\n' "${SCRIPT_PATH:-}"
    printf 'DRY_PREFLIGHT_ONLY=%s\n' "${DRY_PREFLIGHT_ONLY:-0}"
    printf 'TEST_ROOT_SET=%s\n' "$([[ -n "${TEST_ROOT:-}" ]] && echo YES || echo NO)"
    printf 'PIN_HOP=%s\n' "${PIN_HOP:-}"
    printf 'MIRROR_BASE=%s\n' "${MIRROR_BASE:-}"
  } >"${evid}/environment-sanitized.txt"
  cp -a "$(hostpath "$STATE_FILE")" "${evid}/current-state.txt" 2>/dev/null || true
  cp -a "$(hostpath "$CURRENT_HOP_ENV_FILE")" "${evid}/current-hop.env" 2>/dev/null || true
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "${SCRIPT_PATH:-/dev/null}" 2>/dev/null | awk '{print $1}' >"${evid}/artifact-sha256.txt" || true
  fi
  : >"${evid}/function-checkpoints.log"
  # shellcheck disable=SC2094
  exec 9>>"${evid}/bash-xtrace.log"
  export BASH_XTRACEFD=9
  PS4='+${BASH_SOURCE}:${LINENO}:${FUNCNAME[0]}: '
  set -x
  log INFO "CONTROL_FLOW_DEBUG_EVIDENCE=${evid}"
}

guard_unexpected_preflight_exit() {
  # Called from EXIT trap. Converts silent PREFLIGHT success / SIGPIPE abort into EC_INTERNAL.
  local rc="$1"
  local st ver
  [[ "${_PREFLIGHT_EXIT_GUARD_DONE}" -eq 1 ]] && return 0
  _PREFLIGHT_EXIT_GUARD_DONE=1
  [[ "${DP_OFFLINE_ALLOW_PREFLIGHT_EXIT:-0}" == "1" ]] && return 0
  [[ "${_OS_PREFLIGHT_ENTERED}" -eq 1 ]] || return 0

  st="$(read_state 2>/dev/null || true)"
  ver="$(read_os_field VERSION_ID 2>/dev/null || true)"

  if [[ -n "${_CONTROL_FLOW_EVIDENCE_DIR:-}" ]]; then
    printf '%s\n' "$rc" >"${_CONTROL_FLOW_EVIDENCE_DIR}/exit-code" 2>/dev/null || true
    printf '%s\n' "${FUNCNAME[*]:-}" >"${_CONTROL_FLOW_EVIDENCE_DIR}/last-function.txt" 2>/dev/null || true
    printf '%s\n' "$st" >"${_CONTROL_FLOW_EVIDENCE_DIR}/current-state.txt" 2>/dev/null || true
  fi

  if [[ "$ver" != "$PIN_SOURCE_VERSION" ]]; then
    return 0
  fi
  case "$st" in
    PREFLIGHT|CONFIGURING) ;;
    *) return 0 ;;
  esac

  if [[ "$rc" -eq 141 ]]; then
    log ERROR "PREFLIGHT_ABORT_SIGPIPE=YES"
    log ERROR "PREFLIGHT_RETURN_STATE=${st}"
    log ERROR "FAIL_PREFLIGHT_CONTROL_FLOW_PIPEFAIL_SIGPIPE"
    log ERROR "HINT=apt-cache|awk early-exit under set -o pipefail previously aborted outer client"
    exit "$EC_INTERNAL"
  fi

  if [[ "$rc" -eq 0 && "${DRY_PREFLIGHT_ONLY:-0}" -eq 0 ]]; then
    log ERROR "PREFLIGHT_SILENT_SUCCESS_EXIT=YES"
    log ERROR "PREFLIGHT_RETURNED_WITHOUT_READY_STATE=YES"
    log ERROR "PREFLIGHT_RETURN_STATE=${st}"
    log ERROR "FAIL_PREFLIGHT_RETURNED_WITHOUT_READY_FOR_CONFIRMATION"
    exit "$EC_INTERNAL"
  fi
  return 0
}

main_exit_trap() {
  # Capture status BEFORE any `local`/assignment — `local rc=$?` clobbers $? to 0
  # (this was a contributor to silent PREFLIGHT "exit 0" reports under set -e aborts).
  _MAIN_EXIT_RC=$?
  local work_dir="$1"
  local rc="$_MAIN_EXIT_RC"
  rm -rf "$work_dir" 2>/dev/null || true
  guard_unexpected_preflight_exit "$rc"
}

assert_preflight_ready_state() {
  local preflight_state
  preflight_state="$(read_state)"
  if [[ "$preflight_state" != "READY_FOR_CONFIRMATION" ]]; then
    log ERROR "PREFLIGHT_RETURNED_WITHOUT_READY_STATE=YES"
    log ERROR "PREFLIGHT_RETURN_STATE=${preflight_state}"
    die "$EC_INTERNAL" "FAIL_PREFLIGHT_RETURNED_WITHOUT_READY_FOR_CONFIRMATION"
  fi
}

hostpath() {
  local p="$1"
  if [[ -n "$TEST_ROOT" ]]; then
    printf '%s%s' "$TEST_ROOT" "$p"
  else
    printf '%s' "$p"
  fi
}

usage() {
  cat <<EOF
Usage: sudo $(basename "$0") [--mirror-base URL] [--mode os-only] [--detach]

Phase 1 OS-only offline upgrade: Ubuntu ${PIN_SOURCE_VERSION} → ${PIN_TARGET_VERSION}.
Does not start subsequent hops or DP product validation/bringup.

Options:
  --mirror-base URL   Override pinned mirror base (default: ${PIN_MIRROR_BASE})
  --mode os-only      Phase 1 OS-only mode (default; product gates skipped)
  --detach            Start under systemd and return immediately without
                      attaching the local progress monitor
  --help              Show this help
EOF
}

b64_decode_to_file() {
  local b64="$1" dest="$2"
  # Ubuntu 22.04: base64 -d
  printf '%s\n' "$b64" | tr -d '\n' | base64 -d >"$dest"
}

sha256_file() {
  local f="$1"
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "$f" | awk '{print $1}'
  else
    die "$EC_CMDS" "sha256sum required"
  fi
}

version_is_mmp() {
  # True only for strict major.minor.patch (no suffix, no bare integers).
  [[ "${1:-}" =~ ^[0-9]+\.[0-9]+\.[0-9]+$ ]]
}

version_ge() {
  # return 0 if $1 >= $2 (strict major.minor.patch only; never feed raw strings to (( )))
  local a="$1" b="$2"
  local a1 a2 a3 b1 b2 b3
  version_is_mmp "$a" || return 1
  version_is_mmp "$b" || return 1
  IFS=. read -r a1 a2 a3 <<<"$a"
  IFS=. read -r b1 b2 b3 <<<"$b"
  if ((a1 != b1)); then ((a1 > b1)); return $?; fi
  if ((a2 != b2)); then ((a2 > b2)); return $?; fi
  ((a3 >= b3))
}

