DP_AELLA_CLI_OUTPUT=""

reset_aella_cli_capture() {
  DP_AELLA_CLI_CAPTURED=0
  DP_AELLA_CLI_RC_STATUS=""
  DP_AELLA_CLI_OUTPUT=""
}

# Verified on target DP: timeout 10 sh -c "printf 'show version\nquit\n' | aella_cli"
# Idempotent within one preflight — call reset_aella_cli_capture to re-probe.
capture_aella_cli_show_version() {
  local outf rc
  if [[ "${DP_AELLA_CLI_CAPTURED:-0}" -eq 1 ]]; then
    return 0
  fi
  DP_AELLA_CLI_CAPTURED=1
  DP_AELLA_CLI_RC_STATUS=""
  DP_AELLA_CLI_OUTPUT=""

  if ! command -v aella_cli >/dev/null 2>&1; then
    DP_AELLA_CLI_RC_STATUS="missing"
    return 1
  fi
  if ! command -v timeout >/dev/null 2>&1; then
    DP_AELLA_CLI_RC_STATUS="missing"
    return 1
  fi

  outf="$(mktemp)"
  set +e
  timeout 10 sh -c "printf 'show version\nquit\n' | aella_cli" >"$outf" 2>&1
  rc=$?
  set -e
  DP_AELLA_CLI_OUTPUT="$(cat "$outf" 2>/dev/null || true)"
  rm -f "$outf"

  if [[ "$rc" -eq 124 ]]; then
    DP_AELLA_CLI_RC_STATUS="timeout"
    return 1
  fi
  if [[ "$rc" -ne 0 ]]; then
    DP_AELLA_CLI_RC_STATUS="nonzero"
    return 1
  fi
  DP_AELLA_CLI_RC_STATUS="ok"
  return 0
}

# Authoritative release-image.yml keys that track the DP product release train.
# Observed on real DP 6.5.0 hosts (aella-cm-* share build 7942; stellar-conf /
# stellar-controller share build 111034); both normalize to the same product
# major.minor.patch. Do NOT include independent app/OSS components (kafka,
# keydb, spark, skupper-*, elasticsearch, connectors, etc.) — those carry their
# own semver and must never participate in product-version voting.
is_authoritative_release_image_key() {
  case "${1:-}" in
    aella-cm-master|aella-cm-bg|aella-cm-user|aella-cm-worker|stellar-conf|stellar-controller)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

# Extract exact major.minor.patch tokens from text (whitespace-delimited).
# Does not truncate longer forms such as 6.5.0.7942 or 6.5.0.7942-hash.
extract_mmp_tokens_from_text() {
  local text="${1:-}"
  local line token
  while IFS= read -r line || [[ -n "$line" ]]; do
    line="${line%$'\r'}"
    # shellcheck disable=SC2086
    for token in $line; do
      if version_is_mmp "$token"; then
        printf '%s\n' "$token"
      fi
    done
  done <<<"$text"
}

# Extract DataProcessor(<role>)> prompt roles (parenthetical only).
# Ignores Welcome text and free-form lines without this prompt shape.
extract_dataprocessor_roles_from_text() {
  local text="${1:-}"
  local line re matched
  re='DataProcessor\(([A-Za-z0-9_-]+)\)>'
  while IFS= read -r line || [[ -n "$line" ]]; do
    line="${line%$'\r'}"
    while [[ "$line" =~ $re ]]; do
      printf '%s\n' "${BASH_REMATCH[1]}"
      matched="${BASH_REMATCH[0]}"
      line="${line#*"$matched"}"
    done
  done <<<"$text"
}

# Normalize CLI / role-file topology labels to canonical forms used in logs.
canonicalize_dp_topology() {
  local raw="${1:-}"
  local low
  low="$(printf '%s' "$raw" | tr '[:upper:]' '[:lower:]' | tr '_' '-')"
  case "$low" in
    aio|all-in-one|allinone) printf 'AIO' ;;
    dl-master|dl) printf 'DL-Master' ;;
    da-master|da) printf 'DA-Master' ;;
    worker) printf 'Worker' ;;
    collector-master) printf 'Collector-Master' ;;
    collector-worker) printf 'Collector-Worker' ;;
    master) printf 'Master' ;;
    unknown|"") printf 'UNKNOWN' ;;
    *) printf '%s' "$raw" ;;
  esac
}

is_supported_dp_topology() {
  [[ "$(canonicalize_dp_topology "${1:-}")" == "AIO" ]]
}

is_cluster_dp_topology() {
  case "$(canonicalize_dp_topology "${1:-}")" in
    AIO|UNKNOWN|"") return 1 ;;
    *) return 0 ;;
  esac
}

# Authoritative keys only from release-image.yml.
# Accepts: name: 6.5.0 | 6.5.0.7942 | 6.5.0.7942-9ed2e58c1 → prints 6.5.0
# Rejects: comments, timestamps, non-allowlisted components.
collect_authoritative_release_image_versions() {
  local f="$1"
  local line re key
  # Bash 4.3: keep regex unquoted on the RHS of =~
  re='^[[:space:]]*([A-Za-z0-9_.-]+):[[:space:]]*([0-9]+\.[0-9]+\.[0-9]+)([.-][A-Za-z0-9.-]+)?[[:space:]]*$'
  while IFS= read -r line || [[ -n "$line" ]]; do
    [[ "$line" =~ ^[[:space:]]*# ]] && continue
    [[ "$line" =~ ^[[:space:]]*$ ]] && continue
    if [[ "$line" =~ $re ]]; then
      key="${BASH_REMATCH[1]}"
      if is_authoritative_release_image_key "$key"; then
        printf '%s\n' "${BASH_REMATCH[2]}"
      fi
    fi
  done <"$f"
}

# Parse product version from already-captured CLI output.
# Sets DP_VERSION_CLI_STATUS: ok|no_semver|inconsistent
# On ok: prints the single product version to stdout and returns 0.
parse_dp_version_from_cli_output() {
  local tmp uniq_n ver
  DP_VERSION_CLI_STATUS=""
  tmp="$(mktemp)"
  extract_mmp_tokens_from_text "${DP_AELLA_CLI_OUTPUT:-}" >"$tmp" || true
  sort -u "$tmp" -o "$tmp"
  uniq_n="$(wc -l <"$tmp" | tr -d ' ')"
  if [[ "${uniq_n:-0}" -eq 0 ]]; then
    rm -f "$tmp"
    DP_VERSION_CLI_STATUS="no_semver"
    return 1
  fi
  if [[ "$uniq_n" -gt 1 ]]; then
    rm -f "$tmp"
    DP_VERSION_CLI_STATUS="inconsistent"
    return 1
  fi
  ver="$(tr -d '[:space:]' <"$tmp")"
  rm -f "$tmp"
  if ! version_is_mmp "$ver"; then
    DP_VERSION_CLI_STATUS="no_semver"
    return 1
  fi
  DP_VERSION_CLI_STATUS="ok"
  printf '%s' "$ver"
  return 0
}

# Parse topology from already-captured CLI output (prompt parentheses only).
# Sets DP_TOPOLOGY_CLI_STATUS: ok|no_prompt|inconsistent
# On ok: prints canonical topology to stdout and returns 0.
parse_dp_topology_from_cli_output() {
  local tmp uniq_n role
  DP_TOPOLOGY_CLI_STATUS=""
  tmp="$(mktemp)"
  extract_dataprocessor_roles_from_text "${DP_AELLA_CLI_OUTPUT:-}" >"$tmp" || true
  # Canonicalize then unique
  local tmp2
  tmp2="$(mktemp)"
  while IFS= read -r role || [[ -n "$role" ]]; do
    [[ -z "${role:-}" ]] && continue
    printf '%s\n' "$(canonicalize_dp_topology "$role")"
  done <"$tmp" >"$tmp2"
  rm -f "$tmp"
  sort -u "$tmp2" -o "$tmp2"
  uniq_n="$(wc -l <"$tmp2" | tr -d ' ')"
  if [[ "${uniq_n:-0}" -eq 0 ]]; then
    rm -f "$tmp2"
    DP_TOPOLOGY_CLI_STATUS="no_prompt"
    return 1
  fi
  if [[ "$uniq_n" -gt 1 ]]; then
    rm -f "$tmp2"
    DP_TOPOLOGY_CLI_STATUS="inconsistent"
    return 1
  fi
  role="$(tr -d '[:space:]' <"$tmp2")"
  rm -f "$tmp2"
  DP_TOPOLOGY_CLI_STATUS="ok"
  printf '%s' "$role"
  return 0
}

# Secondary fallback: authoritative release-image.yml keys only (never whole-file vote).
# Sets DP_VERSION_* for release-image source; returns 0 on agreement.
detect_dp_version_from_release_image() {
  local image tmp uniq_n ver
  image="$(hostpath /opt/aelladata/release-image.yml)"
  DP_VERSION_SOURCE="/opt/aelladata/release-image.yml"
  DP_VERSION_COMMAND=""
  DP_VERSION_AUTHORITATIVE_RECORDS=0
  DP_VERSION_MATCHED_RECORDS=0

  if [[ ! -r "$image" ]]; then
    DP_VERSION_DETECT_STATUS="undetermined"
    DP_VERSION_CONSISTENCY="FAIL"
    return 1
  fi

  tmp="$(mktemp)"
  collect_authoritative_release_image_versions "$image" >"$tmp" || true
  DP_VERSION_AUTHORITATIVE_RECORDS="$(wc -l <"$tmp" | tr -d ' ')"
  DP_VERSION_MATCHED_RECORDS="$DP_VERSION_AUTHORITATIVE_RECORDS"

  if [[ "${DP_VERSION_AUTHORITATIVE_RECORDS:-0}" -lt 2 ]]; then
    rm -f "$tmp"
    DP_VERSION_DETECT_STATUS="undetermined"
    DP_VERSION_CONSISTENCY="FAIL"
    return 1
  fi

  sort -u "$tmp" -o "$tmp"
  uniq_n="$(wc -l <"$tmp" | tr -d ' ')"
  if [[ "$uniq_n" -gt 1 ]]; then
    rm -f "$tmp"
    DP_VERSION_DETECT_STATUS="inconsistent"
    DP_VERSION_CONSISTENCY="FAIL"
    log INFO "DP_VERSION_DIAG=INCONSISTENT authoritative release-image keys disagree (records=${DP_VERSION_AUTHORITATIVE_RECORDS} unique=${uniq_n})"
    return 1
  fi
  ver="$(tr -d '[:space:]' <"$tmp")"
  rm -f "$tmp"
  if ! version_is_mmp "$ver"; then
    DP_VERSION_DETECT_STATUS="undetermined"
    DP_VERSION_CONSISTENCY="FAIL"
    return 1
  fi

  DP_VERSION="$ver"
  DP_VERSION_CONSISTENCY="PASS"
  DP_VERSION_DETECT_STATUS="ok"
  return 0
}

# Read explicit vendor node-role files (exact content → canonical topology).
# These paths are the same appliance role files consulted by readiness collection.
# Does NOT treat /opt/aelladata/cluster-name alone as topology (present on real AIO).
collect_authoritative_topology_from_role_files() {
  local f content canon
  for f in \
    "$(hostpath /opt/aelladata/conf/role)" \
    "$(hostpath /opt/aelladata/role)" \
    "$(hostpath /opt/aelladata/cluster/role)" \
    "$(hostpath /etc/aella/role)"
  do
    [[ -r "$f" ]] || continue
    content="$(tr -d '\r\n' <"$f" | sed 's/^[[:space:]]*//;s/[[:space:]]*$//')"
    [[ -z "$content" ]] && continue
    # Single-token role labels only — reject free-form blobs.
    [[ "$content" =~ ^[A-Za-z0-9_-]+$ ]] || continue
    canon="$(canonicalize_dp_topology "$content")"
    [[ "$canon" == "UNKNOWN" ]] && continue
    printf '%s\n' "$canon"
  done
}

# True if worker inventory lists non-loopback peer IPs (multi-node cluster signal).
# Paths mirror collect-dp-upgrade-readiness.sh worker inventory locations.
authoritative_cluster_worker_ips_present() {
  local f ip tmp
  tmp="$(mktemp)"
  for f in \
    "$(hostpath /opt/aelladata/conf/worker_ips)" \
    "$(hostpath /opt/aelladata/worker_ips)" \
    "$(hostpath /opt/aelladata/conf/workers)" \
    "$(hostpath /opt/aelladata/cluster/workers)" \
    "$(hostpath /opt/aelladata/cluster/nodes)" \
    "$(hostpath /opt/aelladata/provision/workers)"
  do
    [[ -r "$f" ]] || continue
    grep -Eo '([0-9]{1,3}\.){3}[0-9]{1,3}' "$f" 2>/dev/null >>"$tmp" || true
  done
  while IFS= read -r ip || [[ -n "$ip" ]]; do
    [[ -z "${ip:-}" ]] && continue
    case "$ip" in
      127.*|0.0.0.0|::1) continue ;;
    esac
    rm -f "$tmp"
    return 0
  done <"$tmp"
  rm -f "$tmp"
  return 1
}

# Secondary topology fallback from explicit vendor role / worker inventory only.
# Weak signals intentionally ignored: process names, hostname, cluster-name presence,
# release-metadata free text, "AIO somewhere in a file", mere /opt/aelladata existence.
detect_dp_topology_from_vendor_files() {
  local tmp uniq_n role
  DP_TOPOLOGY_SOURCE="vendor-role-files"
  tmp="$(mktemp)"
  collect_authoritative_topology_from_role_files >"$tmp" || true
  sort -u "$tmp" -o "$tmp"
  uniq_n="$(wc -l <"$tmp" | tr -d ' ')"

  if [[ "${uniq_n:-0}" -gt 1 ]]; then
    rm -f "$tmp"
    DP_TOPOLOGY_DETECT_STATUS="inconsistent"
    DP_TOPOLOGY_CONSISTENCY="FAIL"
    log INFO "DP_TOPOLOGY_DIAG=INCONSISTENT authoritative role files disagree"
    return 1
  fi

  if [[ "${uniq_n:-0}" -eq 1 ]]; then
    role="$(tr -d '[:space:]' <"$tmp")"
    rm -f "$tmp"
    if authoritative_cluster_worker_ips_present && [[ "$role" == "AIO" ]]; then
      DP_TOPOLOGY_DETECT_STATUS="inconsistent"
      DP_TOPOLOGY_CONSISTENCY="FAIL"
      log INFO "DP_TOPOLOGY_DIAG=INCONSISTENT role file says AIO but worker inventory lists peer IPs"
      return 1
    fi
    DP_TOPOLOGY="$role"
    DP_TOPOLOGY_CONSISTENCY="PASS"
    DP_TOPOLOGY_DETECT_STATUS="ok"
    return 0
  fi
  rm -f "$tmp"

  # No role file: peer worker inventory alone means multi-node cluster (not AIO).
  if authoritative_cluster_worker_ips_present; then
    DP_TOPOLOGY="Worker"
    DP_TOPOLOGY_SOURCE="vendor-worker-inventory"
    DP_TOPOLOGY_CONSISTENCY="PASS"
    DP_TOPOLOGY_DETECT_STATUS="ok"
    return 0
  fi

  DP_TOPOLOGY=""
  DP_TOPOLOGY_DETECT_STATUS="undetermined"
  DP_TOPOLOGY_CONSISTENCY="FAIL"
  return 1
}

detect_dp_version() {
  # Priority:
  #   1) noninteractive aella_cli "show version" (primary; shared capture)
  #   2) authoritative keys in release-image.yml (fallback)
  # Never use release-metadata.yml (deploy timestamp) or whole-file component voting.
  #
  # Sets globals DP_VERSION / DP_VERSION_* ; also prints DP_VERSION on stdout.
  # Callers that need status MUST invoke without command substitution, e.g.:
  #   detect_dp_version >/dev/null || true
  #   dpver="$DP_VERSION"
  DP_VERSION=""
  DP_VERSION_SOURCE=""
  DP_VERSION_COMMAND=""
  DP_VERSION_MATCHED_RECORDS=0
  DP_VERSION_AUTHORITATIVE_RECORDS=0
  DP_VERSION_CONSISTENCY=""
  DP_VERSION_DETECT_STATUS="undetermined"
  DP_VERSION_CLI_STATUS=""

  if [[ -n "${DP_OFFLINE_FAKE_DP_VERSION:-}" ]]; then
    DP_VERSION="$DP_OFFLINE_FAKE_DP_VERSION"
    DP_VERSION_SOURCE="FAKE"
    DP_VERSION_MATCHED_RECORDS=1
    DP_VERSION_AUTHORITATIVE_RECORDS=1
    DP_VERSION_CONSISTENCY="PASS"
    DP_VERSION_DETECT_STATUS="ok"
    printf '%s' "$DP_VERSION"
    return 0
  fi

  capture_aella_cli_show_version || true

  local cli_ver cli_out
  cli_ver=""
  if [[ "${DP_AELLA_CLI_RC_STATUS}" == "ok" ]]; then
    cli_out="$(mktemp)"
    set +e
    parse_dp_version_from_cli_output >"$cli_out"
    set -e
    cli_ver="$(tr -d '[:space:]' <"$cli_out")"
    rm -f "$cli_out"
  else
    DP_VERSION_CLI_STATUS="${DP_AELLA_CLI_RC_STATUS:-missing}"
  fi

  case "${DP_VERSION_CLI_STATUS}" in
    ok)
      DP_VERSION="$cli_ver"
      DP_VERSION_SOURCE="aella_cli"
      DP_VERSION_COMMAND="noninteractive"
      DP_VERSION_MATCHED_RECORDS=1
      DP_VERSION_AUTHORITATIVE_RECORDS=0
      DP_VERSION_CONSISTENCY="PASS"
      DP_VERSION_DETECT_STATUS="ok"
      printf '%s' "$DP_VERSION"
      return 0
      ;;
    inconsistent)
      DP_VERSION_SOURCE="aella_cli"
      DP_VERSION_COMMAND="noninteractive"
      DP_VERSION_DETECT_STATUS="inconsistent"
      DP_VERSION_CONSISTENCY="FAIL"
      log INFO "DP_VERSION_DIAG=INCONSISTENT aella_cli returned multiple distinct product versions"
      printf ''
      return 1
      ;;
    timeout)
      log INFO "DP_VERSION_DIAG=TIMEOUT aella_cli show version timed out; trying release-image.yml fallback"
      ;;
    nonzero)
      log WARN "aella_cli show version exited non-zero; trying release-image.yml fallback"
      ;;
    no_semver)
      log WARN "aella_cli show version produced no strict major.minor.patch; trying release-image.yml fallback"
      ;;
    missing|"")
      :
      ;;
  esac

  if detect_dp_version_from_release_image; then
    printf '%s' "$DP_VERSION"
    return 0
  fi
  printf ''
  return 1
}

detect_dp_topology() {
  # Priority:
  #   1) DataProcessor(<role>)> prompt from shared aella_cli capture
  #   2) explicit vendor role files / worker inventory (fallback)
  # Never default UNKNOWN→AIO; never treat cluster-name presence as topology.
  #
  # Sets globals DP_TOPOLOGY / DP_TOPOLOGY_* ; also prints DP_TOPOLOGY on stdout.
  DP_TOPOLOGY=""
  DP_TOPOLOGY_SOURCE=""
  DP_TOPOLOGY_CONSISTENCY=""
  DP_TOPOLOGY_DETECT_STATUS="undetermined"
  DP_TOPOLOGY_CLI_STATUS=""
  DP_TOPOLOGY_SUPPORTED=""

  if [[ -n "${DP_OFFLINE_FAKE_ROLE:-}" ]]; then
    DP_TOPOLOGY="$(canonicalize_dp_topology "$DP_OFFLINE_FAKE_ROLE")"
    DP_TOPOLOGY_SOURCE="FAKE"
    DP_TOPOLOGY_CONSISTENCY="PASS"
    DP_TOPOLOGY_DETECT_STATUS="ok"
    printf '%s' "$DP_TOPOLOGY"
    return 0
  fi

  capture_aella_cli_show_version || true

  local cli_role cli_out
  cli_role=""
  if [[ "${DP_AELLA_CLI_RC_STATUS}" == "ok" ]]; then
    cli_out="$(mktemp)"
    set +e
    parse_dp_topology_from_cli_output >"$cli_out"
    set -e
    cli_role="$(tr -d '[:space:]' <"$cli_out")"
    rm -f "$cli_out"
  else
    DP_TOPOLOGY_CLI_STATUS="${DP_AELLA_CLI_RC_STATUS:-missing}"
  fi

  case "${DP_TOPOLOGY_CLI_STATUS}" in
    ok)
      DP_TOPOLOGY="$cli_role"
      DP_TOPOLOGY_SOURCE="aella_cli"
      DP_TOPOLOGY_CONSISTENCY="PASS"
      DP_TOPOLOGY_DETECT_STATUS="ok"
      printf '%s' "$DP_TOPOLOGY"
      return 0
      ;;
    inconsistent)
      DP_TOPOLOGY_SOURCE="aella_cli"
      DP_TOPOLOGY_DETECT_STATUS="inconsistent"
      DP_TOPOLOGY_CONSISTENCY="FAIL"
      log INFO "DP_TOPOLOGY_DIAG=INCONSISTENT aella_cli prompts reported multiple distinct roles"
      printf ''
      return 1
      ;;
    timeout|nonzero|missing|no_prompt|"")
      # Fall through to vendor authoritative files.
      :
      ;;
  esac

  if detect_dp_topology_from_vendor_files; then
    printf '%s' "$DP_TOPOLOGY"
    return 0
  fi
  printf ''
  return 1
}

require_cmds() {
  local missing=()
  local c
  for c in "$@"; do
    if ! command -v "$c" >/dev/null 2>&1; then
      missing+=("$c")
    fi
  done
  if ((${#missing[@]} > 0)); then
    die "$EC_CMDS" "missing required commands: ${missing[*]} (install from local repository only; refusing internet install)"
  fi
}

http_code() {
  local url="$1"
  if [[ -n "$TEST_ROOT" && -f "$(hostpath /tmp/http-map.tsv)" ]]; then
    local mapped
    mapped="$(awk -F'\t' -v u="$url" '$1==u {print $2; exit}' "$(hostpath /tmp/http-map.tsv)" || true)"
    if [[ -n "$mapped" ]]; then
      printf '%s' "$mapped"
      return 0
    fi
  fi
  curl -sS -o /dev/null -w '%{http_code}' --connect-timeout 10 --max-time 30 "$url" 2>/dev/null || printf '000'
}

http_fetch() {
  local url="$1" dest="$2"
  curl -fsS --connect-timeout 10 --max-time 120 -o "$dest" "$url"
}

read_os_field() {
  local key="$1"
  local f
  f="$(hostpath /etc/os-release)"
  [[ -r "$f" ]] || { printf ''; return 0; }
  # Avoid sourcing os-release
  grep -E "^${key}=" "$f" | head -1 | cut -d= -f2- | tr -d '"'
}

is_stellar_dp() {
  # Soft host identity for diagnostics only (not a Phase 1 hard gate).
  [[ -d "$(hostpath /opt/aelladata)" ]] || return 1
  [[ -f "$(hostpath /opt/aelladata/release-metadata.yml)" || -f "$(hostpath /opt/aelladata/release-image.yml)" ]]
}

is_critical_os_hold_package() {
  # Return 0 if package name is an OS-critical hold that requires planned unhold.
  local pkg="$1"
  local c
  for c in $CRITICAL_HOLD_PACKAGES; do
    [[ "$pkg" == "$c" ]] && return 0
  done
  case "$pkg" in
    linux-image*|linux-generic*|linux-virtual*|linux-headers*|linux-modules*)
      return 0 ;;
    grub*|shim-signed|openssh-server|openssh-client)
      return 0 ;;
    ubuntu-release-upgrader*|update-manager*)
      return 0 ;;
    libc6*|libsystemd*|systemd-*)
      return 0 ;;
  esac
  return 1
}

critical_holds_dir() {
  hostpath "${STATE_ROOT}/critical-holds"
}

utc_now() {
  date -u '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null || date
}

json_escape() {
  # Minimal JSON string escape for package names / short status tokens.
  local s="$1"
  s="${s//\\/\\\\}"
  s="${s//\"/\\\"}"
  s="${s//$'\n'/\\n}"
  printf '%s' "$s"
}

json_string_array_from_words() {
  # Emit JSON array from whitespace-separated words (Bash 4.3 safe).
  local words="$1"
  local first=1 w
  printf '['
  # shellcheck disable=SC2086
  for w in $words; do
    [[ -n "$w" ]] || continue
    if [[ "$first" -eq 1 ]]; then
      first=0
    else
      printf ','
    fi
    printf '"%s"' "$(json_escape "$w")"
  done
  printf ']'
}

atomic_write_file() {
  local dest="$1"
  local tmp
  tmp="${dest}.tmp.$$"
  cat >"$tmp"
  mv -f "$tmp" "$dest"
}

list_held_packages() {
  # Print currently held package names, one per line (or space-joined via caller).
  local held=""
  if [[ -n "$TEST_ROOT" && -f "$(hostpath /tmp/held-packages.txt)" ]]; then
    held="$(tr -d '\r' <"$(hostpath /tmp/held-packages.txt)" || true)"
  elif [[ -n "$TEST_ROOT" ]]; then
    held=""
  else
    held="$(dpkg --get-selections 2>/dev/null | awk '$2=="hold"{print $1}' || true)"
  fi
  # Normalize to unique whitespace-separated tokens
  printf '%s' "$held" | tr -s '[:space:]' '\n' | sed '/^$/d' | sort -u | tr '\n' ' ' | sed 's/[[:space:]]*$//'
}

is_package_currently_held() {
  local pkg="$1"
  local held
  held="$(list_held_packages)"
  local h
  # shellcheck disable=SC2086
  for h in $held; do
    [[ "$h" == "$pkg" ]] && return 0
  done
  return 1
}

test_root_set_held_packages() {
  # Rewrite TEST_ROOT held fixture (space or newline separated).
  local packages="$1"
  local f
  f="$(hostpath /tmp/held-packages.txt)"
  mkdir -p "$(dirname "$f")"
  printf '%s' "$packages" | tr -s '[:space:]' '\n' | sed '/^$/d' >"$f"
}

apt_mark_unhold_pkg() {
  local pkg="$1"
  if [[ -n "$TEST_ROOT" ]]; then
    if [[ "${DP_OFFLINE_FAKE_UNHOLD_FAIL:-}" == "$pkg" || "${DP_OFFLINE_FAKE_UNHOLD_FAIL:-}" == "all" ]]; then
      return 1
    fi
    if [[ "${DP_OFFLINE_FAKE_UNHOLD_STILL_HELD:-}" == "1" || "${DP_OFFLINE_FAKE_UNHOLD_STILL_HELD:-}" == "$pkg" ]]; then
      # Command "succeeds" but selection remains hold — verification must catch this.
      return 0
    fi
    local cur next="" h
    cur="$(list_held_packages)"
    # shellcheck disable=SC2086
    for h in $cur; do
      [[ "$h" == "$pkg" ]] && continue
      next="${next}${h} "
    done
    test_root_set_held_packages "$next"
    return 0
  fi
  apt-mark unhold "$pkg"
}

apt_mark_hold_pkg() {
  local pkg="$1"
  if [[ -n "$TEST_ROOT" ]]; then
    if [[ "${DP_OFFLINE_FAKE_HOLD_FAIL:-}" == "$pkg" || "${DP_OFFLINE_FAKE_HOLD_FAIL:-}" == "all" ]]; then
      return 1
    fi
    local cur
    cur="$(list_held_packages)"
    if ! is_package_currently_held "$pkg"; then
      test_root_set_held_packages "${cur} ${pkg}"
    fi
    return 0
  fi
  apt-mark hold "$pkg"
}

classify_held_packages() {
  # Sets DETECTED_ALL_HOLDS, PLANNED_CRITICAL_OS_HOLDS, DETECTED_PRODUCT_HOLDS.
  local held critical_hit="" product_hit="" pkg
  held="$(list_held_packages)"
  DETECTED_ALL_HOLDS="$held"
  PLANNED_CRITICAL_OS_HOLDS=""
  DETECTED_PRODUCT_HOLDS=""
  [[ -n "$held" ]] || return 0
  # shellcheck disable=SC2086
  for pkg in $held; do
    [[ -n "$pkg" ]] || continue
    if is_critical_os_hold_package "$pkg"; then
      critical_hit="${critical_hit}${pkg} "
    else
      product_hit="${product_hit}${pkg} "
    fi
  done
  PLANNED_CRITICAL_OS_HOLDS="$(printf '%s' "$critical_hit" | sed 's/[[:space:]]*$//')"
  DETECTED_PRODUCT_HOLDS="$(printf '%s' "$product_hit" | sed 's/[[:space:]]*$//')"
}

write_critical_holds_state_json() {
  # Atomically write critical-holds-state.json from current globals + args.
  # Args: confirmation status, restore_attempted (true|false), restore_result, restore_reason
  local confirmation="${1:-pending}"
  local restore_attempted="${2:-false}"
  local restore_result="${3:-}"
  local restore_reason="${4:-}"
  local dir detected_at unhold_started unhold_completed pkg_results_json final_holds
  local pkg result_line results_file
  dir="$(critical_holds_dir)"
  mkdir -p "$dir"
  detected_at=""
  unhold_started=""
  unhold_completed=""
  [[ -f "$dir/detected_at" ]] && detected_at="$(tr -d '\n' <"$dir/detected_at")"
  [[ -f "$dir/unhold_started_at" ]] && unhold_started="$(tr -d '\n' <"$dir/unhold_started_at")"
  [[ -f "$dir/unhold_completed_at" ]] && unhold_completed="$(tr -d '\n' <"$dir/unhold_completed_at")"
  results_file="$dir/package-results.tsv"
  pkg_results_json="{"
  local first=1
  if [[ -f "$results_file" ]]; then
    while IFS=$'\t' read -r pkg result_line; do
      [[ -n "$pkg" ]] || continue
      if [[ "$first" -eq 1 ]]; then first=0; else pkg_results_json+=","; fi
      pkg_results_json+="\"$(json_escape "$pkg")\":\"$(json_escape "$result_line")\""
    done <"$results_file"
  fi
  pkg_results_json+="}"
  final_holds="$(list_held_packages)"
  {
    printf '{\n'
    printf '  "detected_at": "%s",\n' "$(json_escape "$detected_at")"
    printf '  "original_held_packages": %s,\n' "$(json_string_array_from_words "${DETECTED_ALL_HOLDS}")"
    printf '  "critical_holds": %s,\n' "$(json_string_array_from_words "${PLANNED_CRITICAL_OS_HOLDS}")"
    printf '  "product_holds": %s,\n' "$(json_string_array_from_words "${DETECTED_PRODUCT_HOLDS}")"
    printf '  "critical_holds_removed": %s,\n' "$(json_string_array_from_words "${CRITICAL_HOLDS_REMOVED}")"
    printf '  "confirmation": "%s",\n' "$(json_escape "$confirmation")"
    printf '  "unhold_started_at": "%s",\n' "$(json_escape "$unhold_started")"
    printf '  "unhold_completed_at": "%s",\n' "$(json_escape "$unhold_completed")"
    printf '  "package_results": %s,\n' "$pkg_results_json"
    printf '  "release_upgrade_started": %s,\n' "${RELEASE_UPGRADE_STARTED}"
    printf '  "release_upgrade_invocation_started": %s,\n' "${RELEASE_UPGRADE_INVOCATION_STARTED}"
    printf '  "release_upgrade_process_spawned": %s,\n' "${RELEASE_UPGRADE_PROCESS_SPAWNED}"
    printf '  "release_upgrade_package_transition_started": %s,\n' "${RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED}"
    printf '  "release_upgrade_completed": %s,\n' "${RELEASE_UPGRADE_COMPLETED}"
    printf '  "legacy_state_reconciled": %s,\n' "${LEGACY_STATE_RECONCILED}"
    if [[ -n "$RECONCILIATION_REASON" ]]; then
      printf '  "reconciliation_reason": "%s",\n' "$(json_escape "$RECONCILIATION_REASON")"
    else
      printf '  "reconciliation_reason": null,\n'
    fi
    printf '  "restore_attempted": %s,\n' "$restore_attempted"
    if [[ -n "$restore_result" ]]; then
      printf '  "restore_result": "%s",\n' "$(json_escape "$restore_result")"
    else
      printf '  "restore_result": null,\n'
    fi
    if [[ -n "$restore_reason" ]]; then
      printf '  "critical_hold_restore_reason": "%s",\n' "$(json_escape "$restore_reason")"
    else
      printf '  "critical_hold_restore_reason": null,\n'
    fi
    printf '  "final_holds": %s\n' "$(json_string_array_from_words "$final_holds")"
    printf '}\n'
  } | atomic_write_file "$dir/critical-holds-state.json"
}

reconcile_critical_hold_state() {
  # Compare prior critical-holds state with live selection. Fail-closed on incomplete mutation.
  local dir state_json
  dir="$(critical_holds_dir)"
  state_json="$dir/critical-holds-state.json"
  [[ -f "$state_json" ]] || return 0

  local unhold_started=0 unhold_completed=0 release_started=0
  [[ -f "$dir/unhold_started_at" ]] && unhold_started=1
  [[ -f "$dir/unhold_completed_at" ]] && unhold_completed=1
  if grep -q '"release_upgrade_started": true' "$state_json" 2>/dev/null; then
    release_started=1
  fi

  if [[ "$unhold_started" -eq 1 && "$unhold_completed" -eq 0 ]]; then
    log ERROR "CRITICAL_OS_HOLD_STATE_INCONSISTENT: unhold started but not completed"
    log ERROR "state=${state_json}"
    log ERROR "live_holds=$(list_held_packages)"
    die "$EC_CRITICAL_HOLD" "FAIL_CRITICAL_OS_HOLD_STATE_INCONSISTENT"
  fi

  if [[ -f "$dir/critical-holds-removed.txt" ]]; then
    local removed pkg still_held="" unexpectedly_held=""
    removed="$(tr -d '\r' <"$dir/critical-holds-removed.txt" | tr -s '[:space:]' ' ' | sed 's/[[:space:]]*$//')"
    # shellcheck disable=SC2086
    for pkg in $removed; do
      [[ -n "$pkg" ]] || continue
      if is_package_currently_held "$pkg"; then
        still_held="${still_held}${pkg} "
      fi
    done
    if [[ "$release_started" -eq 0 && -n "$still_held" && "$unhold_completed" -eq 1 ]]; then
      # Prior run claimed unhold but packages are held again — re-plan (do not invent restores).
      log WARN "CRITICAL_OS_HOLD_RECONCILE: previously removed holds are held again: ${still_held}"
      log WARN "CRITICAL_OS_HOLD_RECONCILE_ACTION=REPLAN_UNHOLD_AFTER_CONFIRMATION"
    elif [[ "$release_started" -eq 0 && -z "$still_held" && "$unhold_completed" -eq 1 ]]; then
      log INFO "CRITICAL_OS_HOLD_RECONCILE: prior critical OS holds remain unheld (expected until Phase 2 policy)"
    fi
  fi
  return 0
}

snapshot_critical_holds_before() {
  local dir
  dir="$(critical_holds_dir)"
  mkdir -p "$dir"
  utc_now >"$dir/detected_at"
  list_held_packages | tr -s '[:space:]' '\n' | sed '/^$/d' | atomic_write_file "$dir/selection-snapshot-before.txt"
  printf '%s\n' $PLANNED_CRITICAL_OS_HOLDS | sed '/^$/d' | atomic_write_file "$dir/critical-holds-before.txt"
  printf '%s\n' $DETECTED_PRODUCT_HOLDS | sed '/^$/d' | atomic_write_file "$dir/product-holds.txt"
  write_critical_holds_state_json "accepted" "false" "" ""
  log INFO "CRITICAL_OS_HOLD_SNAPSHOT=PASS"
}

unhold_critical_os_packages() {
  # Unhold only PLANNED_CRITICAL_OS_HOLDS. Never touch product holds.
  local dir pkg
  dir="$(critical_holds_dir)"
  mkdir -p "$dir"
  : >"$dir/package-results.tsv"
  CRITICAL_HOLDS_REMOVED=""
  [[ -n "$PLANNED_CRITICAL_OS_HOLDS" ]] || {
    log INFO "CRITICAL_OS_UNHOLD_BEGIN"
    log INFO "CRITICAL_OS_UNHOLD_RESULT=PASS"
    log INFO "CRITICAL_OS_UNHOLD_SKIPPED=none_planned"
    utc_now >"$dir/unhold_started_at"
    utc_now >"$dir/unhold_completed_at"
    : >"$dir/critical-holds-removed.txt"
    write_critical_holds_state_json "accepted" "false" "" "DEFERRED_UNTIL_PHASE2_POLICY"
    return 0
  }

  utc_now >"$dir/unhold_started_at"
  log INFO "CRITICAL_OS_UNHOLD_BEGIN"
  CRITICAL_HOLD_RESTORE_ON_EXIT=1
  # shellcheck disable=SC2086
  for pkg in $PLANNED_CRITICAL_OS_HOLDS; do
    [[ -n "$pkg" ]] || continue
    log INFO "CRITICAL_OS_UNHOLD_PACKAGE=${pkg}"
    if ! apt_mark_unhold_pkg "$pkg"; then
      printf '%s\tFAIL\n' "$pkg" >>"$dir/package-results.tsv"
      write_critical_holds_state_json "accepted" "false" "" ""
      log ERROR "FAIL_CRITICAL_OS_UNHOLD"
      log ERROR "PACKAGE=${pkg}"
      restore_critical_os_holds_if_safe "unhold_command_failed" || true
      die "$EC_CRITICAL_HOLD" "FAIL_CRITICAL_OS_UNHOLD"
    fi
    printf '%s\tUNHOLD_OK\n' "$pkg" >>"$dir/package-results.tsv"
    CRITICAL_HOLDS_REMOVED="${CRITICAL_HOLDS_REMOVED}${pkg} "
  done
  CRITICAL_HOLDS_REMOVED="$(printf '%s' "$CRITICAL_HOLDS_REMOVED" | sed 's/[[:space:]]*$//')"
  printf '%s\n' $CRITICAL_HOLDS_REMOVED | sed '/^$/d' | atomic_write_file "$dir/critical-holds-removed.txt"

  # Verify none of the planned critical packages remain held.
  # shellcheck disable=SC2086
  for pkg in $PLANNED_CRITICAL_OS_HOLDS; do
    [[ -n "$pkg" ]] || continue
    if is_package_currently_held "$pkg"; then
      printf '%s\tSTILL_HELD\n' "$pkg" >>"$dir/package-results.tsv"
      write_critical_holds_state_json "accepted" "false" "" ""
      log ERROR "FAIL_CRITICAL_OS_UNHOLD"
      log ERROR "PACKAGE=${pkg}"
      log ERROR "REASON=still_held_after_unhold"
      restore_critical_os_holds_if_safe "unhold_verify_failed" || true
      die "$EC_CRITICAL_HOLD" "FAIL_CRITICAL_OS_UNHOLD"
    fi
  done

  # Product holds must remain held.
  # shellcheck disable=SC2086
  for pkg in $DETECTED_PRODUCT_HOLDS; do
    [[ -n "$pkg" ]] || continue
    if ! is_package_currently_held "$pkg"; then
      log ERROR "FAIL_CRITICAL_OS_UNHOLD"
      log ERROR "PACKAGE=${pkg}"
      log ERROR "REASON=product_hold_unexpectedly_cleared"
      restore_critical_os_holds_if_safe "product_hold_cleared" || true
      die "$EC_CRITICAL_HOLD" "FAIL_CRITICAL_OS_UNHOLD"
    fi
  done

  list_held_packages | tr -s '[:space:]' '\n' | sed '/^$/d' | atomic_write_file "$dir/critical-holds-after.txt"
  utc_now >"$dir/unhold_completed_at"
  write_critical_holds_state_json "accepted" "false" "" "DEFERRED_UNTIL_PHASE2_POLICY"
  log INFO "CRITICAL_OS_UNHOLD_RESULT=PASS"
  log INFO "CRITICAL_OS_HOLD_RESTORE=DEFERRED_UNTIL_PHASE2_POLICY"
  log INFO "ORIGINAL_CRITICAL_OS_HOLDS=${PLANNED_CRITICAL_OS_HOLDS}"
}

restore_critical_os_holds_if_safe() {
  # Restore original critical holds when package transition has NOT begun.
  # do-release-upgrade invocation alone is not a package mutation barrier.
  local reason="${1:-pre_upgrade_failure}"
  local dir pkg restored="" failed=""
  dir="$(critical_holds_dir)"
  load_release_upgrade_started_flag
  # Only the durable watcher/marker flag blocks restore. Historical dpkg.log
  # without a this-hop baseline must not skip critical hold restore.
  if [[ "$RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED" == "true" ]]; then
    log INFO "CRITICAL_OS_HOLD_RESTORE=SKIPPED_PACKAGE_TRANSITION_STARTED"
    write_critical_holds_state_json "accepted" "false" "skipped" "PACKAGE_TRANSITION_STARTED"
    return 0
  fi
  if package_transition_evidence_present; then
    log INFO "CRITICAL_OS_HOLD_RESTORE=SKIPPED_PACKAGE_TRANSITION_EVIDENCE"
    write_critical_holds_state_json "accepted" "false" "skipped" "PACKAGE_TRANSITION_EVIDENCE"
    return 0
  fi
  if [[ "$CRITICAL_HOLD_RESTORE_ON_EXIT" -ne 1 \
    && "$reason" != "pre_package_transition_failure" \
    && "$reason" != "pre_upgrade_failure" \
    && "$reason" != "injected_pre_upgrade_failure" ]]; then
    return 0
  fi
  [[ -n "$CRITICAL_HOLDS_REMOVED" || -f "$dir/critical-holds-removed.txt" ]] || return 0
  if [[ -z "$CRITICAL_HOLDS_REMOVED" && -f "$dir/critical-holds-removed.txt" ]]; then
    CRITICAL_HOLDS_REMOVED="$(tr '\n' ' ' <"$dir/critical-holds-removed.txt" | sed 's/[[:space:]]*$//')"
  fi
  log INFO "CRITICAL_OS_HOLD_RESTORE_BEGIN reason=${reason}"
  # shellcheck disable=SC2086
  for pkg in $CRITICAL_HOLDS_REMOVED; do
    [[ -n "$pkg" ]] || continue
    if apt_mark_hold_pkg "$pkg"; then
      restored="${restored}${pkg} "
      log INFO "CRITICAL_OS_HOLD_RESTORED=${pkg}"
    else
      failed="${failed}${pkg} "
      log ERROR "CRITICAL_OS_HOLD_RESTORE_FAILED=${pkg}"
    fi
  done
  CRITICAL_HOLD_RESTORE_ON_EXIT=0
  if [[ -n "$failed" ]]; then
    write_critical_holds_state_json "accepted" "true" "FAIL" "$reason"
    log ERROR "CRITICAL_OS_HOLD_RESTORE_RESULT=FAIL"
    return 1
  fi
  write_critical_holds_state_json "accepted" "true" "PASS" "$reason"
  log INFO "CRITICAL_OS_HOLD_RESTORE_RESULT=PASS"
  log INFO "critical_holds_restored=$(printf '%s' "$restored" | sed 's/[[:space:]]*$//')"
  return 0
}

write_release_upgrade_marker_meta() {
  # Companion ownership metadata for a true/false marker (hop-aware classification).
  local marker_path="$1"
  local value="$2"
  local meta tmp
  meta="${marker_path}.meta"
  tmp="${meta}.tmp.$$"
  {
    printf 'VALUE=%s\n' "$value"
    printf 'HOP=%s\n' "${PIN_HOP:-focal-to-jammy}"
    printf 'SOURCE_CODENAME=%s\n' "${PIN_SOURCE_CODENAME:-focal}"
    printf 'TARGET_CODENAME=%s\n' "${PIN_TARGET_CODENAME:-jammy}"
    printf 'RUN_ID=%s\n' "${CURRENT_RUN_ID:-}"
    printf 'RUN_EPOCH=%s\n' "${CURRENT_RUN_EPOCH:-}"
    printf 'DETECTED_AT=%s\n' "$(utc_now)"
    printf 'SOURCE=%s\n' "${PACKAGE_TRANSITION_DETECTION_SOURCE:-persist_release_upgrade_flags}"
    printf 'EVIDENCE=%s\n' "${PACKAGE_TRANSITION_DETECTION_EVIDENCE:-}"
  } >"$tmp"
  mv -f "$tmp" "$meta"
  chmod 0600 "$meta" 2>/dev/null || true
}

persist_release_upgrade_flags() {
  local dir
  dir="$(critical_holds_dir)"
  mkdir -p "$dir"
  printf '%s\n' "$RELEASE_UPGRADE_INVOCATION_STARTED" >"$dir/release_upgrade_invocation_started"
  printf '%s\n' "$RELEASE_UPGRADE_PROCESS_SPAWNED" >"$dir/release_upgrade_process_spawned"
  printf '%s\n' "$RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED" >"$dir/release_upgrade_package_transition_started"
  printf '%s\n' "$RELEASE_UPGRADE_COMPLETED" >"$dir/release_upgrade_completed"
  write_release_upgrade_marker_meta "$dir/release_upgrade_package_transition_started" \
    "$RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED"
  write_release_upgrade_marker_meta "$dir/release_upgrade_invocation_started" \
    "$RELEASE_UPGRADE_INVOCATION_STARTED"
  # Legacy flag: true once invocation started (historical semantics). Never alone means mutation.
  if [[ "$RELEASE_UPGRADE_INVOCATION_STARTED" == "true" ]]; then
    printf 'true\n' >"$dir/release_upgrade_started"
    RELEASE_UPGRADE_STARTED="true"
    write_release_upgrade_marker_meta "$dir/release_upgrade_started" "true"
  fi
  if [[ -n "$RECONCILIATION_REASON" ]]; then
    printf '%s\n' "$RECONCILIATION_REASON" >"$dir/reconciliation_reason"
  fi
  if [[ "$LEGACY_STATE_RECONCILED" == "true" ]]; then
    printf 'true\n' >"$dir/legacy_state_reconciled"
  fi
  write_critical_holds_state_json "accepted" "false" "" "DEFERRED_UNTIL_PHASE2_POLICY"
}

mark_release_upgrade_invocation_started() {
  RELEASE_UPGRADE_INVOCATION_STARTED="true"
  RELEASE_UPGRADE_STARTED="true"
  CRITICAL_HOLD_RESTORE_ON_EXIT=0
  persist_release_upgrade_flags
  log INFO "RELEASE_UPGRADE_INVOCATION_STARTED=true"
  log INFO "RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED=${RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED}"
  # Keep legacy log line for older tooling.
  log INFO "release_upgrade_started=true"
}

mark_release_upgrade_process_spawned() {
  RELEASE_UPGRADE_PROCESS_SPAWNED="true"
  persist_release_upgrade_flags
  log INFO "RELEASE_UPGRADE_PROCESS_SPAWNED=true"
}

mark_release_upgrade_package_transition_started() {
  RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED="true"
  persist_release_upgrade_flags
  log INFO "RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED=true"
}

mark_release_upgrade_completed() {
  RELEASE_UPGRADE_COMPLETED="true"
  RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED="true"
  persist_release_upgrade_flags
  log INFO "RELEASE_UPGRADE_COMPLETED=true"
}

# Backward-compatible alias used by older call sites / harnesses.
mark_release_upgrade_started() {
  mark_release_upgrade_invocation_started
}

load_release_upgrade_started_flag() {
  # Compatibility wrapper: only load markers owned by the current hop.
  load_release_upgrade_started_flag_for_current_hop
}

marker_meta_field() {
  local marker_path="$1" field="$2"
  local meta
  meta="${marker_path}.meta"
  [[ -f "$meta" ]] || return 1
  sed -n "s/^${field}=//p" "$meta" 2>/dev/null | head -1
}

marker_owned_by_current_hop() {
  # Return 0 only when marker companion metadata matches current-hop identity.
  local marker_path="$1"
  local hop run_id
  hop="$(marker_meta_field "$marker_path" HOP || true)"
  run_id="$(marker_meta_field "$marker_path" RUN_ID || true)"
  [[ -n "$hop" ]] || return 1
  [[ "$hop" == "${PIN_HOP:-focal-to-jammy}" ]] || return 1
  if [[ -n "${CURRENT_RUN_ID:-}" && -n "$run_id" && "$run_id" != "$CURRENT_RUN_ID" ]]; then
    return 1
  fi
  return 0
}

load_release_upgrade_started_flag_for_current_hop() {
  # Never promote previous-hop (bionic-to-focal) markers into current-hop globals.
  local dir st current_hop
  dir="$(critical_holds_dir)"
  st="$(read_state 2>/dev/null || true)"
  current_hop=""
  if [[ -f "$(hostpath "${CURRENT_HOP_ENV_FILE:-${STATE_ROOT}/current-hop.env}")" ]]; then
    current_hop="$(sed -n 's/^CURRENT_HOP=//p' "$(hostpath "${CURRENT_HOP_ENV_FILE:-${STATE_ROOT}/current-hop.env}")" 2>/dev/null | head -1)"
    CURRENT_RUN_ID="$(sed -n 's/^CURRENT_RUN_ID=//p' "$(hostpath "${CURRENT_HOP_ENV_FILE:-${STATE_ROOT}/current-hop.env}")" 2>/dev/null | head -1)"
    CURRENT_RUN_EPOCH="$(sed -n 's/^CURRENT_RUN_EPOCH=//p' "$(hostpath "${CURRENT_HOP_ENV_FILE:-${STATE_ROOT}/current-hop.env}")" 2>/dev/null | head -1)"
  fi

  # Previous-hop terminal: do not load any release-upgrade transaction flags yet.
  if [[ "$st" == "COMPLETED_FOCAL" ]]; then
    return 0
  fi

  # Without current-hop identity, only load markers that explicitly claim this hop.
  _load_flag_if_current() {
    local name="$1" var="$2"
    local f
    f="${dir}/${name}"
    [[ -f "$f" ]] && grep -qx 'true' "$f" 2>/dev/null || return 0
    if marker_owned_by_current_hop "$f"; then
      printf -v "$var" '%s' "true"
      return 0
    fi
    # Mid-hop with matching pins/current-hop.env and no meta: fail closed later via classifier.
    if [[ -n "$current_hop" && "$current_hop" == "${PIN_HOP:-focal-to-jammy}" ]] \
      && [[ ! -f "${f}.meta" ]]; then
      # Legacy current-hop marker without meta — treat as current only in mid-hop states.
      case "$st" in
        CONFIGURING|PREPARING_FOCAL|UPGRADING_FOCAL_TO_JAMMY|REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|FAILED_AFTER_PACKAGE_TRANSITION|FAILED_POST_TRANSACTION)
          printf -v "$var" '%s' "true"
          ;;
      esac
    fi
  }

  _load_flag_if_current release_upgrade_invocation_started RELEASE_UPGRADE_INVOCATION_STARTED
  _load_flag_if_current release_upgrade_process_spawned RELEASE_UPGRADE_PROCESS_SPAWNED
  _load_flag_if_current release_upgrade_package_transition_started RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED
  _load_flag_if_current release_upgrade_completed RELEASE_UPGRADE_COMPLETED
  _load_flag_if_current release_upgrade_started RELEASE_UPGRADE_STARTED
  if [[ "$RELEASE_UPGRADE_STARTED" == "true" && "$RELEASE_UPGRADE_INVOCATION_STARTED" != "true" ]]; then
    RELEASE_UPGRADE_INVOCATION_STARTED="true"
  fi
  if [[ -f "$dir/legacy_state_reconciled" ]] && grep -qx 'true' "$dir/legacy_state_reconciled"; then
    LEGACY_STATE_RECONCILED="true"
  fi
  if [[ -f "$dir/reconciliation_reason" ]]; then
    RECONCILIATION_REASON="$(tr -d '\n' <"$dir/reconciliation_reason")"
  fi
}

has_target_core_package_contamination() {
  # Return 0 if any core package looks like the target (Focal) release.
  local pkg ivers
  if [[ -n "$TEST_ROOT" ]]; then
    [[ -f "$(hostpath ${STATE_ROOT}/force-target-core-packages)" ]] && return 0
    return 1
  fi
  for pkg in base-files libc6 apt dpkg systemd systemd-sysv; do
    ivers="$(pkg_installed_version "$pkg")"
    if is_jammy_version_for_pkg "$pkg" "$ivers"; then
      return 0
    fi
  done
  return 1
}

source_suite_still_focal() {
  local sl
  sl="$(hostpath /etc/apt/sources.list)"
  [[ -f "$sl" ]] || return 1
  if grep -qE '[[:space:]]focal(-|$|[[:space:]])' "$sl" 2>/dev/null; then
    # Fail if sources already primarily on jammy without focal.
    if grep -qE '[[:space:]]jammy(-|$|[[:space:]])' "$sl" 2>/dev/null \
      && ! grep -qE '[[:space:]]focal(-|$|[[:space:]])' "$sl" 2>/dev/null; then
      return 1
    fi
    return 0
  fi
  # Our stellar offline list uses focal suites during Phase 1 prep.
  if grep -qE 'stellar-offline|focal' "$sl" 2>/dev/null; then
    return 0
  fi
  return 1
}

has_upgrade_transaction_evidence() {
  # Return 0 if dist-upgrade / apt history shows an upgrade transaction.
  if [[ -n "$TEST_ROOT" ]]; then
    [[ -f "$(hostpath ${STATE_ROOT}/force-upgrade-transaction-evidence)" ]] && return 0
    return 1
  fi
  if [[ -f /var/log/dist-upgrade/apt.log ]] \
    && grep -qiE '^(Install|Upgrade|Remove):' /var/log/dist-upgrade/apt.log 2>/dev/null; then
    return 0
  fi
  if [[ -f /var/log/dist-upgrade/main.log ]] \
    && grep -qiE 'apt.distupgrade|altering|Installing|upgrading packages' /var/log/dist-upgrade/main.log 2>/dev/null; then
    return 0
  fi
  if [[ -f /var/log/apt/history.log ]] \
    && grep -qiE 'Upgrade:|Install:.*jammy|Commandline:.*do-release-upgrade' /var/log/apt/history.log 2>/dev/null \
    && grep -qiE 'jammy|20\.04' /var/log/apt/history.log 2>/dev/null; then
    return 0
  fi
  return 1
}

detect_meta_release_encoding_failure_signature() {
  # Return 0 if logs show MetaRelease UnicodeDecodeError / ascii codec failure.
  local logf meta
  logf="$(hostpath "$LOG_FILE")"
  meta="$(hostpath /etc/update-manager/meta-release)"
  if [[ -n "$TEST_ROOT" && -f "$(hostpath ${STATE_ROOT}/force-meta-release-encoding-failure)" ]]; then
    return 0
  fi
  if [[ -f "$logf" ]] && grep -q 'UnicodeDecodeError' "$logf" 2>/dev/null; then
    if grep -qiE 'MetaRelease|meta-release|ascii.*codec|0xe2' "$logf" 2>/dev/null; then
      return 0
    fi
  fi
  if [[ -f "$meta" ]] && ! assert_ascii_file "$meta" "FAIL_META_RELEASE_CONFIG_NON_ASCII" 2>/dev/null; then
    # Non-ASCII meta-release still present from prior attempt (UTF-8 arrow was 0xe2 0x86 0x92).
    if LC_ALL=C grep -aq $'\xe2\x86\x92' "$meta" 2>/dev/null || LC_ALL=C grep -aq $'\xe2' "$meta" 2>/dev/null; then
      return 0
    fi
  fi
  return 1
}

package_transition_evidence_present() {
  # Real package mutation only — not DistUpgrade PID/invocation.
  # Mirrors runner policy: dpkg unpack/start, status DB change, install phase.
  local ver status dpkglog mainlog aptlog offset
  ver="$(read_os_field VERSION_ID)"
  if [[ "$ver" != "$PIN_SOURCE_VERSION" ]]; then
    return 0
  fi
  if has_target_core_package_contamination; then
    return 0
  fi
  if has_upgrade_transaction_evidence; then
    return 0
  fi
  if [[ -n "$TEST_ROOT" ]]; then
    [[ -f "$(hostpath ${STATE_ROOT}/force-upgrade-transaction-evidence)" ]] && return 0
    [[ -f "$(hostpath /tmp/dpkg-broken)" ]] && return 0
    return 1
  fi
  # Without this-hop package-transition baseline, do not scan historical dpkg.log.
  dpkglog="$(hostpath /var/log/dpkg.log)"
  offset="$(cat "$(critical_holds_dir)/dpkg_log_offset_before" 2>/dev/null || echo "")"
  if [[ -f "$(critical_holds_dir)/package_transition_run_epoch" ]] \
    && [[ -n "$offset" && "$offset" =~ ^[0-9]+$ ]] && [[ -f "$dpkglog" ]]; then
    if [[ "$offset" -gt 0 ]]; then
      if tail -c +"$((offset + 1))" "$dpkglog" 2>/dev/null \
        | grep -q 'startup archives unpack'; then
        return 0
      fi
    fi
  fi
  if pgrep -f 'dpkg[[:space:]]+.*--(unpack|install|configure)' >/dev/null 2>&1; then
    return 0
  fi
  mainlog="$(hostpath /var/log/dist-upgrade/main.log)"
  aptlog="$(hostpath /var/log/dist-upgrade/apt.log)"
  if [[ -f "$mainlog" ]] \
    && grep -qiE 'apt\.distupgrade\.(install|doTheInstall)|installing packages|about to install|DistUpgrade\.install' "$mainlog" 2>/dev/null; then
    return 0
  fi
  if [[ -f "$aptlog" ]] \
    && grep -qiE '^(Install|Upgrade|Remove):' "$aptlog" 2>/dev/null; then
    return 0
  fi
  if dpkg --audit 2>/dev/null | grep -q .; then
    return 0
  fi
  if ! apt-get check >/dev/null 2>&1; then
    return 0
  fi
  return 1
}

classify_previous_release_upgrade_failure() {
  # Sets RELEASE_UPGRADE_FAILURE_CLASS / PREVIOUS_FAILURE_CLASS.
  RELEASE_UPGRADE_FAILURE_CLASS=""
  PREVIOUS_FAILURE_CLASS=""
  local ver
  ver="$(read_os_field VERSION_ID)"

  if package_transition_evidence_present; then
    RELEASE_UPGRADE_FAILURE_CLASS="PARTIAL_OR_UNKNOWN_MUTATION"
    PREVIOUS_FAILURE_CLASS="$RELEASE_UPGRADE_FAILURE_CLASS"
    PARTIAL_RELEASE_TRANSITION="YES"
    return 1
  fi

  if [[ "$ver" == "$PIN_SOURCE_VERSION" ]] \
    && detect_meta_release_encoding_failure_signature; then
    RELEASE_UPGRADE_FAILURE_CLASS="PRE_MUTATION_META_RELEASE_ENCODING"
    PREVIOUS_FAILURE_CLASS="$RELEASE_UPGRADE_FAILURE_CLASS"
    PARTIAL_RELEASE_TRANSITION="NO"
    log INFO "RELEASE_UPGRADE_FAILURE_CLASS=PRE_MUTATION_CONFIG_PARSE"
    log INFO "RELEASE_UPGRADE_FAILURE_CLASS=${RELEASE_UPGRADE_FAILURE_CLASS}"
    log INFO "RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED=false"
    return 0
  fi

  if [[ "$ver" == "$PIN_SOURCE_VERSION" ]] \
    && ! has_upgrade_transaction_evidence \
    && ! has_target_core_package_contamination; then
    # Clean source OS without a known pre-mutation signature is NOT auto-resumable.
    RELEASE_UPGRADE_FAILURE_CLASS="PRE_MUTATION_UNKNOWN"
    PREVIOUS_FAILURE_CLASS="$RELEASE_UPGRADE_FAILURE_CLASS"
    PARTIAL_RELEASE_TRANSITION="NO"
    return 1
  fi

  RELEASE_UPGRADE_FAILURE_CLASS="UNCLASSIFIED"
  PREVIOUS_FAILURE_CLASS="$RELEASE_UPGRADE_FAILURE_CLASS"
  PARTIAL_RELEASE_TRANSITION="YES"
  return 1
}

reconcile_legacy_release_upgrade_state() {
  # Migrate legacy release_upgrade_started=true without assuming package mutation.
  load_release_upgrade_started_flag
  local dir legacy=0
  dir="$(critical_holds_dir)"
  [[ -f "$dir/release_upgrade_started" ]] && grep -qx 'true' "$dir/release_upgrade_started" && legacy=1

  if [[ "$legacy" -eq 0 && "$RELEASE_UPGRADE_STARTED" != "true" ]]; then
    return 0
  fi

  if package_transition_evidence_present; then
    log ERROR "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
    log ERROR "MANUAL_REVIEW_REQUIRED=YES"
    log ERROR "REASON=legacy_flag_with_package_transition_evidence"
    die "$EC_RESUME" "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
  fi

  if [[ "$LEGACY_STATE_RECONCILED" == "true" && -n "$RECONCILIATION_REASON" ]]; then
    log INFO "legacy_state_reconciled=true"
    log INFO "reconciliation_reason=${RECONCILIATION_REASON}"
    return 0
  fi

  log INFO "legacy_release_upgrade_started=true"

  if ! classify_previous_release_upgrade_failure; then
    if [[ "$PREVIOUS_FAILURE_CLASS" != "PRE_MUTATION_META_RELEASE_ENCODING" \
       && "$PREVIOUS_FAILURE_CLASS" != "PRE_MUTATION_CONFIG_PARSE" ]]; then
      log ERROR "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
      log ERROR "MANUAL_REVIEW_REQUIRED=YES"
      log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS}"
      die "$EC_RESUME" "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
    fi
  fi

  # Only reconcile to resumable state for known pre-mutation encoding/parse failures.
  if [[ "$PREVIOUS_FAILURE_CLASS" != "PRE_MUTATION_META_RELEASE_ENCODING" \
     && "$PREVIOUS_FAILURE_CLASS" != "PRE_MUTATION_CONFIG_PARSE" ]]; then
    log ERROR "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
    log ERROR "MANUAL_REVIEW_REQUIRED=YES"
    die "$EC_RESUME" "FAIL_RELEASE_UPGRADE_STATE_RECONCILIATION"
  fi

  RELEASE_UPGRADE_INVOCATION_STARTED="true"
  RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED="false"
  RELEASE_UPGRADE_STARTED="true"
  LEGACY_STATE_RECONCILED="true"
  if [[ "$PREVIOUS_FAILURE_CLASS" == "PRE_MUTATION_META_RELEASE_ENCODING" ]]; then
    RECONCILIATION_REASON="META_RELEASE_CONFIG_PARSE_BEFORE_TRANSACTION"
  else
    RECONCILIATION_REASON="PRE_MUTATION_FAILURE_BEFORE_TRANSACTION"
  fi
  persist_release_upgrade_flags
  log INFO "release_upgrade_invocation_started=true"
  log INFO "release_upgrade_package_transition_started=false"
  log INFO "legacy_state_reconciled=true"
  log INFO "reconciliation_reason=${RECONCILIATION_REASON}"
  return 0
}

verify_prior_critical_hold_resume_consistency() {
  # Prior unhold + live no-hold => PASS. State says removed but live held => fail-closed.
  local dir removed pkg unexpectedly_held=""
  dir="$(critical_holds_dir)"
  [[ -f "$dir/critical-holds-removed.txt" ]] || {
    log INFO "CRITICAL_OS_HOLD_STATE=NO_PRIOR_UNHOLD_RECORD"
    return 0
  }
  removed="$(tr -d '\r' <"$dir/critical-holds-removed.txt" | tr -s '[:space:]' ' ' | sed 's/[[:space:]]*$//')"
  # shellcheck disable=SC2086
  for pkg in $removed; do
    [[ -n "$pkg" ]] || continue
    if is_package_currently_held "$pkg"; then
      unexpectedly_held="${unexpectedly_held}${pkg} "
    fi
  done
  if [[ -n "$unexpectedly_held" ]]; then
    log ERROR "FAIL_CRITICAL_OS_HOLD_STATE_INCONSISTENT"
    log ERROR "REASON=prior_removed_but_currently_held"
    log ERROR "PACKAGES=${unexpectedly_held}"
    die "$EC_CRITICAL_HOLD" "FAIL_CRITICAL_OS_HOLD_STATE_INCONSISTENT"
  fi
  log INFO "CRITICAL_OS_HOLD_STATE=ALREADY_UNHELD_BY_PRIOR_PHASE1_ATTEMPT"
  log INFO "ORIGINAL_CRITICAL_OS_HOLDS=${removed}"
  log INFO "CURRENT_CRITICAL_OS_HOLDS="
  log INFO "CRITICAL_OS_HOLD_RESTORE=DEFERRED_UNTIL_PHASE2_POLICY"
  log INFO "PREVIOUS_UNHOLD_REUSED=YES"
  # Do not re-plan unhold for packages already removed.
  PLANNED_CRITICAL_OS_HOLDS=""
  return 0
}

log_idempotent_prep_states() {
  local lists f base disabled=0
  lists="$(hostpath /etc/apt/sources.list.d)"
  if [[ -d "$lists" ]]; then
    for f in "$lists"/*; do
      [[ -e "$f" ]] || continue
      base="$(basename "$f")"
      case "$base" in
        *.disabled|*.bak|*.dpkg-old|*.dpkg-dist|*.save|stellar-offline-*.list) continue ;;
        *) disabled=1 ;;
      esac
    done
  fi
  if [[ "$disabled" -eq 0 ]]; then
    log INFO "THIRD_PARTY_SOURCE_STATE=ALREADY_DISABLED"
  fi
  local passwd_file line shell
  passwd_file="$(hostpath /etc/passwd)"
  if [[ -f "$passwd_file" ]]; then
    line="$(grep -E '^aella:' "$passwd_file" 2>/dev/null || true)"
    if [[ -n "$line" ]]; then
      shell="$(printf '%s' "$line" | cut -d: -f7)"
      if [[ "$shell" == "/bin/bash" ]]; then
        log INFO "AELLA_SHELL_STATE=ALREADY_BASH"
      fi
    fi
  fi
}

assess_safe_resume_from_failed() {
  # Return 0 when FAILED state is a safe pre-mutation resume candidate.
  local ver st
  ver="$(read_os_field VERSION_ID)"
  st="$(read_state)"
  PREVIOUS_FAILURE_DETECTED="YES"
  load_release_upgrade_started_flag

  if [[ "$ver" != "$PIN_SOURCE_VERSION" ]]; then
    log ERROR "RESUME_SAFETY_VALIDATION=FAIL"
    log ERROR "REASON=os_not_source_version"
    return 1
  fi

  # Explicit pre-DRO / pre-package-transition terminal failures with no package
  # mutation evidence are safe to re-confirm; never auto-start DRO.
  # Invocation/process-spawn alone does NOT block resume.
  # Plain FAILED without a known pre-mutation signature stays non-resumable
  # (handled below via classify_previous_release_upgrade_failure).
  if [[ "$st" == "FAILED_PRE_DRO" || "$st" == "FAILED_PRE_DRO_STALE" \
     || "$st" == "FAILED_BEFORE_PACKAGE_TRANSITION" ]]; then
    if [[ "$RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED" != "true" ]] \
      && ! package_transition_evidence_present; then
      PREVIOUS_FAILURE_CLASS="PRE_DRO_FAILURE_BEFORE_TRANSACTION"
      PARTIAL_RELEASE_TRANSITION="NO"
      RESUME_FROM="PRE_DRO_CONFIGURATION"
      verify_prior_critical_hold_resume_consistency
      log_idempotent_prep_states
      log INFO "PREVIOUS_FAILURE_DETECTED=YES"
      log INFO "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS}"
      log INFO "PARTIAL_RELEASE_TRANSITION=NO"
      log INFO "RESUME_SAFETY_VALIDATION=PASS"
      log INFO "RESUME_FROM=${RESUME_FROM}"
      return 0
    fi
  fi

  reconcile_legacy_release_upgrade_state

  if ! classify_previous_release_upgrade_failure; then
    log ERROR "RESUME_SAFETY_VALIDATION=FAIL"
    log ERROR "PARTIAL_RELEASE_TRANSITION=${PARTIAL_RELEASE_TRANSITION}"
    log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS:-UNCLASSIFIED}"
    return 1
  fi

  case "$PREVIOUS_FAILURE_CLASS" in
    PRE_MUTATION_META_RELEASE_ENCODING|PRE_MUTATION_CONFIG_PARSE) ;;
    *)
      log ERROR "RESUME_SAFETY_VALIDATION=FAIL"
      log ERROR "REASON=failure_class_not_auto_resumable"
      log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS}"
      return 1
      ;;
  esac

  verify_prior_critical_hold_resume_consistency
  log_idempotent_prep_states

  RESUME_FROM="PRE_DRO_CONFIGURATION"
  log INFO "PREVIOUS_FAILURE_DETECTED=YES"
  log INFO "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS}"
  log INFO "PARTIAL_RELEASE_TRANSITION=NO"
  log INFO "RESUME_SAFETY_VALIDATION=PASS"
  log INFO "RESUME_FROM=${RESUME_FROM}"
  return 0
}

log_phase1_banner() {
  log INFO "UPGRADE_PHASE=${UPGRADE_PHASE}"
  log INFO "UPGRADE_MODE=${UPGRADE_MODE}"
  log INFO "PRODUCT_VALIDATION=OUT_OF_SCOPE"
  log INFO "SOURCE_OS=${PIN_SOURCE_VERSION}"
  log INFO "TARGET_OS=${PIN_TARGET_VERSION}"
}

detect_dp_install_state() {
  # Soft product install probe for Phase 1 logging only.
  local rc_file role_file da_conf
  DP_INSTALL_STATE="UNKNOWN"
  rc_file="$(hostpath /opt/aelladata/work/runtime_config.json)"
  role_file="$(hostpath /opt/aelladata/aella.role)"
  da_conf="$(hostpath /opt/aelladata/work/da_conf.yml)"
  if [[ -f "$rc_file" ]]; then
    if grep -qE '"installed"[[:space:]]*:[[:space:]]*false' "$rc_file" 2>/dev/null; then
      DP_INSTALL_STATE="UNINSTALLED"
      return 0
    fi
    if grep -qE '"installed"[[:space:]]*:[[:space:]]*true' "$rc_file" 2>/dev/null; then
      DP_INSTALL_STATE="INSTALLED"
      return 0
    fi
  fi
  if [[ ! -f "$role_file" && ! -f "$da_conf" ]]; then
    if [[ -d "$(hostpath /opt/aelladata)" ]]; then
      DP_INSTALL_STATE="UNINSTALLED"
      return 0
    fi
  fi
  if [[ -f "$role_file" || -f "$da_conf" ]]; then
    DP_INSTALL_STATE="PRESENT"
    return 0
  fi
  DP_INSTALL_STATE="UNKNOWN"
}

log_product_state_phase1() {
  # Diagnostic-only product probe. Never dies; never invents AIO/role files.
  local role dpver
  DP_INSTALL_STATE="UNKNOWN"
  detect_dp_install_state || true

  reset_aella_cli_capture
  capture_aella_cli_show_version || true
  detect_dp_version >/dev/null || true
  detect_dp_topology >/dev/null || true

  dpver="${DP_VERSION:-}"
  role="${DP_TOPOLOGY:-}"

  log INFO "DP_INSTALL_STATE=${DP_INSTALL_STATE}"
  log INFO "DP_PRODUCT_STATE_ACTION=IGNORED_BY_PHASE1_POLICY"
  log INFO "DP_PRODUCT_VALIDATION=NOT_IN_PHASE1_SCOPE"
  log INFO "DP_VERSION_GATE=SKIPPED_PHASE1_OS_ONLY"
  log INFO "DP_TOPOLOGY_GATE=SKIPPED_PHASE1_OS_ONLY"
  log INFO "DP_SERVICE_GATE=SKIPPED_PHASE1_OS_ONLY"

  if [[ -n "$dpver" ]]; then
    log INFO "DP_VERSION=${dpver}"
    log INFO "DP_VERSION_SOURCE=${DP_VERSION_SOURCE:-}"
    log INFO "DP_VERSION_DETECT_STATUS=${DP_VERSION_DETECT_STATUS:-}"
    log INFO "DP_VERSION_CONSISTENCY=${DP_VERSION_CONSISTENCY:-}"
  else
    log INFO "DP_VERSION=UNDETERMINED"
    log INFO "DP_VERSION_DETECT_STATUS=${DP_VERSION_DETECT_STATUS:-undetermined}"
  fi

  if [[ -n "$role" && "$role" != "UNKNOWN" ]]; then
    log INFO "DP_TOPOLOGY=${role}"
    log INFO "DP_TOPOLOGY_SOURCE=${DP_TOPOLOGY_SOURCE:-}"
    log INFO "DP_TOPOLOGY_DETECT_STATUS=${DP_TOPOLOGY_DETECT_STATUS:-}"
    log INFO "DP_TOPOLOGY_CONSISTENCY=${DP_TOPOLOGY_CONSISTENCY:-}"
    if is_supported_dp_topology "$role"; then
      DP_TOPOLOGY_SUPPORTED="INFO_AIO"
    elif is_cluster_dp_topology "$role"; then
      DP_TOPOLOGY_SUPPORTED="INFO_CLUSTER"
    else
      DP_TOPOLOGY_SUPPORTED="INFO_OTHER"
    fi
    log INFO "DP_TOPOLOGY_SUPPORTED=${DP_TOPOLOGY_SUPPORTED}"
  else
    log INFO "DP_TOPOLOGY=UNDETERMINED"
    log INFO "DP_TOPOLOGY_DETECT_STATUS=${DP_TOPOLOGY_DETECT_STATUS:-undetermined}"
    DP_TOPOLOGY_SUPPORTED="SKIPPED_PHASE1_OS_ONLY"
    log INFO "DP_TOPOLOGY_SUPPORTED=${DP_TOPOLOGY_SUPPORTED}"
  fi
}

