write_pins_env() {
  # Write root-only EnvironmentFile + pins.env copy. Never depend on systemd manager env.
  # Args: commit stamp (UTC) used for backup/restore paths.
  local stamp="${1:-}"
  local env_path pins_path tmp_env tmp_pins val_esc
  if [[ -z "$stamp" ]]; then
    die "$EC_INTERNAL" "write_pins_env requires commit stamp"
  fi
  # Handoff may have already written minimal current-hop identity — keep consistent.
  if declare -F verify_pins_match_current_hop_identity >/dev/null 2>&1; then
    verify_pins_match_current_hop_identity
  fi
  COMMIT_STAMP="$stamp"
  COMMIT_BACKUP_PATH="${BACKUP_ROOT}/${stamp}"
  # Keep PIN_MIRROR_BASE in sync with runtime --mirror-base override.
  PIN_MIRROR_BASE="${MIRROR_BASE}"

  env_path="$(hostpath "$ENV_DEFAULT_FILE")"
  pins_path="$(hostpath "$PIN_ENV_FILE")"
  mkdir -p "$(dirname "$env_path")" "$(dirname "$pins_path")" "$(hostpath "$STATE_ROOT")"

  _env_quote() {
    # Single-quote for systemd EnvironmentFile + bash source; reject newlines.
    local v="$1"
    case "$v" in
      *$'\n'*|*$'\r'*)
        die "$EC_INTERNAL" "refusing env value containing newline"
        ;;
    esac
    printf "'%s'" "${v//\'/\'\\\'\'}"
  }

  tmp_env="${env_path}.tmp.$$"
  tmp_pins="${pins_path}.tmp.$$"
  {
    printf '# stellar-offline-os-upgrade — generated by client commit; root-only\n'
    printf '# Do not log this file contents. Values are not secrets but may be large.\n'
    printf 'PIN_MIRROR_BASE=%s\n' "$(_env_quote "$PIN_MIRROR_BASE")"
    printf 'MIRROR_BASE=%s\n' "$(_env_quote "$MIRROR_BASE")"
    printf 'PIN_HOP=%s\n' "$(_env_quote "$PIN_HOP")"
    printf 'PIN_SOURCE_CODENAME=%s\n' "$(_env_quote "$PIN_SOURCE_CODENAME")"
    printf 'PIN_TARGET_CODENAME=%s\n' "$(_env_quote "$PIN_TARGET_CODENAME")"
    printf 'PIN_SOURCE_VERSION=%s\n' "$(_env_quote "$PIN_SOURCE_VERSION")"
    printf 'PIN_TARGET_VERSION=%s\n' "$(_env_quote "$PIN_TARGET_VERSION")"
    printf 'PIN_COMPONENTS=%s\n' "$(_env_quote "$PIN_COMPONENTS")"
    printf 'PIN_SOURCE_SUITES=%s\n' "$(_env_quote "$PIN_SOURCE_SUITES")"
    printf 'PIN_TARGET_SUITES=%s\n' "$(_env_quote "$PIN_TARGET_SUITES")"
    printf 'PIN_KEY_FINGERPRINT=%s\n' "$(_env_quote "$PIN_KEY_FINGERPRINT")"
    printf 'PIN_UPGRADER_TAR_SHA256=%s\n' "$(_env_quote "$PIN_UPGRADER_TAR_SHA256")"
    printf 'PIN_UPGRADER_GPG_SHA256=%s\n' "$(_env_quote "$PIN_UPGRADER_GPG_SHA256")"
    printf 'PIN_PLAN_CHECKSUM=%s\n' "$(_env_quote "$PIN_PLAN_CHECKSUM")"
    printf 'PIN_DISCOVERY_CHECKSUM=%s\n' "$(_env_quote "$PIN_DISCOVERY_CHECKSUM")"
    printf 'STATE_ROOT=%s\n' "$(_env_quote "$STATE_ROOT")"
    printf 'STATE_FILE=%s\n' "$(_env_quote "$STATE_FILE")"
    printf 'HISTORY_FILE=%s\n' "$(_env_quote "$HISTORY_FILE")"
    printf 'LOG_FILE=%s\n' "$(_env_quote "$LOG_FILE")"
    printf 'BACKUP_ROOT=%s\n' "$(_env_quote "$BACKUP_ROOT")"
    printf 'COMMIT_STAMP=%s\n' "$(_env_quote "$COMMIT_STAMP")"
    printf 'COMMIT_BACKUP_PATH=%s\n' "$(_env_quote "$COMMIT_BACKUP_PATH")"
    printf 'HOLDS_DIR=%s\n' "$(_env_quote "$HOLDS_DIR")"
    printf 'DISTUPGRADE_SOURCES_PATH=%s\n' "$(_env_quote "$DISTUPGRADE_SOURCES_PATH")"
    printf 'DISTUPGRADE_MIRRORS_FILE=%s\n' "$(_env_quote "${DISTUPGRADE_MIRRORS_FILE:-${STATE_ROOT}/distupgrade-valid-mirrors.cfg}")"
    printf 'DISTUPGRADE_OVERRIDE_CFG=%s\n' "$(_env_quote "${DISTUPGRADE_OVERRIDE_CFG:-/etc/update-manager/release-upgrades.d/99-stellar-offline-mirror.cfg}")"
    printf 'EFFECTIVE_SOURCE_GATE_BIN=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_BIN:-${STATE_ROOT}/bin/distupgrade-effective-source-gate}")"
    printf 'EFFECTIVE_SOURCE_GATE_APT=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_APT:-/etc/apt/apt.conf.d/98stellar-distupgrade-source-gate}")"
    printf 'NONINTERACTIVE_CONFFILE_APT_CONFIG=%s\n' "$(_env_quote "${NONINTERACTIVE_CONFFILE_APT_CONFIG:-/etc/apt/apt.conf.d/97stellar-offline-conffile-policy}")"
    printf 'EFFECTIVE_SOURCE_CAPTURE_DIR=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_CAPTURE_DIR:-${STATE_ROOT}/effective-sources}")"
    printf 'EFFECTIVE_SOURCE_GATE_ARMED_MARKER=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_ARMED_MARKER:-${STATE_ROOT}/effective-source-gate.armed}")"
    printf 'EFFECTIVE_SOURCE_GATE_PASSED_MARKER=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_PASSED_MARKER:-${STATE_ROOT}/effective-source-gate.passed}")"
    printf 'EFFECTIVE_SOURCE_GATE_LOG=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_LOG:-/var/log/aella/distupgrade_effective_source_gate.log}")"
    printf 'EFFECTIVE_SOURCE_GATE_EVIDENCE_ROOT=%s\n' "$(_env_quote "${EFFECTIVE_SOURCE_GATE_EVIDENCE_ROOT:-${STATE_ROOT}/evidence/effective-source-gate}")"
    printf 'META_RELEASE_FILE=%s\n' "$(_env_quote "$META_RELEASE_FILE")"
    printf 'LEGACY_APT_KEYRING_PATH=%s\n' "$(_env_quote "$LEGACY_APT_KEYRING_PATH")"
    printf 'RUNNER_PID_FILE=%s\n' "$(_env_quote "$RUNNER_PID_FILE")"
    printf 'UNIT_NAME=%s\n' "$(_env_quote "$UNIT_NAME")"
    printf 'POSTBOOT_UNIT_NAME=%s\n' "$(_env_quote "$POSTBOOT_UNIT_NAME")"
    # Official DistUpgradeController env override for internal mirrors.
    printf 'RELEASE_UPGRADER_ALLOW_THIRD_PARTY=%s\n' "$(_env_quote "1")"
  } >"$tmp_env"
  cp -f "$tmp_env" "$tmp_pins"
  chmod 0600 "$tmp_env" "$tmp_pins"
  chown root:root "$tmp_env" "$tmp_pins" 2>/dev/null || true
  mv -f "$tmp_env" "$env_path"
  mv -f "$tmp_pins" "$pins_path"
  chmod 0600 "$env_path" "$pins_path"
  chown root:root "$env_path" "$pins_path" 2>/dev/null || true
  log INFO "RUNNER_ENV_FILE=${ENV_DEFAULT_FILE}"
  log INFO "RUNNER_ENV_FILE_MODE=0600"
  log INFO "PIN_MIRROR_BASE_RESOLVED=${PIN_MIRROR_BASE}"
  log INFO "PIN_HOP=${PIN_HOP}"
  log INFO "COMMIT_BACKUP_PATH=${COMMIT_BACKUP_PATH}"
}

# --- systemd handoff (non-blocking start; evidence-based PASS/FAIL) ---

is_dbus_disconnect_text() {
  local text="$1"
  printf '%s' "$text" | grep -qiE \
    'D-Bus connection terminated|Failed to wait for response|Connection reset by peer|Transport endpoint is not connected'
}

allow_live_systemctl() {
  # Never touch host systemd from TEST_ROOT unless handoff fixture opts in.
  if [[ -n "$TEST_ROOT" && "${DP_OFFLINE_TEST_HANDOFF:-}" != "1" ]]; then
    return 1
  fi
  return 0
}

run_systemctl() {
  # Run systemctl in the *current* shell so LAST_SYSTEMCTL_* and
  # DBUS_DISCONNECT_SEEN persist (never call via $(run_systemctl ...)).
  local out rc
  LAST_SYSTEMCTL_OUTPUT=""
  LAST_SYSTEMCTL_RC=0
  if ! allow_live_systemctl; then
    LAST_SYSTEMCTL_RC=1
    LAST_SYSTEMCTL_OUTPUT="TEST_ROOT_SYSTEMCTL_SKIPPED"
    return 1
  fi
  set +e
  out="$("$SYSTEMCTL_BIN" "$@" 2>&1)"
  rc=$?
  set +e
  LAST_SYSTEMCTL_OUTPUT="$out"
  LAST_SYSTEMCTL_RC="$rc"
  if is_dbus_disconnect_text "$out"; then
    DBUS_DISCONNECT_SEEN=1
  fi
  return "$rc"
}

systemctl_show_prop() {
  # Portable for systemd 229 (no --value): parse Property= lines.
  local prop="$1"
  local unit="${2:-$UNIT_NAME}"
  set +e
  run_systemctl show -p "$prop" "$unit"
  set +e
  printf '%s\n' "$LAST_SYSTEMCTL_OUTPUT" | sed -n "s/^${prop}=//p" | head -n 1
  return 0
}

proc_cmdline() {
  local pid="$1"
  local raw
  [[ -n "$pid" && "$pid" != "0" && -r "/proc/${pid}/cmdline" ]] || return 1
  raw="$(tr '\0' ' ' <"/proc/${pid}/cmdline" 2>/dev/null || true)"
  printf '%s' "$raw"
}

runner_cmdline_matches() {
  local pid="$1"
  local cmd prefix
  cmd="$(proc_cmdline "$pid" 2>/dev/null || true)"
  [[ -n "$cmd" ]] || return 1
  printf '%s' "$cmd" | grep -q 'stellar-offline-os-upgrade-runner' || return 1
  # Fixture tests: only match runners under the active fake-root prefix.
  prefix="${STELLAR_OFFLINE_TEST_ROOT:-${TEST_ROOT:-${DP_OFFLINE_TEST_ROOT:-}}}"
  if [[ -n "$prefix" ]]; then
    printf '%s' "$cmd" | grep -qF "$prefix" || return 1
  fi
  return 0
}

find_runner_pid_via_ps() {
  # Prefer ps (fast) over full /proc walk.
  local pid prefix
  prefix="${STELLAR_OFFLINE_TEST_ROOT:-${TEST_ROOT:-${DP_OFFLINE_TEST_ROOT:-}}}"
  if [[ -n "$prefix" ]]; then
    pid="$(ps -eo pid=,args= 2>/dev/null | awk -v p="$prefix" '
      index($0, "stellar-offline-os-upgrade-runner") && index($0, p) && $0 !~ /awk/ {
        print $1; exit
      }')"
  else
    pid="$(ps -eo pid=,args= 2>/dev/null | awk '/stellar-offline-os-upgrade-runner/ && !/awk/ {print $1; exit}')"
  fi
  if [[ -n "$pid" && -d "/proc/${pid}" ]]; then
    printf '%s' "$pid"
    return 0
  fi
  return 1
}

find_dro_pid_via_ps() {
  local pid
  pid="$(ps -eo pid=,args= 2>/dev/null | awk '/do-release-upgrade/ && !/awk/ {print $1; exit}')"
  if [[ -n "$pid" && -d "/proc/${pid}" ]]; then
    printf '%s' "$pid"
    return 0
  fi
  return 1
}

resolve_upgrade_runner_pid() {
  local main_pid ps_pid
  main_pid="$(systemctl_show_prop MainPID "$UNIT_NAME" || true)"
  if [[ -n "$main_pid" && "$main_pid" != "0" ]] && [[ -d "/proc/${main_pid}" ]]; then
    if runner_cmdline_matches "$main_pid"; then
      printf '%s' "$main_pid"
      return 0
    fi
  fi
  ps_pid="$(find_runner_pid_via_ps || true)"
  if [[ -n "$ps_pid" && -d "/proc/${ps_pid}" ]]; then
    printf '%s' "$ps_pid"
    return 0
  fi
  return 1
}

state_is_upgrade_running() {
  local st="$1"
  case "$st" in
    # PREPARING_FOCAL alone is not proof of a live upgrade (may be stale after runner crash).
    UPGRADING_FOCAL_TO_JAMMY|POST_UPGRADE_VERIFY|REBOOT_PENDING|REBOOTING)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

state_is_in_progress_or_configuring() {
  local st="$1"
  case "$st" in
    CONFIGURING|PREPARING_FOCAL|UPGRADING_FOCAL_TO_JAMMY|REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|POST_UPGRADE_VERIFY)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

state_is_stale_candidate() {
  local st="$1"
  case "$st" in
    CONFIGURING|PREPARING_FOCAL)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

collect_upgrade_liveness() {
  # Sets globals: LIVE_SERVICE_ACTIVE LIVE_RUNNER_PRESENT LIVE_DRO_PRESENT LIVE_MAIN_PID
  LIVE_SERVICE_ACTIVE="NO"
  LIVE_RUNNER_PRESENT="NO"
  LIVE_DRO_PRESENT="NO"
  LIVE_MAIN_PID="0"
  if ! allow_live_systemctl; then
    return 0
  fi
  local active main_pid runner_pid dro_pid
  active="$(systemctl_show_prop ActiveState "$UNIT_NAME" || true)"
  case "$active" in
    activating|active) LIVE_SERVICE_ACTIVE="YES" ;;
  esac
  main_pid="$(systemctl_show_prop MainPID "$UNIT_NAME" || true)"
  if [[ -n "$main_pid" && "$main_pid" != "0" ]] && [[ -d "/proc/${main_pid}" ]]; then
    LIVE_MAIN_PID="$main_pid"
    LIVE_RUNNER_PRESENT="YES"
  fi
  runner_pid="$(find_runner_pid_via_ps || true)"
  if [[ -n "$runner_pid" ]]; then
    LIVE_RUNNER_PRESENT="YES"
  fi
  dro_pid="$(find_dro_pid_via_ps || true)"
  if [[ -n "$dro_pid" ]]; then
    LIVE_DRO_PRESENT="YES"
  fi
}

live_upgrade_evidence_present() {
  collect_upgrade_liveness
  if [[ "$LIVE_SERVICE_ACTIVE" == "YES" \
     || "$LIVE_RUNNER_PRESENT" == "YES" \
     || "$LIVE_DRO_PRESENT" == "YES" ]]; then
    return 0
  fi
  return 1
}

transaction_markers_any_true() {
  # Package-mutation markers only, and only when owned by the current hop.
  if declare -F classify_mutation_evidence_ownership >/dev/null 2>&1; then
    classify_mutation_evidence_ownership || true
    [[ "${MUTATION_EVIDENCE_CLASS}" == "CURRENT_HOP_MUTATION" ]]
    return $?
  fi
  # Legacy fallback for partial test harnesses that do not embed hop ownership helpers.
  local dir
  dir="$(hostpath ${HOLDS_DIR})"
  if [[ -f "${dir}/release_upgrade_package_transition_started" ]] \
    && grep -qx 'true' "${dir}/release_upgrade_package_transition_started"; then
    return 0
  fi
  if declare -F package_transition_evidence_present >/dev/null 2>&1; then
    package_transition_evidence_present && return 0
  fi
  return 1
}

preserve_stale_state_evidence() {
  local st="$1"
  local dest
  dest="$(hostpath ${BACKUP_ROOT}/stale-state-$(date -u '+%Y%m%dT%H%M%SZ'))"
  mkdir -p "$dest"
  cp -a "$(hostpath "$STATE_FILE")" "$dest/state" 2>/dev/null || true
  cp -a "$(hostpath "$LOG_FILE")" "$dest/offline_os_upgrade.log" 2>/dev/null || true
  if [[ -d "$(hostpath "$HOLDS_DIR")" ]]; then
    mkdir -p "$dest/critical-holds"
    cp -a "$(hostpath "$HOLDS_DIR")/." "$dest/critical-holds/" 2>/dev/null || true
  fi
  if [[ -f "$(hostpath "$ENV_DEFAULT_FILE")" ]]; then
    # Copy metadata only — do not dump full env into operator console logs.
    cp -a "$(hostpath "$ENV_DEFAULT_FILE")" "$dest/stellar-offline-os-upgrade.env" 2>/dev/null || true
  fi
  {
    echo "STALE_STATE_DETECTED=YES"
    echo "PREVIOUS_STATE=${st}"
    echo "SERVICE_ACTIVE=${LIVE_SERVICE_ACTIVE:-NO}"
    echo "RUNNER_PROCESS_PRESENT=${LIVE_RUNNER_PRESENT:-NO}"
    echo "DO_RELEASE_UPGRADE_PROCESS_PRESENT=${LIVE_DRO_PRESENT:-NO}"
    echo "STALE_STATE_RECOVERY_REQUIRED=YES"
  } >"$dest/liveness.txt"
  log INFO "STALE_STATE_EVIDENCE=${dest}"
  printf '%s' "$dest"
}

handle_stale_pre_dro_state() {
  local st="$1"
  collect_upgrade_liveness
  log INFO "STALE_STATE_DETECTED=YES"
  log INFO "SERVICE_ACTIVE=${LIVE_SERVICE_ACTIVE}"
  log INFO "RUNNER_PROCESS_PRESENT=${LIVE_RUNNER_PRESENT}"
  log INFO "DO_RELEASE_UPGRADE_PROCESS_PRESENT=${LIVE_DRO_PRESENT}"
  log INFO "STALE_STATE_RECOVERY_REQUIRED=YES"
  preserve_stale_state_evidence "$st" >/dev/null
  if transaction_markers_any_true; then
    log ERROR "STALE_STATE_CLASS=UNSAFE_OR_AMBIGUOUS"
    log ERROR "manual recovery required; state file not deleted"
    die "$EC_STATE" "stale state '${st}' with transaction markers; refusing automatic resume"
  fi
  # Safe pre-DRO stale: classify terminal failure without deleting evidence.
  write_state "FAILED_PRE_DRO_STALE"
  # Clear stale runner pid file if present.
  rm -f "$(hostpath "$RUNNER_PID_FILE")" 2>/dev/null || true
  printf '0\n' >"$(hostpath "$RUNNER_PID_FILE")" 2>/dev/null || true
  rm -f "$(hostpath "$RUNNER_PID_FILE")" 2>/dev/null || true
  log INFO "STALE_STATE_CLASS=FAILED_PRE_DRO_STALE"
  log INFO "ACTION=TERMINAL_FAILURE_CLASSIFIED"
  log INFO "previous state=${st} classified as FAILED_PRE_DRO_STALE (not MONITOR_ONLY)"
  return 0
}

log_has_runner_evidence() {
  local logf
  logf="$(hostpath "$LOG_FILE")"
  [[ -f "$logf" ]] || return 1
  grep -qE 'RUNNER_START=PASS|STAGE=SOURCE_RELEASE_PREPARATION|STAGE=DO_RELEASE_UPGRADE' "$logf" 2>/dev/null
}

unit_looks_failed() {
  local active
  active="$(systemctl_show_prop ActiveState "$UNIT_NAME" || true)"
  [[ "$active" == "failed" ]]
}

print_upgrade_monitor_hints() {
  log INFO "UPGRADE_MONITOR_SERVICE=systemctl status ${UNIT_NAME} --no-pager -l"
  log INFO "UPGRADE_MONITOR_LOG=tail -f ${LOG_FILE}"
  log INFO "UPGRADE_MONITOR_STATE=cat ${STATE_FILE}"
  cat <<EOF

Monitor with:
  systemctl status ${UNIT_NAME} --no-pager -l
  tail -f ${LOG_FILE}
  cat ${STATE_FILE}
EOF
}

client_is_interactive_tty() {
  # Test overrides (fixture-only).
  if [[ "${DP_OFFLINE_FORCE_NONINTERACTIVE:-}" == "1" ]]; then
    return 1
  fi
  if [[ "${DP_OFFLINE_FORCE_MONITOR:-}" == "1" ]]; then
    return 0
  fi
  [[ -t 0 && -t 1 ]]
}

should_attach_progress_monitor() {
  if [[ "${DETACH_AFTER_HANDOFF:-0}" -eq 1 ]]; then
    return 1
  fi
  client_is_interactive_tty
}

utc_now() {
  date -u '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null || date
}

format_monitor_elapsed() {
  local secs="$1"
  local h m s
  [[ -n "$secs" ]] || secs=0
  h=$((secs / 3600))
  m=$(((secs % 3600) / 60))
  s=$((secs % 60))
  printf '%02d:%02d:%02d' "$h" "$m" "$s"
}

state_user_message() {
  case "${1:-}" in
    PREPARING_FOCAL)
      printf '%s' "Preparing repositories and release-upgrade configuration."
      ;;
    UPGRADING_FOCAL_TO_JAMMY)
      printf '%s' "Ubuntu package upgrade is actively running. Do not interrupt the host."
      ;;
    POST_UPGRADE_VERIFY)
      printf '%s' "Package upgrade completed. Running pre-reboot validation."
      ;;
    REBOOT_PENDING)
      printf '%s' "Validation completed. Automatic reboot is pending."
      ;;
    REBOOTING)
      printf '%s' "The host is rebooting. This SSH session will disconnect."
      ;;
    FAILED|FAILED_PRE_DRO|FAILED_BEFORE_PACKAGE_TRANSITION|FAILED_AFTER_PACKAGE_TRANSITION|FAILED_PRE_DRO_STALE|FAILED_POST_TRANSACTION)
      printf '%s' "The background upgrade reported a failure. Do not rerun the client."
      ;;
    SUCCESS|COMPLETED_JAMMY|POST_BOOT_VERIFY)
      printf '%s' "The background upgrade completed successfully."
      ;;
    *)
      printf '%s' "Background upgrade is in progress."
      ;;
  esac
}

state_is_terminal_success() {
  case "${1:-}" in
    REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|COMPLETED_JAMMY|SUCCESS)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

state_is_terminal_failure() {
  case "${1:-}" in
    FAILED|FAILED_PRE_DRO|FAILED_BEFORE_PACKAGE_TRANSITION|FAILED_AFTER_PACKAGE_TRANSITION|FAILED_PRE_DRO_STALE|FAILED_POST_TRANSACTION)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

state_is_terminal_state() {
  state_is_terminal_failure "${1:-}" || state_is_terminal_success "${1:-}"
}

state_is_active_progress() {
  case "${1:-}" in
    CONFIGURING|PREPARING_FOCAL|UPGRADING_FOCAL_TO_JAMMY|POST_UPGRADE_VERIFY)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

log_has_terminal_failure_marker() {
  local logf
  logf="$(hostpath "$LOG_FILE")"
  [[ -f "$logf" ]] || return 1
  grep -qE 'STATE=FAILED|os_upgrade_result=FAIL|UPGRADE_FAILED=YES|FAIL_STAGE=' "$logf" 2>/dev/null
}

monitor_runner_alive() {
  local pid="${1:-0}"
  [[ -n "$pid" && "$pid" != "0" ]] || return 1
  [[ -d "/proc/${pid}" ]] || return 1
  runner_cmdline_matches "$pid"
}

monitor_resolve_runner_pid() {
  # D-Bus-free: prefer known PID + /proc + pgrep/ps fallback.
  local pid="${1:-0}"
  if monitor_runner_alive "$pid"; then
    printf '%s' "$pid"
    return 0
  fi
  pid="$(find_runner_pid_via_ps || true)"
  if monitor_runner_alive "$pid"; then
    printf '%s' "$pid"
    return 0
  fi
  return 1
}

monitor_emit_new_log_bytes() {
  local logf="$1"
  local size=0
  [[ -f "$logf" ]] || return 0
  size="$(wc -c <"$logf" | tr -d '[:space:]')"
  [[ -n "$size" ]] || size=0
  if [[ "$size" -lt "${MONITOR_LOG_OFFSET:-0}" ]]; then
    # Log truncated or rotated — resync from start of new file.
    MONITOR_LOG_OFFSET=0
  fi
  if [[ "$size" -gt "${MONITOR_LOG_OFFSET:-0}" ]]; then
    tail -c "+$((MONITOR_LOG_OFFSET + 1))" "$logf" 2>/dev/null || true
    MONITOR_LOG_OFFSET="$size"
  fi
}

print_background_upgrade_banner() {
  local st pid
  st="${1:-$(read_state)}"
  pid="${2:-${UPGRADE_RUNNER_PID:-0}}"
  cat <<EOF

============================================================
 BACKGROUND OFFLINE UPGRADE IS RUNNING
============================================================
Service:    ${UNIT_NAME}
Runner PID: ${pid}
State:      ${st:-UNKNOWN}

The upgrade is running independently under systemd.
This terminal is attached only to the progress monitor.

- Closing SSH will NOT stop the upgrade
- Pressing Ctrl+C will stop monitoring only
- Do NOT run the upgrade client again
- The host will reboot automatically after completion
============================================================

Following upgrade progress...
Persistent log: ${LOG_FILE}
State file:     ${STATE_FILE}
EOF
}

print_monitor_stopped_banner() {
  cat <<EOF

============================================================
 MONITORING STOPPED
============================================================
The background upgrade is still running under systemd.
Stopping this monitor did NOT stop the upgrade.

Check again with:
  cat ${STATE_FILE}
  tail -f ${LOG_FILE}
  systemctl status ${UNIT_NAME} --no-pager -l
============================================================
EOF
}

print_stage_changed_banner() {
  local prev="$1" cur="$2" when
  when="$(utc_now)"
  cat <<EOF

============================================================
 UPGRADE STAGE CHANGED
============================================================
Previous: ${prev:-UNKNOWN}
Current:  ${cur:-UNKNOWN}
Time:     ${when}
$(state_user_message "$cur")
============================================================
EOF
}

print_reboot_starting_banner() {
  cat <<EOF

============================================================
 UPGRADE COMPLETED — AUTOMATIC REBOOT STARTING
============================================================
The package upgrade and pre-reboot validation completed.
The host will reboot automatically.
This SSH session is expected to disconnect.
Do not manually restart the client.
============================================================
EOF
}

print_upgrade_failed_banner() {
  local st="$1" pid="$2" logf
  logf="$(hostpath "$LOG_FILE")"
  cat <<EOF

============================================================
 BACKGROUND UPGRADE FAILED
============================================================
State: ${st:-UNKNOWN}
Last known runner PID: ${pid:-0}
Last log entries:
EOF
  if [[ -f "$logf" ]]; then
    tail -n 20 "$logf" 2>/dev/null || true
  else
    echo "(persistent log missing)"
  fi
  cat <<EOF
Do not rerun the client until the failure is reviewed.
============================================================
EOF
}

print_already_running_banner() {
  local st="$1" pid="$2" attach="${3:-no}"
  cat <<EOF

============================================================
 UPGRADE ALREADY RUNNING
============================================================
State:      ${st:-UNKNOWN}
Runner PID: ${pid:-0}
Action:     MONITOR_ONLY

A second upgrade will not be started.
EOF
  if [[ "$attach" == "yes" ]]; then
    cat <<EOF
Attaching to the existing upgrade progress monitor...
============================================================
EOF
  else
    cat <<EOF
Use the monitor commands below to follow progress.
============================================================
EOF
  fi
}

print_handoff_complete_banner() {
  # Non-interactive / --detach path: handoff done, no foreground monitor.
  cat <<EOF

============================================================
OFFLINE UPGRADE HANDOFF COMPLETE
============================================================
- Upgrade service started under systemd
- Upgrade continues independently from this client
- Do not run this client again
- Monitor the service and persistent upgrade log
============================================================
EOF
  print_upgrade_monitor_hints
}

emit_handoff_policy_logs() {
  local attach="$1"
  log INFO "UPGRADE_PROCESS_POLICY=DETACHED_UNDER_SYSTEMD"
  log INFO "BACKGROUND_UPGRADE_RUNNING=YES"
  if [[ "$attach" == "foreground" ]]; then
    log INFO "CLIENT_MONITOR_POLICY=FOREGROUND_READ_ONLY"
    log INFO "MONITOR_MODE=FOREGROUND_READ_ONLY"
    log INFO "MONITOR_CAN_BE_INTERRUPTED=YES"
    log INFO "MONITOR_INTERRUPT_STOPS_UPGRADE=NO"
  elif [[ "$attach" == "detach" ]]; then
    log INFO "CLIENT_MONITOR_POLICY=DETACHED_BY_REQUEST"
  else
    log INFO "CLIENT_MONITOR_POLICY=DETACHED_NONINTERACTIVE"
  fi
}

maybe_attach_progress_monitor() {
  # Return contract mirrors monitor_upgrade_progress:
  #   0 = terminal success / user interrupt (detached-running) / detach path
  #   non-zero = terminal failure / runner inconsistency
  local runner_pid="${1:-${UPGRADE_RUNNER_PID:-0}}"
  local st
  st="$(read_state)"

  if [[ "${DETACH_AFTER_HANDOFF:-0}" -eq 1 ]]; then
    emit_handoff_policy_logs "detach"
    print_handoff_complete_banner
    MONITOR_RESULT="DETACHED_BY_REQUEST"
    return 0
  fi

  if ! should_attach_progress_monitor; then
    emit_handoff_policy_logs "noninteractive"
    print_handoff_complete_banner
    MONITOR_RESULT="DETACHED_NONINTERACTIVE"
    return 0
  fi

  local mon_rc=0
  emit_handoff_policy_logs "foreground"
  print_background_upgrade_banner "$st" "$runner_pid"
  set +e
  monitor_upgrade_progress "$runner_pid"
  mon_rc=$?
  set +e
  return "$mon_rc"
}

monitor_upgrade_progress() {
  # Read-only progress monitor. Never signals the runner or systemd unit.
  local runner_pid="${1:-0}"
  local logf statef
  local last_state="" cur_state=""
  local start_epoch now_epoch last_hb_epoch elapsed last_log_age
  local runner_status="UNKNOWN"
  local poll hb recent max_secs
  local dro_pid="" new_pid=""
  local reboot_announced=0
  local failed=0
  local log_mtime=0

  # Ctrl+C interrupts sleep(1); with set -e that would abort before the
  # MONITOR_INTERRUPTED check. Keep the loop resilient for the monitor only.
  set +e

  logf="$(hostpath "$LOG_FILE")"
  statef="$(hostpath "$STATE_FILE")"
  poll="${MONITOR_POLL_SECS:-3}"
  hb="${MONITOR_HEARTBEAT_SECS:-15}"
  recent="${MONITOR_RECENT_LINES:-15}"
  max_secs="${DP_OFFLINE_MONITOR_MAX_SECS:-0}"
  if [[ -z "$poll" || "$poll" -lt 1 ]]; then poll=1; fi
  if [[ -z "$hb" || "$hb" -lt 1 ]]; then hb=15; fi
  if [[ -z "$recent" || "$recent" -lt 1 ]]; then recent=15; fi

  MONITOR_INTERRUPTED=0
  MONITOR_EXIT_REASON=""
  MONITOR_RESULT=""
  # Trap only in this monitor scope — never forward to runner/service.
  trap 'MONITOR_INTERRUPTED=1' INT TERM

  runner_pid="$(monitor_resolve_runner_pid "$runner_pid" || true)"
  [[ -n "$runner_pid" ]] || runner_pid="${UPGRADE_RUNNER_PID:-0}"
  UPGRADE_RUNNER_PID="$runner_pid"

  echo ""
  echo "--- recent upgrade log (last ${recent} lines) ---"
  if [[ -f "$logf" ]]; then
    tail -n "$recent" "$logf" 2>/dev/null || true
    MONITOR_LOG_OFFSET="$(wc -c <"$logf" | tr -d '[:space:]')"
  else
    MONITOR_LOG_OFFSET=0
    echo "(log not created yet)"
  fi
  echo "--- live progress (new lines + heartbeat) ---"

  last_state="$(read_state)"
  start_epoch="$(date +%s 2>/dev/null || echo 0)"
  last_hb_epoch="$start_epoch"

  while true; do
    if [[ "${MONITOR_INTERRUPTED:-0}" -eq 1 ]]; then
      MONITOR_EXIT_REASON="USER_INTERRUPT"
      MONITOR_RESULT="DETACHED_RUNNING"
      log INFO "MONITOR_EXIT_REASON=USER_INTERRUPT"
      log INFO "MONITOR_RESULT=DETACHED_RUNNING"
      log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
      log INFO "UPGRADE_SERVICE_CONTINUES=YES"
      print_monitor_stopped_banner
      trap - INT TERM
      return 0
    fi

    now_epoch="$(date +%s 2>/dev/null || echo 0)"
    if [[ -n "$max_secs" && "$max_secs" -gt 0 ]]; then
      if [[ $((now_epoch - start_epoch)) -ge "$max_secs" ]]; then
        MONITOR_EXIT_REASON="TEST_MAX_SECS"
        MONITOR_RESULT="DETACHED_RUNNING"
        log INFO "MONITOR_EXIT_REASON=TEST_MAX_SECS"
        log INFO "MONITOR_RESULT=DETACHED_RUNNING"
        log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
        log INFO "UPGRADE_SERVICE_CONTINUES=YES"
        trap - INT TERM
        return 0
      fi
    fi

    new_pid="$(monitor_resolve_runner_pid "$runner_pid" || true)"
    if [[ -n "$new_pid" ]]; then
      runner_pid="$new_pid"
      UPGRADE_RUNNER_PID="$runner_pid"
      runner_status="ALIVE"
    else
      runner_status="GONE"
    fi

    cur_state="$(read_state)"
    if [[ -n "$cur_state" && "$cur_state" != "$last_state" ]]; then
      print_stage_changed_banner "$last_state" "$cur_state"
      case "$cur_state" in
        REBOOT_PENDING|REBOOTING)
          if [[ "$reboot_announced" -eq 0 ]]; then
            print_reboot_starting_banner
            log INFO "UPGRADE_REBOOT_ANNOUNCED=YES"
            log INFO "SSH_DISCONNECT_EXPECTED=YES"
            reboot_announced=1
          fi
          ;;
      esac
      if state_is_terminal_failure "$cur_state"; then
        failed=1
      fi
      last_state="$cur_state"
      # Do not reset heartbeat timer on stage change — users still need
      # periodic alive signals when logs are quiet between stages.
    fi

    monitor_emit_new_log_bytes "$logf"

    # Terminal failure states (including FAILED_PRE_DRO): exit immediately.
    # Never keep printing "Background upgrade is in progress" / heartbeats.
    if state_is_terminal_failure "$cur_state" || [[ "$failed" -eq 1 ]]; then
      MONITOR_EXIT_REASON="TERMINAL_FAILURE_STATE"
      MONITOR_RESULT="TERMINAL_FAILURE"
      log ERROR "MONITOR_TERMINAL_STATE_DETECTED=${cur_state:-UNKNOWN}"
      if [[ "$runner_status" == "ALIVE" ]]; then
        log INFO "MONITOR_RUNNER_PRESENT=YES"
      else
        log INFO "MONITOR_RUNNER_PRESENT=NO"
      fi
      log ERROR "MONITOR_EXIT_REASON=TERMINAL_FAILURE_STATE"
      log ERROR "MONITOR_RESULT=TERMINAL_FAILURE"
      log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
      print_upgrade_failed_banner "${cur_state:-UNKNOWN}" "$runner_pid"
      trap - INT TERM
      return 1
    fi

    if state_is_terminal_success "$cur_state"; then
      MONITOR_EXIT_REASON="TERMINAL_SUCCESS_STATE"
      MONITOR_RESULT="TERMINAL_SUCCESS"
      log INFO "MONITOR_TERMINAL_STATE_DETECTED=${cur_state}"
      log INFO "MONITOR_EXIT_REASON=TERMINAL_SUCCESS_STATE"
      log INFO "MONITOR_RESULT=TERMINAL_SUCCESS"
      log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
      if [[ "$reboot_announced" -eq 0 ]] && [[ "$cur_state" == "REBOOT_PENDING" || "$cur_state" == "REBOOTING" ]]; then
        print_reboot_starting_banner
        reboot_announced=1
      fi
      trap - INT TERM
      return 0
    fi

    if [[ "$runner_status" == "GONE" ]] && state_is_active_progress "$cur_state"; then
      dro_pid="$(find_dro_pid_via_ps || true)"
      if [[ -z "$dro_pid" ]]; then
        # Brief grace: runner may be restarting between stages.
        sleep 1
        new_pid="$(monitor_resolve_runner_pid "$runner_pid" || true)"
        dro_pid="$(find_dro_pid_via_ps || true)"
        if [[ -z "$new_pid" && -z "$dro_pid" ]]; then
          MONITOR_EXIT_REASON="RUNNER_GONE"
          MONITOR_RESULT="TERMINAL_FAILURE"
          log ERROR "MONITOR_EXIT_REASON=RUNNER_GONE"
          log ERROR "MONITOR_RESULT=TERMINAL_FAILURE"
          log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
          print_upgrade_failed_banner "${cur_state:-UNKNOWN}" "$runner_pid"
          trap - INT TERM
          return 1
        fi
        if [[ -n "$new_pid" ]]; then
          runner_pid="$new_pid"
          UPGRADE_RUNNER_PID="$runner_pid"
          runner_status="ALIVE"
        fi
      fi
    fi

    # Runner disappeared and state is neither terminal nor active progress.
    if [[ "$runner_status" == "GONE" ]] && ! state_is_terminal_state "$cur_state" \
       && ! state_is_active_progress "$cur_state"; then
      dro_pid="$(find_dro_pid_via_ps || true)"
      sleep 1
      new_pid="$(monitor_resolve_runner_pid "$runner_pid" || true)"
      dro_pid="$(find_dro_pid_via_ps || true)"
      if [[ -z "$new_pid" && -z "$dro_pid" ]]; then
        MONITOR_EXIT_REASON="RUNNER_MISSING_WITHOUT_TERMINAL_STATE"
        MONITOR_RESULT="TERMINAL_FAILURE"
        log ERROR "MONITOR_EXIT_REASON=RUNNER_MISSING_WITHOUT_TERMINAL_STATE"
        log ERROR "MONITOR_RESULT=TERMINAL_FAILURE"
        log ERROR "MONITOR_RUNNER_PRESENT=NO"
        log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
        print_upgrade_failed_banner "${cur_state:-UNKNOWN}" "$runner_pid"
        trap - INT TERM
        return 1
      fi
      if [[ -n "$new_pid" ]]; then
        runner_pid="$new_pid"
        UPGRADE_RUNNER_PID="$runner_pid"
        runner_status="ALIVE"
      fi
    fi

    if ! state_is_terminal_failure "$cur_state" && state_is_active_progress "$cur_state" \
       && log_has_terminal_failure_marker; then
      MONITOR_EXIT_REASON="LOG_FAILURE_MARKER"
      MONITOR_RESULT="TERMINAL_FAILURE"
      log ERROR "MONITOR_EXIT_REASON=LOG_FAILURE_MARKER"
      log ERROR "MONITOR_RESULT=TERMINAL_FAILURE"
      log INFO "UPGRADE_SERVICE_STOP_REQUESTED=NO"
      print_upgrade_failed_banner "${cur_state:-UNKNOWN}" "$runner_pid"
      trap - INT TERM
      return 1
    fi

    # Heartbeat only while upgrade is still in an active non-terminal state.
    if state_is_active_progress "$cur_state" \
       && [[ $((now_epoch - last_hb_epoch)) -ge "$hb" ]]; then
      elapsed=$((now_epoch - start_epoch))
      last_log_age=0
      if [[ -f "$logf" ]]; then
        log_mtime="$(stat -c %Y "$logf" 2>/dev/null || stat -f %m "$logf" 2>/dev/null || echo "$now_epoch")"
        last_log_age=$((now_epoch - log_mtime))
        [[ "$last_log_age" -ge 0 ]] || last_log_age=0
      fi
      printf '%s [PROGRESS] state=%s runner=%s runner_pid=%s elapsed=%ss last_log_age=%ss\n' \
        "$(utc_now)" "${cur_state:-UNKNOWN}" "$runner_status" "${runner_pid:-0}" "$elapsed" "$last_log_age"
      last_hb_epoch="$now_epoch"
    fi

    sleep "$poll"
  done
}

refuse_duplicate_upgrade() {
  local st pid
  st="$(read_state)"
  # Prefer D-Bus-free resolution when attaching monitor.
  pid="$(monitor_resolve_runner_pid "${UPGRADE_RUNNER_PID:-0}" 2>/dev/null || true)"
  if [[ -z "$pid" || "$pid" == "0" ]]; then
    pid="$(resolve_upgrade_runner_pid 2>/dev/null || true)"
  fi
  [[ -n "$pid" ]] || pid="${UPGRADE_RUNNER_PID:-0}"
  UPGRADE_RUNNER_PID="$pid"
  log INFO "UPGRADE_ALREADY_RUNNING=YES"
  log INFO "CURRENT_STATE=${st:-UNKNOWN}"
  log INFO "UPGRADE_RUNNER_PID=${pid:-0}"
  log INFO "ACTION=MONITOR_ONLY"

  if should_attach_progress_monitor; then
    local mon_rc=0
    print_already_running_banner "$st" "$pid" "yes"
    log INFO "UPGRADE_PROCESS_POLICY=DETACHED_UNDER_SYSTEMD"
    log INFO "CLIENT_MONITOR_POLICY=FOREGROUND_READ_ONLY"
    log INFO "MONITOR_MODE=FOREGROUND_READ_ONLY"
    log INFO "MONITOR_CAN_BE_INTERRUPTED=YES"
    log INFO "MONITOR_INTERRUPT_STOPS_UPGRADE=NO"
    log INFO "BACKGROUND_UPGRADE_RUNNING=YES"
    print_background_upgrade_banner "$st" "$pid"
    set +e
    monitor_upgrade_progress "$pid"
    mon_rc=$?
    set +e
    if [[ "$mon_rc" -ne 0 ]]; then
      CLIENT_HANDOFF_RESULT="FAIL"
      CLIENT_EXIT_REASON="BACKGROUND_UPGRADE_FAILED"
      log ERROR "CLIENT_HANDOFF_RESULT=FAIL"
      log ERROR "CLIENT_EXIT_REASON=BACKGROUND_UPGRADE_FAILED"
      log ERROR "MONITOR_RESULT=${MONITOR_RESULT:-TERMINAL_FAILURE}"
      exit "$mon_rc"
    fi
    exit "$EC_OK"
  fi

  print_already_running_banner "$st" "$pid" "no"
  if [[ "${DETACH_AFTER_HANDOFF:-0}" -eq 1 ]]; then
    log INFO "CLIENT_MONITOR_POLICY=DETACHED_BY_REQUEST"
  else
    log INFO "CLIENT_MONITOR_POLICY=DETACHED_NONINTERACTIVE"
  fi
  print_upgrade_monitor_hints
  die "$EC_BUSY" "duplicate execution refused"
}

detect_upgrade_already_running() {
  # Return 0 when a second client must not start/mutate again.
  # CONFIGURING is owned by the current client commit/handoff path — re-entry is
  # refused by handle_existing_state, not here (would block our own start).
  # PREPARING_FOCAL without live process/service evidence is stale, not running.
  local st active main_pid runner_pid dro_pid
  st="$(read_state)"
  if [[ "$st" == "CONFIGURING" ]]; then
    return 1
  fi
  if [[ "$st" == "PREPARING_FOCAL" ]]; then
    if allow_live_systemctl && live_upgrade_evidence_present; then
      return 0
    fi
    return 1
  fi
  if state_is_upgrade_running "$st"; then
    return 0
  fi
  if [[ "$st" == "POST_BOOT_VERIFY" ]]; then
    return 0
  fi
  # Fixture runs without DP_OFFLINE_TEST_HANDOFF must not scan host /proc or systemd.
  if ! allow_live_systemctl; then
    return 1
  fi
  active="$(systemctl_show_prop ActiveState "$UNIT_NAME" || true)"
  case "$active" in
    activating|active) return 0 ;;
  esac
  main_pid="$(systemctl_show_prop MainPID "$UNIT_NAME" || true)"
  if [[ -n "$main_pid" && "$main_pid" != "0" ]] && [[ -d "/proc/${main_pid}" ]]; then
    return 0
  fi
  runner_pid="$(find_runner_pid_via_ps || true)"
  [[ -n "$runner_pid" ]] && return 0
  dro_pid="$(find_dro_pid_via_ps || true)"
  [[ -n "$dro_pid" ]] && return 0
  return 1
}

handoff_evidence_ok() {
  # Minimum PASS: runner pid alive with matching cmdline AND (running state OR runner log).
  local pid st active sub load
  pid="$(resolve_upgrade_runner_pid 2>/dev/null || true)"
  [[ -n "$pid" && "$pid" != "0" ]] || return 1
  [[ -d "/proc/${pid}" ]] || return 1
  runner_cmdline_matches "$pid" || return 1
  UPGRADE_RUNNER_PID="$pid"
  st="$(read_state)"
  if state_is_upgrade_running "$st" || log_has_runner_evidence; then
    active="$(systemctl_show_prop ActiveState "$UNIT_NAME" 2>/dev/null || true)"
    sub="$(systemctl_show_prop SubState "$UNIT_NAME" 2>/dev/null || true)"
    load="$(systemctl_show_prop LoadState "$UNIT_NAME" 2>/dev/null || true)"
    [[ -z "$load" ]] || [[ "$load" == "loaded" ]] || true
    log INFO "UPGRADE_SERVICE_ACTIVE_STATE=${active:-unknown}"
    log INFO "UPGRADE_SERVICE_SUB_STATE=${sub:-unknown}"
    log INFO "UPGRADE_RUNNER_PID=${pid}"
    return 0
  fi
  return 1
}

verify_upgrade_handoff() {
  local waited=0
  local max_wait="${HANDOFF_WAIT_SECS:-15}"
  local poll="${HANDOFF_POLL_SECS:-1}"
  HANDOFF_CONFIRMED=0
  # Do not clear DBUS_DISCONNECT_SEEN — start request may have already recorded it.
  # Bash arithmetic: poll=0 would spin forever; clamp to at least 1 second.
  if [[ -z "$poll" || "$poll" -lt 1 ]]; then
    poll=1
  fi
  if [[ -z "$max_wait" || "$max_wait" -lt 1 ]]; then
    max_wait=1
  fi

  while [[ "$waited" -le "$max_wait" ]]; do
    if unit_looks_failed; then
      log ERROR "UPGRADE_SERVICE_ACTIVE_STATE=failed"
      log ERROR "UPGRADE_HANDOFF=FAILED"
      log ERROR "MANUAL_REVIEW_REQUIRED=YES"
      return 1
    fi
    if handoff_evidence_ok; then
      HANDOFF_CONFIRMED=1
      log INFO "UPGRADE_HANDOFF=PASS"
      log INFO "UPGRADE_PROCESS_POLICY=DETACHED_UNDER_SYSTEMD"
      return 0
    fi
    if [[ "$waited" -ge "$max_wait" ]]; then
      break
    fi
    sleep "$poll"
    waited=$((waited + poll))
  done

  if handoff_evidence_ok; then
    HANDOFF_CONFIRMED=1
    log INFO "UPGRADE_HANDOFF=PASS"
    log INFO "UPGRADE_PROCESS_POLICY=DETACHED_UNDER_SYSTEMD"
    return 0
  fi

  if [[ "$DBUS_DISCONNECT_SEEN" -eq 1 ]]; then
    log ERROR "DBUS_DISCONNECT_PHASE=BEFORE_HANDOFF"
  fi
  log ERROR "UPGRADE_HANDOFF=FAILED"
  log ERROR "MANUAL_REVIEW_REQUIRED=YES"
  return 1
}

classify_dbus_after_attempt() {
  # If D-Bus dropped but upgrade evidence exists, treat as expected control loss.
  if [[ "$DBUS_DISCONNECT_SEEN" -ne 1 ]]; then
    return 0
  fi
  if [[ "$HANDOFF_CONFIRMED" -eq 1 ]] || handoff_evidence_ok; then
    HANDOFF_CONFIRMED=1
    log INFO "DBUS_DISCONNECT_PHASE=AFTER_HANDOFF"
    log INFO "DBUS_DISCONNECT_CLASS=EXPECTED_CONTROL_CONNECTION_LOSS"
    log INFO "UPGRADE_SERVICE_CONTINUES=YES"
    return 0
  fi
  if unit_looks_failed; then
    log ERROR "DBUS_DISCONNECT_PHASE=BEFORE_HANDOFF"
    log ERROR "UPGRADE_SERVICE_ACTIVE_STATE=failed"
    return 1
  fi
  log ERROR "DBUS_DISCONNECT_PHASE=BEFORE_HANDOFF"
  log ERROR "UPGRADE_HANDOFF=FAILED"
  log ERROR "MANUAL_REVIEW_REQUIRED=YES"
  return 1
}

start_upgrade_service_detached() {
  # Non-blocking enqueue + short evidence wait. Never block on oneshot completion.
  local start_out="" start_rc=0 verify_rc=0 cls_rc=0 mon_rc=0
  HANDOFF_CONFIRMED=0
  UPGRADE_RUNNER_PID=0
  DBUS_DISCONNECT_SEEN=0

  if detect_upgrade_already_running; then
    refuse_duplicate_upgrade
  fi

  log INFO "SYSTEMD_START_MODE=NON_BLOCKING"

  set +e
  run_systemctl daemon-reload
  run_systemctl reset-failed "$UNIT_NAME"
  run_systemctl enable "$POSTBOOT_UNIT_NAME"
  run_systemctl start --no-block "$UNIT_NAME"
  start_rc="$LAST_SYSTEMCTL_RC"
  start_out="$LAST_SYSTEMCTL_OUTPUT"
  set +e

  if [[ "$start_rc" -eq 0 ]]; then
    log INFO "UPGRADE_SERVICE_START_REQUEST=PASS"
  else
    log WARN "UPGRADE_SERVICE_START_REQUEST=UNCERTAIN rc=${start_rc}"
    if is_dbus_disconnect_text "${start_out}"; then
      DBUS_DISCONNECT_SEEN=1
      log WARN "systemctl start reported D-Bus disconnect; verifying runner evidence"
    fi
  fi

  set +e
  verify_upgrade_handoff
  verify_rc=$?
  set +e

  if [[ "$verify_rc" -ne 0 ]]; then
    set +e
    classify_dbus_after_attempt
    cls_rc=$?
    set +e
    if [[ "$cls_rc" -eq 0 && "$HANDOFF_CONFIRMED" -eq 1 ]]; then
      CRITICAL_HOLD_RESTORE_ON_EXIT=0
      set +e
      maybe_attach_progress_monitor "${UPGRADE_RUNNER_PID:-0}"
      mon_rc=$?
      set +e
      return "$mon_rc"
    fi
    die "$EC_HANDOFF" "upgrade service handoff failed"
  fi

  if [[ "$DBUS_DISCONNECT_SEEN" -eq 1 ]]; then
    log INFO "DBUS_DISCONNECT_PHASE=AFTER_HANDOFF"
    log INFO "DBUS_DISCONNECT_CLASS=EXPECTED_CONTROL_CONNECTION_LOSS"
    log INFO "UPGRADE_SERVICE_CONTINUES=YES"
  fi

  CRITICAL_HOLD_RESTORE_ON_EXIT=0
  set +e
  maybe_attach_progress_monitor "${UPGRADE_RUNNER_PID:-0}"
  mon_rc=$?
  set +e
  return "$mon_rc"
}

commit_and_start() {
  local work="$1"
  local stamp rc=0 handoff_rc=0
  stamp="$(date -u '+%Y%m%dT%H%M%SZ')"
  write_state CONFIGURING
  mkdir -p "$(hostpath "$STATE_ROOT")" "$(hostpath "$BACKUP_ROOT")"
  ensure_log_dir

  # Order: backup → hold snapshot → unhold → unused LXD removal → APT metadata → runner.
  backup_persistent_config "$stamp"

  # Re-classify from live selection at commit time (still before mutation).
  classify_held_packages
  snapshot_critical_holds_before
  unhold_critical_os_packages

  # Post-confirmation: remove unused deb LXD before DistUpgrade can select
  # Jammy's transitional package (api.snapcraft.io). Fail-closed on risk.
  if [[ -z "${LXD_PREFLIGHT_CLASS:-}" ]]; then
    collect_and_classify_lxd_inventory
  fi
  remove_unused_lxd_before_dro

  if [[ -n "$TEST_ROOT" && "${DP_OFFLINE_FAKE_FAIL_AFTER_UNHOLD:-}" == "1" ]]; then
    log ERROR "TEST: injected failure after unhold (before APT metadata / release upgrade)"
    restore_critical_os_holds_if_safe "injected_pre_upgrade_failure" || true
    die "$EC_INTERNAL" "FAIL_INJECTED_AFTER_UNHOLD"
  fi

  # APT metadata + runner install. On any failure before release upgrade starts,
  # restore APT sources + critical holds (legacy keyring retained by policy).
  set +e
  (
    set -euo pipefail
    install_keyring "$work"
    disable_third_party_sources "$stamp"
    apply_local_sources
    apply_distupgrade_mirror_override
    install_effective_source_gate
    # Validate DistUpgrade-compatible TARGET sources (not merely apt-get update).
    if ! validate_distupgrade_sources_file "$(hostpath "$DISTUPGRADE_SOURCES_PATH")" "$PIN_TARGET_SUITES"; then
      err="$(cat "$(hostpath "${STATE_ROOT}/last-distupgrade-source-error.txt")" 2>/dev/null || true)"
      err="${err:-FAIL_DISTUPGRADE_SOURCE_INVALID}"
      if [[ "$err" == "FAIL_DISTUPGRADE_SOURCE_TEXT_DECODE" ]]; then
        die "$EC_DISTUPGRADE_SOURCE_DECODE" "$err"
      fi
      if [[ "$err" == "FAIL_SIGNED_BY_PRESENT_IN_DISTUPGRADE_SOURCE" ]]; then
        die "$EC_DISTUPGRADE_SOURCE" "$err"
      fi
      if [[ "$err" == "FAIL_DISTUPGRADE_SOURCE_COUNT_MISMATCH" ]]; then
        die "$EC_DISTUPGRADE_SOURCE" "$err"
      fi
      die "$EC_DISTUPGRADE_SOURCE" "$err"
    fi
    if [[ -z "$TEST_ROOT" ]] || [[ "${DP_OFFLINE_FAKE_MIRROR_TRUST:-}" != "1" ]]; then
      if ! validate_target_pocket_components_from_mirror; then
        die "$EC_TARGET_POCKET" "FAIL_TARGET_POCKET_COMPONENT_EMPTY"
      fi
    fi
    log INFO "TARGET_POCKET_REGISTRATION_PREFLIGHT=PASS"
    apply_meta_release "$work"
    change_login_shells "$stamp"
    write_pins_env "$stamp"
    install -m 0644 "$work/client-manifest.json" "$(hostpath ${STATE_ROOT}/client-manifest.json)"
    install_runner_and_units "$work"
  )
  rc=$?
  set -e
  if [[ "$rc" -ne 0 ]]; then
    restore_apt_sources_from_backup "$stamp" "pre_upgrade_failure" || true
    restore_critical_os_holds_if_safe "pre_upgrade_failure" || true
    case "$rc" in
      "$EC_DISTUPGRADE_SOURCE"|"$EC_DISTUPGRADE_SOURCE_DECODE"|"$EC_TARGET_POCKET"|"$EC_TRUST"|"$EC_META"|"$EC_META_ASCII"|"$EC_LXD")
        exit "$rc"
        ;;
    esac
    die "$EC_INTERNAL" "commit failed after critical OS unhold (rc=${rc})"
  fi

  if [[ -n "$TEST_ROOT" && "${DP_OFFLINE_TEST_HANDOFF:-}" != "1" ]]; then
    log INFO "TEST_ROOT set — not starting systemd units"
    CRITICAL_HOLD_RESTORE_ON_EXIT=0
    CLIENT_HANDOFF_RESULT="PASS"
    return 0
  fi

  set +e
  start_upgrade_service_detached
  handoff_rc=$?
  set +e
  if [[ "$handoff_rc" -ne 0 ]]; then
    CLIENT_HANDOFF_RESULT="FAIL"
    CLIENT_EXIT_REASON="BACKGROUND_UPGRADE_FAILED"
    log ERROR "CLIENT_HANDOFF_RESULT=FAIL"
    log ERROR "CLIENT_EXIT_REASON=BACKGROUND_UPGRADE_FAILED"
    log ERROR "MONITOR_RESULT=${MONITOR_RESULT:-TERMINAL_FAILURE}"
    return "$handoff_rc"
  fi
  CLIENT_HANDOFF_RESULT="PASS"
  log INFO "CLIENT_HANDOFF_RESULT=PASS"
  log INFO "client handoff complete; upgrade continues under ${UNIT_NAME}"
  return 0
}

# Previous-hop (Xenial→Focal) terminal success state may remain on disk when the
# Focal→Jammy client starts. That is a normal multi-hop handoff, not corruption.
PREVIOUS_HOP_TERMINAL_STATE="COMPLETED_FOCAL"
HOP_HANDOFF_TARGET_STATE="PREFLIGHT"
HOP_HANDOFF_BACKUP_PATH=""
PREVIOUS_HOP_PIN_NAME="bionic-to-focal"

write_state_atomic() {
  # Atomic state transition: temp → fsync → rename. Preserves mode/owner when possible.
  local st="$1"
  local dest tmp dir
  dest="$(hostpath "$STATE_FILE")"
  dir="$(dirname "$dest")"
  mkdir -p "$dir"
  tmp="${dest}.tmp.$$.$RANDOM"
  # Reject partial writes: write full line then rename.
  printf '%s\n' "$st" >"$tmp" || {
    rm -f "$tmp"
    return 1
  }
  if [[ -f "$dest" ]]; then
    chmod --reference="$dest" "$tmp" 2>/dev/null || chmod 0644 "$tmp" 2>/dev/null || true
    chown --reference="$dest" "$tmp" 2>/dev/null || true
  else
    chmod 0644 "$tmp" 2>/dev/null || true
  fi
  if command -v sync >/dev/null 2>&1; then
    sync "$tmp" 2>/dev/null || true
  fi
  mv -f "$tmp" "$dest" || {
    rm -f "$tmp"
    return 1
  }
  if command -v sync >/dev/null 2>&1; then
    sync "$dir" 2>/dev/null || sync 2>/dev/null || true
  fi
  return 0
}

is_focal_to_jammy_client() {
  # This template is always focal→jammy; pin identity must still match.
  [[ "${PIN_HOP:-}" == "focal-to-jammy" ]] \
    && [[ "${PIN_SOURCE_VERSION:-}" == "20.04" ]] \
    && [[ "${PIN_SOURCE_CODENAME:-}" == "focal" ]] \
    && [[ "${PIN_TARGET_VERSION:-}" == "22.04" ]] \
    && [[ "${PIN_TARGET_CODENAME:-}" == "jammy" ]]
}

read_kv_file_field() {
  local file="$1" field="$2"
  [[ -f "$file" ]] || return 1
  sed -n "s/^${field}=//p" "$file" 2>/dev/null | head -1 | tr -d "'\"" | tr -d '\r'
}

read_live_pins_hop() {
  local f
  f="$(hostpath "${PIN_ENV_FILE:-${STATE_ROOT}/pins.env}")"
  read_kv_file_field "$f" PIN_HOP || true
}

read_live_manifest_hop() {
  local f hop
  f="$(hostpath ${STATE_ROOT}/client-manifest.json)"
  [[ -f "$f" ]] || return 0
  hop="$(sed -n 's/.*"hop"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' "$f" 2>/dev/null | head -1)"
  if [[ -z "$hop" ]] && command -v python3 >/dev/null 2>&1; then
    hop="$(python3 -c 'import json,sys; d=json.load(open(sys.argv[1],encoding="utf-8")); print(d.get("hop") or "")' "$f" 2>/dev/null || true)"
  fi
  printf '%s' "$hop"
}

current_hop_env_path() {
  hostpath "${CURRENT_HOP_ENV_FILE:-${STATE_ROOT}/current-hop.env}"
}

read_current_hop_field() {
  read_kv_file_field "$(current_hop_env_path)" "$1" || true
}

load_current_hop_identity_vars() {
  local p
  p="$(current_hop_env_path)"
  [[ -f "$p" ]] || return 1
  CURRENT_RUN_ID="$(read_kv_file_field "$p" CURRENT_RUN_ID || true)"
  CURRENT_RUN_EPOCH="$(read_kv_file_field "$p" CURRENT_RUN_EPOCH || true)"
  CURRENT_HOP_INITIALIZED_AT="$(read_kv_file_field "$p" INITIALIZED_AT || true)"
  return 0
}

transition_marker_true() {
  local dir f
  dir="$(hostpath ${HOLDS_DIR})"
  f="${dir}/release_upgrade_package_transition_started"
  if [[ -f "$f" ]] && grep -qx 'true' "$f" 2>/dev/null; then
    return 0
  fi
  f="$(hostpath ${STATE_ROOT}/release_upgrade_package_transition_started)"
  if [[ -f "$f" ]] && grep -qx 'true' "$f" 2>/dev/null; then
    return 0
  fi
  return 1
}

any_release_upgrade_marker_true() {
  local dir name
  dir="$(hostpath ${HOLDS_DIR})"
  for name in release_upgrade_package_transition_started \
    release_upgrade_invocation_started \
    release_upgrade_process_spawned \
    release_upgrade_started \
    release_upgrade_completed; do
    if [[ -f "${dir}/${name}" ]] && grep -qx 'true' "${dir}/${name}" 2>/dev/null; then
      return 0
    fi
  done
  return 1
}

classify_mutation_evidence_ownership() {
  # Sets MUTATION_EVIDENCE_CLASS to one of:
  #   CURRENT_HOP_MUTATION | PREVIOUS_HOP_MUTATION | NO_MUTATION | AMBIGUOUS_MUTATION_EVIDENCE
  local st pins_hop manifest_hop marker_path marker_hop marker_run current_hop
  local has_transition=0 has_any_marker=0
  MUTATION_EVIDENCE_CLASS="NO_MUTATION"
  PREVIOUS_HOP_RUNTIME_OWNER=""

  st="$(read_state)"
  pins_hop="$(read_live_pins_hop)"
  manifest_hop="$(read_live_manifest_hop)"
  current_hop="$(read_current_hop_field CURRENT_HOP)"
  marker_path="$(hostpath ${HOLDS_DIR})/release_upgrade_package_transition_started"
  marker_hop="$(marker_meta_field "$marker_path" HOP || true)"
  marker_run="$(marker_meta_field "$marker_path" RUN_ID || true)"

  if transition_marker_true; then
    has_transition=1
  fi
  if any_release_upgrade_marker_true; then
    has_any_marker=1
  fi

  # Explicit test fixtures force current-hop mutation.
  if [[ -n "$TEST_ROOT" ]]; then
    if [[ -f "$(hostpath ${STATE_ROOT}/force-upgrade-transaction-evidence)" ]] \
      || [[ -f "$(hostpath ${STATE_ROOT}/force-partial-transition)" ]]; then
      MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
      return 0
    fi
  fi

  # Real package contamination / dist-upgrade logs for THIS hop mid-flight.
  case "$st" in
    CONFIGURING|PREPARING_FOCAL|UPGRADING_FOCAL_TO_JAMMY|REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|FAILED_AFTER_PACKAGE_TRANSITION|FAILED_POST_TRANSACTION)
      if package_transition_evidence_present 2>/dev/null; then
        MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
        return 0
      fi
      ;;
  esac

  if [[ "$has_transition" -eq 0 && "$has_any_marker" -eq 0 ]]; then
    MUTATION_EVIDENCE_CLASS="NO_MUTATION"
    return 0
  fi

  # Explicit marker owner metadata wins.
  if [[ -n "$marker_hop" ]]; then
    if [[ "$marker_hop" == "focal-to-jammy" ]]; then
      if [[ -n "${CURRENT_RUN_ID:-}" && -n "$marker_run" && "$marker_run" != "$CURRENT_RUN_ID" ]]; then
        MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
        return 0
      fi
      MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
      return 0
    fi
    if [[ "$marker_hop" == "$PREVIOUS_HOP_PIN_NAME" ]]; then
      MUTATION_EVIDENCE_CLASS="PREVIOUS_HOP_MUTATION"
      PREVIOUS_HOP_RUNTIME_OWNER="$PREVIOUS_HOP_PIN_NAME"
      return 0
    fi
    MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
    return 0
  fi

  # Legacy marker without companion metadata — classify via pins/manifest/state/OS.
  if [[ "$st" == "$PREVIOUS_HOP_TERMINAL_STATE" ]]; then
    local ver code
    ver="$(read_os_field VERSION_ID)"
    code="$(read_os_field VERSION_CODENAME)"
    [[ -z "$code" ]] && code="$(read_os_field UBUNTU_CODENAME)"
    if [[ -n "$pins_hop" && -n "$manifest_hop" && "$pins_hop" != "$manifest_hop" ]]; then
      MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
      return 0
    fi
    if [[ "$pins_hop" == "$PREVIOUS_HOP_PIN_NAME" || "$manifest_hop" == "$PREVIOUS_HOP_PIN_NAME" ]]; then
      if [[ "$ver" == "20.04" && "$code" == "focal" ]]; then
        MUTATION_EVIDENCE_CLASS="PREVIOUS_HOP_MUTATION"
        PREVIOUS_HOP_RUNTIME_OWNER="$PREVIOUS_HOP_PIN_NAME"
        return 0
      fi
    fi
    if [[ "$pins_hop" == "focal-to-jammy" || "$manifest_hop" == "focal-to-jammy" || "$current_hop" == "focal-to-jammy" ]]; then
      MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
      return 0
    fi
    # No pins/manifest ownership → fail closed (do not blind-allow).
    MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
    return 0
  fi

  # Current-hop mid-states: unmarked true markers with b2f identity → current.
  case "$st" in
    CONFIGURING|PREPARING_FOCAL|UPGRADING_FOCAL_TO_JAMMY|REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|FAILED_AFTER_PACKAGE_TRANSITION|FAILED_POST_TRANSACTION)
      if [[ "$current_hop" == "focal-to-jammy" || "$pins_hop" == "focal-to-jammy" ]]; then
        MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
        return 0
      fi
      MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
      return 0
      ;;
    PREFLIGHT|READY_FOR_CONFIRMATION|READY_FOR_RESUME)
      if [[ "$pins_hop" == "$PREVIOUS_HOP_PIN_NAME" || "$manifest_hop" == "$PREVIOUS_HOP_PIN_NAME" ]]; then
        MUTATION_EVIDENCE_CLASS="PREVIOUS_HOP_MUTATION"
        PREVIOUS_HOP_RUNTIME_OWNER="$PREVIOUS_HOP_PIN_NAME"
        return 0
      fi
      if [[ "$current_hop" == "focal-to-jammy" && "$has_transition" -eq 1 ]]; then
        MUTATION_EVIDENCE_CLASS="CURRENT_HOP_MUTATION"
        return 0
      fi
      MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
      return 0
      ;;
  esac

  MUTATION_EVIDENCE_CLASS="AMBIGUOUS_MUTATION_EVIDENCE"
  return 0
}

current_hop_mutation_evidence_present() {
  # 0 = current Focal→Jammy mutation evidence
  # 1 = no current-hop mutation (includes previous-hop / none)
  # 2 = ambiguous ownership → callers must fail closed
  classify_mutation_evidence_ownership || true
  case "${MUTATION_EVIDENCE_CLASS}" in
    CURRENT_HOP_MUTATION) return 0 ;;
    AMBIGUOUS_MUTATION_EVIDENCE) return 2 ;;
    *) return 1 ;;
  esac
}

reset_in_memory_upgrade_flags() {
  RELEASE_UPGRADE_STARTED="false"
  RELEASE_UPGRADE_INVOCATION_STARTED="false"
  RELEASE_UPGRADE_PROCESS_SPAWNED="false"
  RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED="false"
  RELEASE_UPGRADE_COMPLETED="false"
  PACKAGE_TRANSITION_DETECTION_SOURCE=""
  PACKAGE_TRANSITION_DETECTION_EVIDENCE=""
  PACKAGE_TRANSITION_DETECTED_AT=""
  PACKAGE_TRANSITION_DETECTION_LATENCY_SECONDS=""
  LIVE_SERVICE_ACTIVE="NO"
  LIVE_RUNNER_PRESENT="NO"
  LIVE_DRO_PRESENT="NO"
  LIVE_MAIN_PID=""
  UPGRADE_RUNNER_PID=0
  log INFO "IN_MEMORY_UPGRADE_FLAGS_RESET=YES"
}

_exact_kv_once() {
  # Exact key=value line, exactly once. Rejects missing/duplicate/whitespace drift.
  local file="$1" key="$2" expected="$3"
  local count actual
  [[ -f "$file" ]] || return 1
  count="$(grep -c "^${key}=" "$file" 2>/dev/null || true)"
  [[ "$count" == "1" ]] || return 1
  actual="$(sed -n "s/^${key}=//p" "$file" 2>/dev/null | head -1 | tr -d '\r')"
  [[ "$actual" == "$expected" ]] || return 1
  grep -qx "${key}=${expected}" "$file" || return 1
  return 0
}

verify_persisted_current_hop_contract() {
  # Post-write contract: all 8 identity fields must match pins exactly.
  local dest="$1"
  [[ -f "$dest" ]] || return 1
  _exact_kv_once "$dest" CURRENT_HOP "${PIN_HOP}" || return 1
  _exact_kv_once "$dest" CURRENT_SOURCE_VERSION "${PIN_SOURCE_VERSION}" || return 1
  _exact_kv_once "$dest" CURRENT_SOURCE_CODENAME "${PIN_SOURCE_CODENAME}" || return 1
  _exact_kv_once "$dest" CURRENT_TARGET_VERSION "${PIN_TARGET_VERSION}" || return 1
  _exact_kv_once "$dest" CURRENT_TARGET_CODENAME "${PIN_TARGET_CODENAME}" || return 1
  _exact_kv_once "$dest" HANDOFF_SOURCE_STATE "${PREVIOUS_HOP_TERMINAL_STATE}" || return 1
  _exact_kv_once "$dest" PACKAGE_TRANSITION_STARTED "false" || return 1
  _exact_kv_once "$dest" CLIENT_ARTIFACT_SHA256 "${PIN_MANIFEST_SHA256:-}" || return 1
  return 0
}

initialize_current_hop_identity() {
  # Persist this hop's identity into current-hop.env (atomic replace).
  # Always rewrite — a previous-hop current-hop.env must not remain live.
  # Variable roles (never reuse one name across roles):
  #   PREVIOUS_RUNTIME_HOP  — value read from existing current-hop.env (if any)
  #   PINNED_CURRENT_HOP    — this client pin (PIN_HOP)
  #   PERSISTED_CURRENT_HOP — value re-read from disk after write
  local dest tmp dir run_id run_epoch now
  local PREVIOUS_RUNTIME_HOP PINNED_CURRENT_HOP PERSISTED_CURRENT_HOP
  PINNED_CURRENT_HOP="${PIN_HOP}"
  dest="$(current_hop_env_path)"
  dir="$(dirname "$dest")"
  mkdir -p "$dir"
  PREVIOUS_RUNTIME_HOP="$(read_current_hop_field CURRENT_HOP 2>/dev/null || true)"
  if [[ -n "$PREVIOUS_RUNTIME_HOP" && "$PREVIOUS_RUNTIME_HOP" != "$PINNED_CURRENT_HOP" ]]; then
    log INFO "PREVIOUS_RUNTIME_HOP=${PREVIOUS_RUNTIME_HOP}"
    log INFO "PINNED_CURRENT_HOP=${PINNED_CURRENT_HOP}"
    log INFO "CURRENT_HOP_IDENTITY_REWRITE=YES reason=PREVIOUS_HOP_ENV_PRESENT"
    if [[ -n "${HOP_HANDOFF_BACKUP_PATH:-}" && -d "${HOP_HANDOFF_BACKUP_PATH}" && -f "$dest" ]]; then
      mkdir -p "${HOP_HANDOFF_BACKUP_PATH}/previous-runtime"
      cp -a "$dest" "${HOP_HANDOFF_BACKUP_PATH}/previous-runtime/current-hop.env" 2>/dev/null || true
    fi
  fi
  now="$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
  run_epoch="$(date -u '+%s' 2>/dev/null || date '+%s')"
  run_id="$(date -u '+%Y%m%dT%H%M%SZ')-$$-${RANDOM}"
  CURRENT_RUN_ID="$run_id"
  CURRENT_RUN_EPOCH="$run_epoch"
  CURRENT_HOP_INITIALIZED_AT="$now"
  tmp="${dest}.tmp.$$.$RANDOM"
  {
    printf 'CURRENT_HOP=%s\n' "${PINNED_CURRENT_HOP}"
    printf 'CURRENT_SOURCE_VERSION=%s\n' "${PIN_SOURCE_VERSION}"
    printf 'CURRENT_SOURCE_CODENAME=%s\n' "${PIN_SOURCE_CODENAME}"
    printf 'CURRENT_TARGET_VERSION=%s\n' "${PIN_TARGET_VERSION}"
    printf 'CURRENT_TARGET_CODENAME=%s\n' "${PIN_TARGET_CODENAME}"
    printf 'HANDOFF_SOURCE_STATE=%s\n' "${PREVIOUS_HOP_TERMINAL_STATE}"
    printf 'CURRENT_RUN_ID=%s\n' "$run_id"
    printf 'CURRENT_RUN_EPOCH=%s\n' "$run_epoch"
    printf 'INITIALIZED_AT=%s\n' "$now"
    printf 'PACKAGE_TRANSITION_STARTED=false\n'
    printf 'CLIENT_ARTIFACT_SHA256=%s\n' "${PIN_MANIFEST_SHA256:-}"
  } >"$tmp" || {
    log ERROR "CURRENT_HOP_IDENTITY_INITIALIZED=NO"
    log ERROR "CURRENT_HOP_IDENTITY_WRITE=FAIL"
    rm -f "$tmp" 2>/dev/null || true
    return 1
  }
  chmod 0600 "$tmp" 2>/dev/null || true
  if command -v sync >/dev/null 2>&1; then
    sync "$tmp" 2>/dev/null || true
  fi
  if ! mv -f "$tmp" "$dest"; then
    log ERROR "CURRENT_HOP_IDENTITY_INITIALIZED=NO"
    log ERROR "CURRENT_HOP_IDENTITY_REPLACE=FAIL"
    rm -f "$tmp" 2>/dev/null || true
    return 1
  fi
  if command -v sync >/dev/null 2>&1; then
    sync "$dir" 2>/dev/null || sync 2>/dev/null || true
  fi
  # Re-read persisted file — never claim success from pins alone.
  # All 8 contract fields must exact-match; any failure blocks INITIALIZED/ACCEPTED.
  PERSISTED_CURRENT_HOP="$(read_current_hop_field CURRENT_HOP)"
  if ! verify_persisted_current_hop_contract "$dest"; then
    log ERROR "CURRENT_HOP_IDENTITY_INITIALIZED=NO"
    log ERROR "PERSISTED_CURRENT_HOP=${PERSISTED_CURRENT_HOP}"
    log ERROR "PINNED_CURRENT_HOP=${PINNED_CURRENT_HOP}"
    log ERROR "CURRENT_HOP_IDENTITY_VERIFY=FAIL"
    return 1
  fi
  log INFO "CURRENT_HOP_IDENTITY_INITIALIZED=YES"
  log INFO "PINNED_CURRENT_HOP=${PINNED_CURRENT_HOP}"
  log INFO "PERSISTED_CURRENT_HOP=${PERSISTED_CURRENT_HOP}"
  log INFO "PERSISTED_CURRENT_SOURCE_VERSION=$(read_current_hop_field CURRENT_SOURCE_VERSION)"
  log INFO "PERSISTED_CURRENT_SOURCE_CODENAME=$(read_current_hop_field CURRENT_SOURCE_CODENAME)"
  log INFO "PERSISTED_CURRENT_TARGET_VERSION=$(read_current_hop_field CURRENT_TARGET_VERSION)"
  log INFO "PERSISTED_CURRENT_TARGET_CODENAME=$(read_current_hop_field CURRENT_TARGET_CODENAME)"
  log INFO "PERSISTED_HANDOFF_SOURCE_STATE=$(read_current_hop_field HANDOFF_SOURCE_STATE)"
  log INFO "PERSISTED_PACKAGE_TRANSITION_STARTED=$(read_current_hop_field PACKAGE_TRANSITION_STARTED)"
  log INFO "PERSISTED_CLIENT_ARTIFACT_SHA256=$(read_current_hop_field CLIENT_ARTIFACT_SHA256)"
  log INFO "CURRENT_HOP=${PERSISTED_CURRENT_HOP}"
  log INFO "CURRENT_RUN_ID=${run_id}"
  return 0
}

verify_pins_match_current_hop_identity() {
  local hop src tgt
  [[ -f "$(current_hop_env_path)" ]] || return 0
  hop="$(read_current_hop_field CURRENT_HOP)"
  src="$(read_current_hop_field CURRENT_SOURCE_CODENAME)"
  tgt="$(read_current_hop_field CURRENT_TARGET_CODENAME)"
  if [[ -n "$hop" && "$hop" != "$PIN_HOP" ]]; then
    die "$EC_STATE" "FAIL_CURRENT_HOP_IDENTITY_MISMATCH (current-hop.env=${hop} pins=${PIN_HOP})"
  fi
  if [[ -n "$src" && "$src" != "$PIN_SOURCE_CODENAME" ]]; then
    die "$EC_STATE" "FAIL_CURRENT_HOP_IDENTITY_MISMATCH (source)"
  fi
  if [[ -n "$tgt" && "$tgt" != "$PIN_TARGET_CODENAME" ]]; then
    die "$EC_STATE" "FAIL_CURRENT_HOP_IDENTITY_MISMATCH (target)"
  fi
  return 0
}

# --- effective source-gate bundle lifecycle (atomic install/archive/retire/repair) ---
# Bundle members:
#   1) executable  ${STATE_ROOT}/bin/distupgrade-effective-source-gate
#   2) env         ${STATE_ROOT}/bin/distupgrade-effective-source-gate.env
#   3) wrapper     ${STATE_ROOT}/bin/distupgrade-effective-source-gate.wrap
#   4) APT hook    /etc/apt/apt.conf.d/98stellar-distupgrade-source-gate
#   5) markers     effective-source-gate.{armed,passed} + evidence/
SOURCE_GATE_CLASS=""
SOURCE_GATE_HOOK_BASENAME="98stellar-distupgrade-source-gate"
SOURCE_GATE_WRAP_BASENAME="distupgrade-effective-source-gate.wrap"

_source_gate_standard_wrap_path() {
  printf '%s\n' "${STATE_ROOT}/bin/${SOURCE_GATE_WRAP_BASENAME}"
}

_source_gate_read_kv() {
  local file="$1" key="$2"
  [[ -f "$file" ]] || return 1
  # shellcheck disable=SC2002
  sed -n "s/^${key}=//p" "$file" 2>/dev/null | head -1 | tr -d '\r'
}

_source_gate_hook_command_target() {
  # Extract quoted Pre-Invoke command from Stellar source-gate apt.conf stanza.
  local hook="$1"
  local line
  [[ -f "$hook" ]] || return 1
  line="$(grep -E 'APT::Update::Pre-Invoke' "$hook" 2>/dev/null | head -1 || true)"
  [[ -n "$line" ]] || return 1
  if [[ "$line" =~ \"([^\"]+)\" ]]; then
    printf '%s\n' "${BASH_REMATCH[1]}"
    return 0
  fi
  if [[ "$line" =~ \'([^\']+)\' ]]; then
    printf '%s\n' "${BASH_REMATCH[1]}"
    return 0
  fi
  return 1
}

_source_gate_hook_is_stellar_only() {
  # True when the apt.conf file contains only the Stellar Pre-Invoke stanza (+ comments/blank).
  local hook="$1"
  local line cleaned=0 stellar=0
  [[ -f "$hook" ]] || return 1
  while IFS= read -r line || [[ -n "$line" ]]; do
    [[ "$line" =~ ^[[:space:]]*$ ]] && continue
    [[ "$line" =~ ^[[:space:]]*// ]] && continue
    [[ "$line" =~ ^[[:space:]]*# ]] && continue
    cleaned=$((cleaned + 1))
    if [[ "$line" =~ APT::Update::Pre-Invoke ]] \
      && [[ "$line" == *"${SOURCE_GATE_WRAP_BASENAME}"* ]]; then
      stellar=$((stellar + 1))
      continue
    fi
    return 1
  done <"$hook"
  [[ "$cleaned" -ge 1 && "$stellar" -eq 1 ]]
}

_source_gate_count_wrap_references() {
  # Count apt.conf.d files that reference the standard Stellar wrap path.
  local confd="$1"
  local wrap_logical="$2"
  local f n=0
  [[ -d "$confd" ]] || { printf '0\n'; return 0; }
  for f in "$confd"/*; do
    [[ -f "$f" ]] || continue
    if grep -Fq "$wrap_logical" "$f" 2>/dev/null \
      || grep -Fq "${SOURCE_GATE_WRAP_BASENAME}" "$f" 2>/dev/null; then
      n=$((n + 1))
    fi
  done
  printf '%s\n' "$n"
}

_source_gate_dump_apt_config() {
  local out="$1"
  if command -v apt-config >/dev/null 2>&1 && [[ -z "${TEST_ROOT:-}" ]]; then
    apt-config dump 2>/dev/null >"$out" || true
  else
    # Fixture / offline: synthesize from apt.conf.d files.
    local confd f
    confd="$(hostpath /etc/apt/apt.conf.d)"
    : >"$out"
    if [[ -d "$confd" ]]; then
      for f in "$confd"/*; do
        [[ -f "$f" ]] || continue
        {
          printf '// file: %s\n' "$f"
          cat "$f"
          printf '\n'
        } >>"$out"
      done
    fi
  fi
}

_source_gate_dangling_hook_in_dump() {
  local dump="$1"
  local wrap_logical
  wrap_logical="$(_source_gate_standard_wrap_path)"
  [[ -f "$dump" ]] || return 1
  grep -Fq "$wrap_logical" "$dump" 2>/dev/null
}

find_latest_handoff_archive_any() {
  # Newest handoff-state-* archive (complete or incomplete).
  local root newest f
  root="$(hostpath "$BACKUP_ROOT")"
  [[ -d "$root" ]] || return 1
  newest=""
  for f in "$root"/handoff-state-*; do
    [[ -d "$f" ]] || continue
    newest="$f"
  done
  [[ -n "$newest" ]] || return 1
  printf '%s\n' "$newest"
}

_source_gate_archive_has_previous_wrap() {
  local dest="$1"
  local wrap="${SOURCE_GATE_WRAP_BASENAME}"
  [[ -f "${dest}/previous-runtime/bin/${wrap}" ]] \
    || [[ -f "${dest}/previous-source-gate/bin/${wrap}" ]]
}

_source_gate_fsync_path() {
  local p="$1"
  if command -v sync >/dev/null 2>&1; then
    sync "$p" 2>/dev/null || sync 2>/dev/null || true
  fi
}

classify_effective_source_gate_bundle() {
  # Classify live source-gate bundle. Sets SOURCE_GATE_CLASS.
  local apt_path bin_path wrap_path env_path confd
  local hook_present=0 wrap_present=0 bin_present=0 env_present=0
  local env_hop="" current_hop="" hook_target="" wrap_logical
  local refs=0 stellar_only=0 marker_hop=""
  local armed passed

  SOURCE_GATE_CLASS="NO_STELLAR_GATE"
  apt_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_APT:-/etc/apt/apt.conf.d/${SOURCE_GATE_HOOK_BASENAME}}")"
  bin_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_BIN:-${STATE_ROOT}/bin/distupgrade-effective-source-gate}")"
  wrap_path="${bin_path}.wrap"
  env_path="${bin_path}.env"
  wrap_logical="$(_source_gate_standard_wrap_path)"
  confd="$(hostpath /etc/apt/apt.conf.d)"
  armed="$(hostpath "${EFFECTIVE_SOURCE_GATE_ARMED_MARKER:-${STATE_ROOT}/effective-source-gate.armed}")"
  passed="$(hostpath "${EFFECTIVE_SOURCE_GATE_PASSED_MARKER:-${STATE_ROOT}/effective-source-gate.passed}")"
  current_hop="$(read_current_hop_field CURRENT_HOP 2>/dev/null || true)"
  [[ -z "$current_hop" ]] && current_hop="${PIN_HOP:-}"

  [[ -f "$apt_path" ]] && hook_present=1
  [[ -e "$wrap_path" ]] && wrap_present=1
  [[ -e "$bin_path" ]] && bin_present=1
  [[ -f "$env_path" ]] && env_present=1
  if [[ -f "$env_path" ]]; then
    env_hop="$(_source_gate_read_kv "$env_path" STELLAR_EXPECTED_HOP || true)"
    [[ -z "$env_hop" ]] && env_hop="$(_source_gate_read_kv "$env_path" EXPECTED_HOP || true)"
  fi
  if [[ -f "$armed" ]]; then
    marker_hop="$(_source_gate_read_kv "$armed" EXPECTED_HOP || true)"
    [[ -z "$marker_hop" ]] && marker_hop="$(_source_gate_read_kv "$armed" STELLAR_EXPECTED_HOP || true)"
  fi
  if [[ "$hook_present" -eq 1 ]]; then
    hook_target="$(_source_gate_hook_command_target "$apt_path" || true)"
    if _source_gate_hook_is_stellar_only "$apt_path"; then
      stellar_only=1
    fi
  fi
  refs="$(_source_gate_count_wrap_references "$confd" "$wrap_logical")"

  # Ambiguity: custom mixed content, unexpected hook target, or duplicate definitions.
  if [[ "$hook_present" -eq 1 && "$stellar_only" -eq 0 ]]; then
    SOURCE_GATE_CLASS="AMBIGUOUS_GATE_CONFIGURATION"
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    log INFO "SOURCE_GATE_REJECT_REASON=HOOK_FILE_HAS_NON_STELLAR_COMMANDS"
    return 0
  fi
  if [[ "$refs" -gt 1 ]]; then
    SOURCE_GATE_CLASS="AMBIGUOUS_GATE_CONFIGURATION"
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    log INFO "SOURCE_GATE_REJECT_REASON=DUPLICATE_HOOK_DEFINITIONS count=${refs}"
    return 0
  fi
  if [[ "$hook_present" -eq 1 && -n "$hook_target" && "$hook_target" != "$wrap_logical" \
    && "$hook_target" != "$(hostpath "$wrap_logical")" ]]; then
    # Allow hostpath-prefixed logical equality under TEST_ROOT.
    if [[ -n "${TEST_ROOT:-}" && "$hook_target" == "$(hostpath "$wrap_logical")" ]]; then
      :
    else
      SOURCE_GATE_CLASS="AMBIGUOUS_GATE_CONFIGURATION"
      log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
      log INFO "SOURCE_GATE_REJECT_REASON=UNEXPECTED_HOOK_TARGET target=${hook_target}"
      return 0
    fi
  fi
  if [[ "$wrap_present" -eq 1 && "$env_present" -eq 1 && -n "$env_hop" && -n "$current_hop" \
    && "$env_hop" != "$current_hop" && "$env_hop" != "${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}" ]]; then
    SOURCE_GATE_CLASS="AMBIGUOUS_GATE_CONFIGURATION"
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    log INFO "SOURCE_GATE_REJECT_REASON=ENV_HOP_MISMATCH env=${env_hop} current=${current_hop}"
    return 0
  fi

  if [[ "$hook_present" -eq 0 && "$wrap_present" -eq 0 && "$bin_present" -eq 0 && "$env_present" -eq 0 ]]; then
    SOURCE_GATE_CLASS="NO_STELLAR_GATE"
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    return 0
  fi

  # Dangling previous-hop hook: hook live, wrap/bin gone (or previous hop env).
  if [[ "$hook_present" -eq 1 && "$wrap_present" -eq 0 ]]; then
    if [[ "$env_present" -eq 1 && -n "$env_hop" && "$env_hop" == "${PIN_HOP:-focal-to-jammy}" ]]; then
      SOURCE_GATE_CLASS="CURRENT_HOP_GATE_INCOMPLETE"
    else
      SOURCE_GATE_CLASS="PREVIOUS_HOP_GATE_DANGLING_HOOK"
    fi
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    return 0
  fi

  # Hook retired but previous wrap retained.
  if [[ "$hook_present" -eq 0 && ( "$wrap_present" -eq 1 || "$bin_present" -eq 1 || "$env_present" -eq 1 ) ]]; then
    if [[ -n "$env_hop" && "$env_hop" == "${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}" ]] \
      || [[ -n "$marker_hop" && "$marker_hop" == "${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}" ]]; then
      SOURCE_GATE_CLASS="PREVIOUS_HOP_GATE_COMPLETE"
    elif [[ -n "$env_hop" && "$env_hop" == "${PIN_HOP:-focal-to-jammy}" ]]; then
      SOURCE_GATE_CLASS="CURRENT_HOP_GATE_INCOMPLETE"
    else
      SOURCE_GATE_CLASS="PREVIOUS_HOP_GATE_COMPLETE"
    fi
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    return 0
  fi

  # Full current-hop bundle.
  if [[ "$hook_present" -eq 1 && "$wrap_present" -eq 1 && "$bin_present" -eq 1 && "$env_present" -eq 1 ]]; then
    if [[ -x "$wrap_path" && -x "$bin_path" ]] \
      && [[ -n "$env_hop" && "$env_hop" == "$current_hop" ]]; then
      SOURCE_GATE_CLASS="CURRENT_HOP_GATE_VALID"
      log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
      return 0
    fi
    if [[ -n "$env_hop" && "$env_hop" == "${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}" ]]; then
      SOURCE_GATE_CLASS="PREVIOUS_HOP_GATE_COMPLETE"
      log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
      return 0
    fi
    SOURCE_GATE_CLASS="CURRENT_HOP_GATE_INCOMPLETE"
    log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
    return 0
  fi

  SOURCE_GATE_CLASS="CURRENT_HOP_GATE_INCOMPLETE"
  log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"
  return 0
}

validate_effective_source_gate_bundle() {
  # Return 0 only for CURRENT_HOP_GATE_VALID or NO_STELLAR_GATE (pre-install).
  classify_effective_source_gate_bundle
  case "$SOURCE_GATE_CLASS" in
    CURRENT_HOP_GATE_VALID|NO_STELLAR_GATE|PREVIOUS_HOP_GATE_COMPLETE)
      return 0
      ;;
    *)
      return 1
      ;;
  esac
}

archive_effective_source_gate_bundle() {
  # Copy live source-gate bundle into handoff archive previous-source-gate/.
  local dest="$1"
  local apt_path bin_path wrap_path env_path armed passed evid_src
  local sg_root dump_path manifest
  [[ -n "$dest" && -d "$dest" ]] || return 1

  sg_root="${dest}/previous-source-gate"
  mkdir -p "${sg_root}/apt" "${sg_root}/bin" "${sg_root}/markers" "${sg_root}/evidence"
  apt_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_APT:-/etc/apt/apt.conf.d/${SOURCE_GATE_HOOK_BASENAME}}")"
  bin_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_BIN:-${STATE_ROOT}/bin/distupgrade-effective-source-gate}")"
  wrap_path="${bin_path}.wrap"
  env_path="${bin_path}.env"
  armed="$(hostpath "${EFFECTIVE_SOURCE_GATE_ARMED_MARKER:-${STATE_ROOT}/effective-source-gate.armed}")"
  passed="$(hostpath "${EFFECTIVE_SOURCE_GATE_PASSED_MARKER:-${STATE_ROOT}/effective-source-gate.passed}")"
  evid_src="$(hostpath "${EFFECTIVE_SOURCE_GATE_EVIDENCE_ROOT:-${STATE_ROOT}/evidence/effective-source-gate}")"

  if [[ -f "$apt_path" ]]; then
    cp -a "$apt_path" "${sg_root}/apt/${SOURCE_GATE_HOOK_BASENAME}" 2>/dev/null || true
  fi
  dump_path="${sg_root}/apt/apt-config-dump.txt"
  _source_gate_dump_apt_config "$dump_path"
  for f in "$bin_path" "$wrap_path" "$env_path"; do
    if [[ -e "$f" ]]; then
      cp -a "$f" "${sg_root}/bin/" 2>/dev/null || true
    fi
  done
  # Also copy any other gate-related binaries beside the trio.
  if [[ -d "$(dirname "$bin_path")" ]]; then
    local g
    for g in "$(dirname "$bin_path")"/distupgrade-effective-source-gate*; do
      [[ -e "$g" ]] || continue
      cp -a "$g" "${sg_root}/bin/" 2>/dev/null || true
    done
  fi
  [[ -f "$armed" ]] && cp -a "$armed" "${sg_root}/markers/" 2>/dev/null || true
  [[ -f "$passed" ]] && cp -a "$passed" "${sg_root}/markers/" 2>/dev/null || true
  if [[ -d "$evid_src" ]]; then
    cp -a "$evid_src/." "${sg_root}/evidence/" 2>/dev/null || true
  fi

  manifest="${sg_root}/manifest.txt"
  {
    printf 'bundle=effective-source-gate\n'
    printf 'previous_hop=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}}"
    printf 'archived_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
    printf 'hook_present=%s\n' "$([[ -f "${sg_root}/apt/${SOURCE_GATE_HOOK_BASENAME}" ]] && echo YES || echo NO)"
    printf 'wrap_present=%s\n' "$([[ -f "${sg_root}/bin/${SOURCE_GATE_WRAP_BASENAME}" ]] && echo YES || echo NO)"
    if [[ -f "${sg_root}/apt/${SOURCE_GATE_HOOK_BASENAME}" ]]; then
      printf 'hook_sha256=%s\n' "$(sha256_file "${sg_root}/apt/${SOURCE_GATE_HOOK_BASENAME}" 2>/dev/null || echo unknown)"
    fi
    if [[ -f "${sg_root}/bin/${SOURCE_GATE_WRAP_BASENAME}" ]]; then
      printf 'wrap_sha256=%s\n' "$(sha256_file "${sg_root}/bin/${SOURCE_GATE_WRAP_BASENAME}" 2>/dev/null || echo unknown)"
    fi
    if [[ -f "${sg_root}/bin/distupgrade-effective-source-gate.env" ]]; then
      printf 'env_sha256=%s\n' "$(sha256_file "${sg_root}/bin/distupgrade-effective-source-gate.env" 2>/dev/null || echo unknown)"
      cat "${sg_root}/bin/distupgrade-effective-source-gate.env" 2>/dev/null \
        | sed -n 's/^STELLAR_EXPECTED_HOP=/env_expected_hop=/p;s/^STELLAR_EXPECTED_MIRROR_URI=/env_expected_mirror=/p'
    fi
  } >"$manifest"
  _source_gate_fsync_path "$sg_root"
  log INFO "SOURCE_GATE_BUNDLE_ARCHIVED=YES path=${sg_root}"
  return 0
}

retire_effective_source_gate_bundle() {
  # Atomically retire live source-gate bundle into archive. APT hook included.
  local dest="$1"
  local apt_path bin_path wrap_path env_path armed passed
  local sg_root retired_hook=0 retired_wrap=0 retired_bin=0 retired_env=0 retired_markers=0
  local dump_after
  [[ -n "$dest" && -d "$dest" ]] || return 1

  # Ensure archive copy exists first (idempotent).
  archive_effective_source_gate_bundle "$dest" || true

  sg_root="${dest}/previous-source-gate"
  mkdir -p "${sg_root}/apt" "${sg_root}/bin" "${sg_root}/markers"
  apt_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_APT:-/etc/apt/apt.conf.d/${SOURCE_GATE_HOOK_BASENAME}}")"
  bin_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_BIN:-${STATE_ROOT}/bin/distupgrade-effective-source-gate}")"
  wrap_path="${bin_path}.wrap"
  env_path="${bin_path}.env"
  armed="$(hostpath "${EFFECTIVE_SOURCE_GATE_ARMED_MARKER:-${STATE_ROOT}/effective-source-gate.armed}")"
  passed="$(hostpath "${EFFECTIVE_SOURCE_GATE_PASSED_MARKER:-${STATE_ROOT}/effective-source-gate.passed}")"

  _sg_retire_one() {
    local src="$1" subdir="$2"
    local base
    [[ -e "$src" ]] || return 0
    base="$(basename "$src")"
    mkdir -p "${sg_root}/${subdir}"
    # Prefer archive destination; if already archived, remove live only.
    if [[ -e "${sg_root}/${subdir}/${base}" ]]; then
      rm -f "$src" 2>/dev/null || true
      return 0
    fi
    if mv -f "$src" "${sg_root}/${subdir}/${base}" 2>/dev/null; then
      return 0
    fi
    cp -a "$src" "${sg_root}/${subdir}/${base}" 2>/dev/null || return 1
    rm -f "$src" 2>/dev/null || true
    return 0
  }

  # Hook first (prevents dangling Pre-Invoke during subsequent moves), then binaries, then markers.
  if [[ -f "$apt_path" ]]; then
    if ! _source_gate_hook_is_stellar_only "$apt_path"; then
      log ERROR "SOURCE_GATE_CONFIGURATION=AMBIGUOUS"
      log ERROR "SOURCE_GATE_REPAIR=REFUSED"
      log ERROR "SOURCE_GATE_REJECT_REASON=HOOK_FILE_HAS_NON_STELLAR_COMMANDS"
      log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
      return 1
    fi
    _sg_retire_one "$apt_path" "apt" || return 1
    retired_hook=1
  fi

  # Also mirror bin retire into previous-runtime/bin for legacy archive layout.
  mkdir -p "${dest}/previous-runtime/bin"
  for f in "$bin_path" "$wrap_path" "$env_path" "${bin_path}.new"; do
    [[ -e "$f" ]] || continue
    base="$(basename "$f")"
    if [[ ! -e "${dest}/previous-runtime/bin/${base}" ]]; then
      cp -a "$f" "${dest}/previous-runtime/bin/${base}" 2>/dev/null || true
    fi
  done

  if [[ -e "$bin_path" ]]; then
    _sg_retire_one "$bin_path" "bin" || return 1
    retired_bin=1
  fi
  if [[ -e "$env_path" ]]; then
    _sg_retire_one "$env_path" "bin" || return 1
    retired_env=1
  fi
  if [[ -e "$wrap_path" ]]; then
    _sg_retire_one "$wrap_path" "bin" || return 1
    retired_wrap=1
  fi
  # Clean leftover gate binaries from live bin.
  if [[ -d "$(dirname "$bin_path")" ]]; then
    local leftover
    for leftover in "$(dirname "$bin_path")"/distupgrade-effective-source-gate*; do
      [[ -e "$leftover" ]] || continue
      _sg_retire_one "$leftover" "bin" || true
    done
  fi
  if [[ -f "$armed" ]]; then
    _sg_retire_one "$armed" "markers" || true
    # Keep legacy previous-runtime marker path too.
    mkdir -p "${dest}/previous-runtime"
    [[ -e "${dest}/previous-runtime/effective-source-gate.armed" ]] \
      || cp -a "${sg_root}/markers/effective-source-gate.armed" \
           "${dest}/previous-runtime/" 2>/dev/null || true
    retired_markers=1
  fi
  if [[ -f "$passed" ]]; then
    _sg_retire_one "$passed" "markers" || true
    mkdir -p "${dest}/previous-runtime"
    [[ -e "${dest}/previous-runtime/effective-source-gate.passed" ]] \
      || cp -a "${sg_root}/markers/effective-source-gate.passed" \
           "${dest}/previous-runtime/" 2>/dev/null || true
    retired_markers=1
  fi

  dump_after="${sg_root}/apt/apt-config-dump-after-retire.txt"
  _source_gate_dump_apt_config "$dump_after"
  if _source_gate_dangling_hook_in_dump "$dump_after"; then
    # Also check live apt path absence.
    if [[ -f "$apt_path" ]]; then
      log ERROR "SOURCE_GATE_DANGLING_HOOK_CHECK=FAIL"
      {
        printf 'SOURCE_GATE_RETIRE_COMPLETE=NO\n'
        printf 'incomplete=YES\n'
        printf 'reason=DANGLING_HOOK_REMAINS\n'
      } >"${sg_root}/retire-incomplete.txt"
      return 1
    fi
  fi

  {
    printf 'SOURCE_GATE_RETIRE_COMPLETE=YES\n'
    printf 'SOURCE_GATE_PREVIOUS_HOP=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}}"
    printf 'APT_HOOK_RETIRED=%s\n' "$([[ "$retired_hook" -eq 1 || ! -f "$apt_path" ]] && echo YES || echo NO)"
    printf 'WRAPPER_RETIRED=%s\n' "$([[ "$retired_wrap" -eq 1 || ! -e "$wrap_path" ]] && echo YES || echo NO)"
    printf 'EXECUTABLE_RETIRED=%s\n' "$([[ "$retired_bin" -eq 1 || ! -e "$bin_path" ]] && echo YES || echo NO)"
    printf 'ENV_RETIRED=%s\n' "$([[ "$retired_env" -eq 1 || ! -e "$env_path" ]] && echo YES || echo NO)"
    printf 'MARKERS_RETIRED=%s\n' "$([[ "$retired_markers" -eq 1 ]] && echo YES || echo NO)"
    printf 'DANGLING_HOOK_CHECK=PASS\n'
  } >"${sg_root}/retire-complete.txt"
  _source_gate_fsync_path "$sg_root"

  log INFO "SOURCE_GATE_RETIRE_COMPLETE=YES"
  log INFO "SOURCE_GATE_PREVIOUS_HOP=${PREVIOUS_HOP_RUNTIME_OWNER:-${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}}"
  log INFO "APT_HOOK_RETIRED=YES"
  log INFO "WRAPPER_RETIRED=YES"
  log INFO "EXECUTABLE_RETIRED=YES"
  log INFO "ENV_RETIRED=YES"
  log INFO "SOURCE_GATE_DANGLING_HOOK_CHECK=PASS"
  return 0
}

_source_gate_preflight_repair_safe() {
  # Preconditions for automatic dangling-hook repair.
  # Two safe shapes:
  #   A) PREFLIGHT/READY + current-hop identity + handoff archive with previous wrap
  #   B) Orphan Stellar hook (no wrap/env) with no current-hop mutation — e.g. fixture
  #      cleanup removed STATE_ROOT/bin but left apt.conf.d hook.
  local st current_hop arch env_path env_hop
  st="$(read_state 2>/dev/null || true)"
  current_hop="$(read_current_hop_field CURRENT_HOP 2>/dev/null || true)"
  env_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_BIN:-${STATE_ROOT}/bin/distupgrade-effective-source-gate}").env"
  env_hop=""
  if [[ -f "$env_path" ]]; then
    env_hop="$(_source_gate_read_kv "$env_path" STELLAR_EXPECTED_HOP || true)"
  fi

  if detect_upgrade_already_running 2>/dev/null; then
    return 1
  fi
  set +e
  current_hop_mutation_evidence_present
  local mut_rc=$?
  set -e
  [[ "$mut_rc" -eq 1 ]] || return 1
  if [[ -z "${TEST_ROOT:-}" ]]; then
    check_dpkg_health || return 1
  fi

  # Shape A: production chained PREFLIGHT with handoff archive evidence.
  if [[ "$st" == "PREFLIGHT" || "$st" == "READY_FOR_CONFIRMATION" ]]; then
    if [[ "$current_hop" == "${PIN_HOP:-focal-to-jammy}" ]]; then
      arch="$(find_latest_handoff_archive_any || true)"
      if [[ -n "$arch" ]] && _source_gate_archive_has_previous_wrap "$arch"; then
        return 0
      fi
    fi
  fi

  # Shape B: orphan Stellar hook — no live wrap/env claiming current hop.
  if [[ ! -e "$(hostpath "$(_source_gate_standard_wrap_path)")" ]]; then
    if [[ -z "$env_hop" || "$env_hop" == "${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}" ]]; then
      # Fresh / wiped STATE_ROOT, or previous-hop env only.
      if [[ -z "$st" || "$st" == "PREFLIGHT" || "$st" == "READY_FOR_CONFIRMATION" || "$st" == "READY_FOR_RESUME" ]]; then
        return 0
      fi
    fi
  fi
  return 1
}

repair_dangling_previous_source_gate_hook() {
  # Repair CURRENT_HOP_PREFLIGHT_WITH_DANGLING_PREVIOUS_SOURCE_GATE_HOOK.
  local apt_path wrap_path arch dump_path
  classify_effective_source_gate_bundle
  log INFO "SOURCE_GATE_CLASS=${SOURCE_GATE_CLASS}"

  case "$SOURCE_GATE_CLASS" in
    NO_STELLAR_GATE|CURRENT_HOP_GATE_VALID|PREVIOUS_HOP_GATE_COMPLETE)
      log INFO "SOURCE_GATE_DANGLING_HOOK_CHECK=PASS"
      return 0
      ;;
    AMBIGUOUS_GATE_CONFIGURATION)
      log ERROR "SOURCE_GATE_CONFIGURATION=AMBIGUOUS"
      log ERROR "SOURCE_GATE_REPAIR=REFUSED"
      log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
      return 1
      ;;
    CURRENT_HOP_GATE_INCOMPLETE)
      # Missing current wrap with current env — do not run apt until reinstall (commit path).
      log ERROR "SOURCE_GATE_CONFIGURATION=CURRENT_HOP_GATE_INCOMPLETE"
      log ERROR "SOURCE_GATE_REPAIR=REFUSED"
      log ERROR "SOURCE_GATE_REJECT_REASON=CURRENT_HOP_WRAPPER_MISSING"
      log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
      return 1
      ;;
    PREVIOUS_HOP_GATE_DANGLING_HOOK)
      ;;
    *)
      log ERROR "SOURCE_GATE_CONFIGURATION=${SOURCE_GATE_CLASS}"
      log ERROR "SOURCE_GATE_REPAIR=REFUSED"
      return 1
      ;;
  esac

  log INFO "DANGLING_PREVIOUS_SOURCE_GATE_HOOK=DETECTED"
  log INFO "CURRENT_HOP_PREFLIGHT_WITH_DANGLING_PREVIOUS_SOURCE_GATE_HOOK=YES"

  if ! _source_gate_preflight_repair_safe; then
    log ERROR "SOURCE_GATE_REPAIR=REFUSED"
    log ERROR "SOURCE_GATE_REJECT_REASON=UNSAFE_REPAIR_PRECONDITIONS"
    log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
    return 1
  fi

  apt_path="$(hostpath "${EFFECTIVE_SOURCE_GATE_APT:-/etc/apt/apt.conf.d/${SOURCE_GATE_HOOK_BASENAME}}")"
  wrap_path="$(hostpath "$(_source_gate_standard_wrap_path)")"
  if [[ -e "$wrap_path" ]]; then
    log ERROR "SOURCE_GATE_REPAIR=REFUSED"
    log ERROR "SOURCE_GATE_REJECT_REASON=WRAP_UNEXPECTEDLY_PRESENT"
    return 1
  fi
  if [[ ! -f "$apt_path" ]] || ! _source_gate_hook_is_stellar_only "$apt_path"; then
    log ERROR "SOURCE_GATE_CONFIGURATION=AMBIGUOUS"
    log ERROR "SOURCE_GATE_REPAIR=REFUSED"
    log ERROR "SOURCE_GATE_REJECT_REASON=HOOK_NOT_STELLAR_ONLY"
    log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
    return 1
  fi

  arch="$(find_latest_handoff_archive_any || true)"
  if [[ -z "$arch" ]] || ! _source_gate_archive_has_previous_wrap "$arch"; then
    # Orphan hook with no chained handoff wrap — quarantine under backups.
    arch="$(hostpath ${BACKUP_ROOT}/orphan-source-gate-$(date -u '+%Y%m%dT%H%M%SZ'))"
    mkdir -p "$arch"
    log INFO "SOURCE_GATE_ORPHAN_HOOK_QUARANTINE=${arch}"
  fi
  mkdir -p "${arch}/previous-source-gate/apt"
  if [[ ! -f "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}" ]]; then
    cp -a "$apt_path" "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}" 2>/dev/null || true
  fi
  dump_path="${arch}/previous-source-gate/apt/apt-config-dump-before-repair.txt"
  _source_gate_dump_apt_config "$dump_path"
  {
    printf 'repair=dangling_previous_source_gate_hook\n'
    printf 'repaired_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
    printf 'previous_hop=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-${PREVIOUS_HOP_PIN_NAME:-bionic-to-focal}}"
    printf 'current_hop=%s\n' "$(read_current_hop_field CURRENT_HOP 2>/dev/null || echo "${PIN_HOP}")"
    printf 'state=%s\n' "$(read_state)"
  } >"${arch}/previous-source-gate/dangling-hook-repair.txt"

  # Atomic retire of live hook only (binaries already archived / absent).
  if ! mv -f "$apt_path" "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}.live" 2>/dev/null; then
    cp -a "$apt_path" "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}.live" 2>/dev/null || true
    rm -f "$apt_path" 2>/dev/null || true
  fi
  # Canonical name in archive if missing.
  if [[ ! -f "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}" ]]; then
    mv -f "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}.live" \
      "${arch}/previous-source-gate/apt/${SOURCE_GATE_HOOK_BASENAME}" 2>/dev/null || true
  fi
  _source_gate_fsync_path "${arch}/previous-source-gate"

  if [[ -f "$apt_path" ]]; then
    log ERROR "PREVIOUS_SOURCE_GATE_HOOK=RETIRE_FAILED"
    return 1
  fi

  dump_path="${arch}/previous-source-gate/apt/apt-config-dump-after-repair.txt"
  _source_gate_dump_apt_config "$dump_path"
  if _source_gate_dangling_hook_in_dump "$dump_path" && [[ -z "${TEST_ROOT:-}" ]]; then
    # Under TEST_ROOT dump is synthesized from files — absence of apt_path is enough.
    if grep -Fq "$(_source_gate_standard_wrap_path)" "$dump_path" 2>/dev/null; then
      log ERROR "SOURCE_GATE_DANGLING_HOOK_CHECK=FAIL"
      return 1
    fi
  fi

  log INFO "PREVIOUS_SOURCE_GATE_HOOK=ARCHIVED"
  log INFO "PREVIOUS_SOURCE_GATE_HOOK=RETIRED"
  log INFO "SOURCE_GATE_DANGLING_HOOK_CHECK=PASS"
  log INFO "SOURCE_GATE_REPAIR=PASS"
  # Keep PREFLIGHT; caller restarts preflight apt checks.
  return 0
}

ensure_source_gate_safe_for_preflight() {
  # Called before any host-visible temporary apt-get update.
  classify_effective_source_gate_bundle
  case "$SOURCE_GATE_CLASS" in
    NO_STELLAR_GATE|CURRENT_HOP_GATE_VALID)
      log INFO "SOURCE_GATE_DANGLING_HOOK_CHECK=PASS"
      return 0
      ;;
    PREVIOUS_HOP_GATE_COMPLETE)
      # Previous wrap may remain without hook — retire leftovers into latest archive if present.
      local arch
      arch="$(find_latest_handoff_archive_any || true)"
      if [[ -n "$arch" ]]; then
        retire_effective_source_gate_bundle "$arch" || true
      fi
      classify_effective_source_gate_bundle
      if [[ "$SOURCE_GATE_CLASS" == "NO_STELLAR_GATE" || "$SOURCE_GATE_CLASS" == "PREVIOUS_HOP_GATE_COMPLETE" ]]; then
        log INFO "SOURCE_GATE_DANGLING_HOOK_CHECK=PASS"
        return 0
      fi
      ;;
    PREVIOUS_HOP_GATE_DANGLING_HOOK)
      repair_dangling_previous_source_gate_hook || \
        die "$EC_STATE" "FAIL_DANGLING_PREVIOUS_SOURCE_GATE_HOOK"
      return 0
      ;;
    AMBIGUOUS_GATE_CONFIGURATION|CURRENT_HOP_GATE_INCOMPLETE)
      log ERROR "SOURCE_GATE_CONFIGURATION=${SOURCE_GATE_CLASS}"
      log ERROR "SOURCE_GATE_REPAIR=REFUSED"
      log ERROR "OPERATOR_INTERVENTION_REQUIRED=YES"
      die "$EC_STATE" "FAIL_SOURCE_GATE_CONFIGURATION_${SOURCE_GATE_CLASS}"
      ;;
  esac
  return 0
}

build_temp_apt_conf_parts_without_stellar_gate() {
  # Copy host apt.conf.d into dest, excluding only the Stellar source-gate hook.
  local dest="$1"
  local confd src base
  confd="$(hostpath /etc/apt/apt.conf.d)"
  mkdir -p "$dest"
  [[ -d "$confd" ]] || return 0
  for src in "$confd"/*; do
    [[ -e "$src" ]] || continue
    base="$(basename "$src")"
    [[ "$base" == "$SOURCE_GATE_HOOK_BASENAME" ]] && continue
    cp -a "$src" "$dest/" 2>/dev/null || true
  done
  return 0
}

persist_temp_apt_failure_evidence() {
  local tmp="$1"
  local exit_code="$2"
  local label="${3:-apt-update}"
  local dest stamp
  stamp="$(date -u '+%Y%m%dT%H%M%SZ')"
  dest="$(hostpath ${STATE_ROOT}/evidence/preflight-apt/${stamp})"
  mkdir -p "$dest" "${dest}/sourceparts"
  if [[ -f "${tmp}/apt-update.err" ]]; then
    cp -a "${tmp}/apt-update.err" "${dest}/apt-update.stderr" 2>/dev/null || true
  fi
  if [[ -f "${tmp}/update.err" ]]; then
    cp -a "${tmp}/update.err" "${dest}/apt-update.stderr" 2>/dev/null || true
  fi
  if [[ -f "${tmp}/apt-update.out" ]]; then
    cp -a "${tmp}/apt-update.out" "${dest}/apt-update.stdout" 2>/dev/null || true
  fi
  _source_gate_dump_apt_config "${dest}/apt-config-dump.txt"
  if [[ -f "${tmp}/aptroot/etc/apt/sources.list" ]]; then
    cp -a "${tmp}/aptroot/etc/apt/sources.list" "${dest}/sources.list" 2>/dev/null || true
  elif [[ -f "${tmp}/sources.list" ]]; then
    cp -a "${tmp}/sources.list" "${dest}/sources.list" 2>/dev/null || true
  fi
  if [[ -d "${tmp}/aptroot/etc/apt/apt.conf.d" ]]; then
    cp -a "${tmp}/aptroot/etc/apt/apt.conf.d/." "${dest}/sourceparts/" 2>/dev/null || true
  fi
  {
    printf 'SOURCE_GATE_CLASS=%s\n' "${SOURCE_GATE_CLASS:-unknown}"
    classify_effective_source_gate_bundle 2>/dev/null || true
    printf 'SOURCE_GATE_CLASS_AFTER=%s\n' "${SOURCE_GATE_CLASS:-unknown}"
  } >"${dest}/source-gate-classification.txt" 2>/dev/null || true
  printf '%s\n' "$exit_code" >"${dest}/exit-code"
  printf 'label=%s\n' "$label" >"${dest}/meta.txt"
  log ERROR "TEMP_APT_FAILURE_EVIDENCE=${dest}"
  printf '%s\n' "$dest"
}

install_effective_source_gate_bundle() {
  # Compatibility alias — install_effective_source_gate performs ordered bundle install.
  install_effective_source_gate "$@"
}

backup_previous_hop_handoff_evidence() {
  # Preserve previous-hop terminal + runtime evidence before retire/state transition.
  local stamp dest src_state holds
  stamp="$(date -u '+%Y%m%dT%H%M%SZ')"
  dest="$(hostpath ${BACKUP_ROOT}/handoff-state-${stamp})"
  mkdir -p "$dest/previous-runtime" "$dest/previous-critical-holds" "$dest/previous-source-gate" "$dest/evidence"
  src_state="$(hostpath "$STATE_FILE")"
  holds="$(hostpath "$HOLDS_DIR")"
  if [[ -f "$src_state" ]]; then
    cp -a "$src_state" "$dest/state" 2>/dev/null || true
  fi
  cp -a "$(hostpath "$LOG_FILE")" "$dest/offline_os_upgrade.log" 2>/dev/null || true
  if [[ -f "$(hostpath "$HISTORY_FILE")" ]]; then
    cp -a "$(hostpath "$HISTORY_FILE")" "$dest/hop_history" 2>/dev/null || true
  fi
  if [[ -d "$holds" ]]; then
    cp -a "$holds/." "$dest/previous-critical-holds/" 2>/dev/null || true
  fi
  if [[ -f "$(hostpath "$PIN_ENV_FILE")" ]]; then
    cp -a "$(hostpath "$PIN_ENV_FILE")" "$dest/previous-pins.env" 2>/dev/null || true
  fi
  if [[ -f "$(current_hop_env_path)" ]]; then
    mkdir -p "$dest/previous-runtime"
    cp -a "$(current_hop_env_path)" "$dest/previous-runtime/current-hop.env" 2>/dev/null || true
  fi
  if [[ -f "$(hostpath ${STATE_ROOT}/client-manifest.json)" ]]; then
    cp -a "$(hostpath ${STATE_ROOT}/client-manifest.json)" "$dest/previous-client-manifest.json" 2>/dev/null || true
  fi
  # Source-gate / distupgrade / runner volatile copies (durable archive, live retired later).
  local sg
  for sg in \
    effective-source-gate.armed \
    effective-source-gate.passed \
    distupgrade-target.sources.list \
    distupgrade-valid-mirrors.cfg \
    runner.pid \
    runner_stage \
    meta-release-lts \
    meta-release-lts.runtime; do
    if [[ -e "$(hostpath ${STATE_ROOT}/${sg})" ]]; then
      cp -a "$(hostpath ${STATE_ROOT}/${sg})" "$dest/previous-source-gate/" 2>/dev/null || true
    fi
  done
  if [[ -d "$(hostpath ${STATE_ROOT}/bin)" ]]; then
    mkdir -p "$dest/previous-source-gate/bin"
    cp -a "$(hostpath ${STATE_ROOT}/bin)/." "$dest/previous-source-gate/bin/" 2>/dev/null || true
  fi
  # Full source-gate bundle (executable/env/wrapper/APT hook/markers/evidence).
  archive_effective_source_gate_bundle "$dest" || true
  if [[ -d "$(hostpath ${STATE_ROOT}/evidence)" ]]; then
    cp -a "$(hostpath ${STATE_ROOT}/evidence)/." "$dest/evidence/" 2>/dev/null || true
  fi
  if [[ -f "$(hostpath /etc/os-release)" ]]; then
    cp -a "$(hostpath /etc/os-release)" "$dest/os-release" 2>/dev/null || true
  fi
  {
    printf 'kernel=%s\n' "$(uname -r 2>/dev/null || echo unknown)"
    printf 'PREVIOUS_HOP_STATE=%s\n' "${PREVIOUS_HOP_TERMINAL_STATE}"
    printf 'PREVIOUS_HOP_RUNTIME_OWNER=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}"
    printf 'NEXT_HOP=%s\n' "${PIN_HOP}"
    printf 'backed_up_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
  } >"$dest/handoff-meta.txt"
  {
    printf 'archive_schema=1\n'
    printf 'previous_hop=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}"
    printf 'next_hop=%s\n' "${PIN_HOP}"
    printf 'created_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
  } >"$dest/archive-manifest.txt"
  if [[ -n "$TEST_ROOT" ]]; then
    printf 'dpkg_audit=CLEAN_TEST_FIXTURE\n' >"$dest/dpkg-audit.txt"
    printf 'service_active=inactive\n' >"$dest/service-status.txt"
  else
    (dpkg --audit 2>&1 || true) >"$dest/dpkg-audit.txt" || true
    {
      printf 'unit=%s\n' "$UNIT_NAME"
      systemctl is-active "$UNIT_NAME" 2>/dev/null || printf 'inactive\n'
      systemctl show -p ActiveState -p SubState "$UNIT_NAME" 2>/dev/null || true
    } >"$dest/service-status.txt" || true
  fi
  if command -v sync >/dev/null 2>&1; then
    sync "$dest" 2>/dev/null || sync 2>/dev/null || true
  fi
  HOP_HANDOFF_BACKUP_PATH="$dest"
  printf '%s\n' "$dest"
}

retire_previous_hop_runtime_evidence() {
  # Move volatile previous-hop runtime out of the live state directory into archive.
  # Never delete durable evidence without an archive copy.
  local dest="$1"
  local holds root name
  local retired=0
  [[ -n "$dest" && -d "$dest" ]] || return 1
  mkdir -p "$dest/previous-runtime" "$dest/previous-critical-holds" "$dest/previous-source-gate"
  holds="$(hostpath "$HOLDS_DIR")"
  root="$(hostpath "$STATE_ROOT")"

  _retire_mv() {
    local src="$1" subdir="$2"
    local base
    [[ -e "$src" ]] || return 0
    base="$(basename "$src")"
    mkdir -p "${dest}/${subdir}"
    # Prefer rename into archive; fall back to copy+rm only if cross-device.
    if mv -f "$src" "${dest}/${subdir}/${base}" 2>/dev/null; then
      retired=$((retired + 1))
      return 0
    fi
    cp -a "$src" "${dest}/${subdir}/${base}" 2>/dev/null || return 1
    rm -rf "$src" 2>/dev/null || true
    retired=$((retired + 1))
  }

  if [[ -d "$holds" ]]; then
    for name in \
      release_upgrade_invocation_started \
      release_upgrade_process_spawned \
      release_upgrade_package_transition_started \
      release_upgrade_completed \
      release_upgrade_started \
      package_transition_detection.done \
      package_transition_run_epoch \
      package_transition_baseline_at \
      package_transition_runner_pid \
      package_transition_watcher.stop \
      package_transition_watcher.pid \
      package_transition_mark.lock \
      dpkg_status_mtime_before \
      dpkg_status_sha_before \
      dpkg_log_offset_before \
      dpkg_log_inode_before \
      dpkg_log_mtime_before \
      dpkg_log_size_before \
      dpkg_updates_listing_before \
      core_package_versions_before \
      release_upgrade_package_transition_started.meta \
      release_upgrade_invocation_started.meta \
      release_upgrade_started.meta; do
      _retire_mv "${holds}/${name}" "previous-critical-holds"
    done
    # Also retire any leftover dpkg_*_before / core_* snapshots.
    local f
    for f in "$holds"/dpkg_*_before "$holds"/core_package_versions_before; do
      [[ -e "$f" ]] || continue
      _retire_mv "$f" "previous-critical-holds"
    done
  fi

  # Source-gate bundle FIRST (hook+wrapper+env+executable+markers) — never leave dangling hook.
  if ! retire_effective_source_gate_bundle "$dest"; then
    log ERROR "SOURCE_GATE_BUNDLE_RETIRE=FAILED"
    printf 'retired_count=%s\nSOURCE_GATE_RETIRE_COMPLETE=NO\n' "$retired" >"$dest/retire-manifest.txt"
    return 1
  fi

  for name in \
    runner.pid \
    runner_stage \
    distupgrade-target.sources.list \
    distupgrade-valid-mirrors.cfg \
    meta-release-lts \
    meta-release-lts.runtime \
    release_upgrade_package_transition_started \
    pins.env \
    client-manifest.json; do
    _retire_mv "${root}/${name}" "previous-runtime"
  done

  printf 'retired_count=%s\nSOURCE_GATE_RETIRE_COMPLETE=YES\n' "$retired" >"$dest/retire-manifest.txt"
  if command -v sync >/dev/null 2>&1; then
    sync "$dest" 2>/dev/null || sync 2>/dev/null || true
  fi
  log INFO "PREVIOUS_HOP_VOLATILE_STATE=RETIRED"
  log INFO "PREVIOUS_HOP_RUNTIME_EVIDENCE=ARCHIVED"
  return 0
}

find_resumable_handoff_archive() {
  # Latest incomplete handoff archive (no handoff-complete.ok) for COMPLETED_FOCAL.
  local root newest f
  root="$(hostpath "$BACKUP_ROOT")"
  [[ -d "$root" ]] || return 1
  newest=""
  for f in "$root"/handoff-state-*; do
    [[ -d "$f" ]] || continue
    [[ -f "$f/handoff-complete.ok" ]] && continue
    if [[ -f "$f/state" ]] && grep -qx "$PREVIOUS_HOP_TERMINAL_STATE" "$f/state" 2>/dev/null; then
      newest="$f"
    fi
  done
  [[ -n "$newest" ]] || return 1
  printf '%s\n' "$newest"
}

find_latest_previous_hop_quarantine_backup() {
  # Return newest corrupt-state-* backup whose state file is exactly COMPLETED_FOCAL.
  local root newest f st
  root="$(hostpath "$BACKUP_ROOT")"
  [[ -d "$root" ]] || return 1
  newest=""
  # Lexicographic order of UTC stamps in directory names is chronological.
  for f in "$root"/corrupt-state-*/state; do
    [[ -f "$f" ]] || continue
    st="$(tr -d '\r' <"$f" | head -1)"
    if [[ "$st" == "$PREVIOUS_HOP_TERMINAL_STATE" ]]; then
      newest="$(dirname "$f")"
    fi
  done
  [[ -n "$newest" ]] || return 1
  printf '%s\n' "$newest"
}

validate_previous_hop_handoff() {
  # Fail-closed cross-check before accepting Xenial→Focal terminal state.
  # Sets no durable state. Return 0 only when all conditions PASS.
  local st="$1"
  local ver code
  local reject_reason=""
  local mut_rc=1

  classify_mutation_evidence_ownership || true
  log INFO "PREVIOUS_HOP_STATE=${st}"
  log INFO "PREVIOUS_HOP_TARGET_OS=20.04"
  log INFO "PREVIOUS_HOP_RUNTIME_OWNER=${PREVIOUS_HOP_RUNTIME_OWNER:-unknown}"
  log INFO "NEXT_HOP=${PIN_HOP}"
  log INFO "MUTATION_EVIDENCE_CLASS=${MUTATION_EVIDENCE_CLASS}"

  if [[ "$st" != "$PREVIOUS_HOP_TERMINAL_STATE" ]]; then
    reject_reason="STATE_NOT_PREVIOUS_HOP_TERMINAL"
  elif ! is_focal_to_jammy_client; then
    reject_reason="CLIENT_HOP_PIN_MISMATCH"
  else
    ver="$(read_os_field VERSION_ID)"
    code="$(read_os_field VERSION_CODENAME)"
    [[ -z "$code" ]] && code="$(read_os_field UBUNTU_CODENAME)"
    log INFO "CURRENT_OS=${ver}"
    log INFO "CURRENT_CODENAME=${code}"
    if [[ "$ver" != "20.04" ]]; then
      reject_reason="OS_VERSION_MISMATCH"
    elif [[ "$code" != "focal" ]]; then
      reject_reason="OS_CODENAME_MISMATCH"
    elif detect_upgrade_already_running; then
      reject_reason="CURRENT_HOP_RUNNER_ACTIVE"
    else
      set +e
      current_hop_mutation_evidence_present
      mut_rc=$?
      set -e
      if [[ "$mut_rc" -eq 0 ]]; then
        reject_reason="CURRENT_HOP_MUTATION_EVIDENCE"
      elif [[ "$mut_rc" -eq 2 ]]; then
        reject_reason="AMBIGUOUS_MUTATION_EVIDENCE"
      elif ! check_dpkg_health; then
        reject_reason="DPKG_OR_APT_UNHEALTHY"
      fi
    fi
  fi

  if [[ -n "$reject_reason" ]]; then
    log ERROR "HOP_HANDOFF_VALIDATION=FAIL"
    log ERROR "HOP_HANDOFF_REJECT_REASON=${reject_reason}"
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    return 1
  fi

  log INFO "HOP_HANDOFF_VALIDATION=PASS"
  return 0
}

accept_previous_hop_terminal_state() {
  # Backup → retire previous volatile runtime → reset flags → current-hop identity → PREFLIGHT.
  local st="$1"
  local backup target resumable
  target="$HOP_HANDOFF_TARGET_STATE"

  if ! validate_previous_hop_handoff "$st"; then
    die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_REJECTED (state=${st})"
  fi

  # Resume incomplete handoff (archive exists, live still COMPLETED_FOCAL).
  resumable="$(find_resumable_handoff_archive || true)"
  if [[ -n "$resumable" ]]; then
    backup="$resumable"
    HOP_HANDOFF_BACKUP_PATH="$backup"
    log INFO "HOP_HANDOFF_RESUME_ARCHIVE=${backup}"
  else
    backup="$(backup_previous_hop_handoff_evidence)"
  fi

  {
    printf 'event=FOCAL_TO_JAMMY_HANDOFF_PENDING\n'
    printf 'PREVIOUS_HOP_STATE=%s\n' "$st"
    printf 'PREVIOUS_HOP_TARGET_OS=20.04\n'
    printf 'PREVIOUS_HOP_RUNTIME_OWNER=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}"
    printf 'CURRENT_OS=%s\n' "$(read_os_field VERSION_ID)"
    printf 'CURRENT_CODENAME=%s\n' "$(read_os_field VERSION_CODENAME)"
    printf 'NEXT_HOP=%s\n' "$PIN_HOP"
    printf 'HOP_HANDOFF_VALIDATION=PASS\n'
    printf 'HOP_HANDOFF_SOURCE_STATE=%s\n' "$st"
    printf 'HOP_HANDOFF_TARGET_STATE=%s\n' "$target"
    printf 'HOP_HANDOFF_STATUS=PENDING\n'
    printf 'HOP_HANDOFF_BACKUP=%s\n' "$backup"
    printf 'pending_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
  } >"${backup}/handoff-event.txt"

  # Retire volatile previous-hop runtime BEFORE flipping state.
  if ! retire_previous_hop_runtime_evidence "$backup"; then
    log ERROR "HOP_HANDOFF_RETIRE=FAILED"
    log ERROR "previous state preserved (live state unchanged)"
    die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_RETIRE"
  fi

  reset_in_memory_upgrade_flags

  # Always (re)write current-hop.env to this hop's pins. An existing previous-hop
  # current-hop.env must not be treated as already-initialized for Focal→Jammy.
  if ! initialize_current_hop_identity; then
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    log ERROR "HOP_HANDOFF_REJECT_REASON=CURRENT_HOP_IDENTITY_PERSIST_FAILED"
    die "$EC_STATE" "FAIL_CURRENT_HOP_IDENTITY_PERSIST"
  fi
  load_current_hop_identity_vars || true

  # Append durable hop history evidence (non-destructive).
  mkdir -p "$(dirname "$(hostpath "$HISTORY_FILE")")"
  printf 'HOP_HANDOFF: %s -> %s backup=%s owner=%s\n' \
    "$st" "$target" "$backup" "${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}" \
    >>"$(hostpath "$HISTORY_FILE")" 2>/dev/null || true

  if ! write_state_atomic "$target"; then
    log ERROR "HOP_HANDOFF_STATE_TRANSITION=FAILED"
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    log ERROR "previous state preserved at ${backup}/state (live state unchanged or partial write cleaned)"
    die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_ATOMIC_WRITE"
  fi

  # Confirm post-rename content.
  if [[ "$(read_state)" != "$target" ]]; then
    log ERROR "HOP_HANDOFF_STATE_TRANSITION=VERIFY_FAILED"
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_VERIFY"
  fi

  # Final identity re-check before claiming handoff accepted.
  if ! verify_persisted_current_hop_contract "$(current_hop_env_path)"; then
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    log ERROR "HOP_HANDOFF_REJECT_REASON=PERSISTED_HOP_CONTRACT_MISMATCH_AFTER_STATE"
    die "$EC_STATE" "FAIL_CURRENT_HOP_IDENTITY_PERSIST"
  fi

  # ACCEPTED evidence only after full 8-field re-read verification (persisted values).
  {
    printf 'event=FOCAL_TO_JAMMY_HANDOFF_ACCEPTED\n'
    printf 'PREVIOUS_HOP_STATE=%s\n' "$st"
    printf 'PREVIOUS_HOP_TARGET_OS=20.04\n'
    printf 'PREVIOUS_HOP_RUNTIME_OWNER=%s\n' "${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}"
    printf 'CURRENT_OS=%s\n' "$(read_os_field VERSION_ID)"
    printf 'CURRENT_CODENAME=%s\n' "$(read_os_field VERSION_CODENAME)"
    printf 'NEXT_HOP=%s\n' "$PIN_HOP"
    printf 'HOP_HANDOFF_VALIDATION=PASS\n'
    printf 'HOP_HANDOFF_SOURCE_STATE=%s\n' "$st"
    printf 'HOP_HANDOFF_TARGET_STATE=%s\n' "$target"
    printf 'HOP_HANDOFF_STATUS=ACCEPTED\n'
    printf 'HOP_HANDOFF_ACCEPTED=YES\n'
    printf 'HOP_HANDOFF_STATE_TRANSITION=ATOMIC\n'
    printf 'HOP_HANDOFF_BACKUP=%s\n' "$backup"
    printf 'PERSISTED_CURRENT_HOP=%s\n' "$(read_current_hop_field CURRENT_HOP)"
    printf 'PERSISTED_CURRENT_SOURCE_VERSION=%s\n' "$(read_current_hop_field CURRENT_SOURCE_VERSION)"
    printf 'PERSISTED_CURRENT_SOURCE_CODENAME=%s\n' "$(read_current_hop_field CURRENT_SOURCE_CODENAME)"
    printf 'PERSISTED_CURRENT_TARGET_VERSION=%s\n' "$(read_current_hop_field CURRENT_TARGET_VERSION)"
    printf 'PERSISTED_CURRENT_TARGET_CODENAME=%s\n' "$(read_current_hop_field CURRENT_TARGET_CODENAME)"
    printf 'PERSISTED_HANDOFF_SOURCE_STATE=%s\n' "$(read_current_hop_field HANDOFF_SOURCE_STATE)"
    printf 'PERSISTED_PACKAGE_TRANSITION_STARTED=%s\n' "$(read_current_hop_field PACKAGE_TRANSITION_STARTED)"
    printf 'PERSISTED_CLIENT_ARTIFACT_SHA256=%s\n' "$(read_current_hop_field CLIENT_ARTIFACT_SHA256)"
    printf 'accepted_at=%s\n' "$(date -u '+%Y-%m-%dT%H:%M:%SZ')"
  } >"${backup}/handoff-event.txt.tmp"
  if ! mv -f "${backup}/handoff-event.txt.tmp" "${backup}/handoff-event.txt"; then
    log ERROR "HOP_HANDOFF_ACCEPTED=NO"
    log ERROR "HOP_HANDOFF_REJECT_REASON=HANDOFF_EVENT_REPLACE_FAILED"
    rm -f "${backup}/handoff-event.txt.tmp" 2>/dev/null || true
    die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_EVENT"
  fi

  printf 'ok\n' >"${backup}/handoff-complete.ok"
  if command -v sync >/dev/null 2>&1; then
    sync "${backup}/handoff-complete.ok" 2>/dev/null || true
    sync "${backup}/handoff-event.txt" 2>/dev/null || true
  fi

  log INFO "PREVIOUS_HOP_RUNTIME_OWNER=${PREVIOUS_HOP_RUNTIME_OWNER:-$PREVIOUS_HOP_PIN_NAME}"
  log INFO "PINNED_CURRENT_HOP=${PIN_HOP}"
  log INFO "PERSISTED_CURRENT_HOP=$(read_current_hop_field CURRENT_HOP)"
  log INFO "CURRENT_HOP=$(read_current_hop_field CURRENT_HOP)"
  log INFO "PREVIOUS_HOP_RUNTIME_EVIDENCE=ARCHIVED"
  log INFO "PREVIOUS_HOP_VOLATILE_STATE=RETIRED"
  log INFO "HOP_HANDOFF_SOURCE_STATE=${st}"
  log INFO "HOP_HANDOFF_TARGET_STATE=${target}"
  log INFO "HOP_HANDOFF_ACCEPTED=YES"
  log INFO "HOP_HANDOFF_STATE_TRANSITION=ATOMIC"
  log INFO "HOP_HANDOFF_BACKUP=${backup}"
  log INFO "PREVIOUS_HOP_COMPLETED_VALIDATED=YES"
  log INFO "FOCAL_TO_JAMMY_HANDOFF_ACCEPTED=YES"
  return 0
}

try_recover_previous_hop_state_from_quarantine() {
  # Case B: live state missing/blank, but a corrupt-state quarantine holds COMPLETED_FOCAL.
  # Never trust a quarantine blindly — re-run full handoff validation after restore.
  local q path st ver code pins_hop manifest_hop mut_rc
  q="$(find_latest_previous_hop_quarantine_backup || true)"
  [[ -n "$q" ]] || return 1

  path="${q}/state"
  st="$(tr -d '\r' <"$path" | head -1)"
  [[ "$st" == "$PREVIOUS_HOP_TERMINAL_STATE" ]] || return 1

  ver="$(read_os_field VERSION_ID)"
  code="$(read_os_field VERSION_CODENAME)"
  [[ -z "$code" ]] && code="$(read_os_field UBUNTU_CODENAME)"
  if [[ "$ver" != "20.04" || "$code" != "focal" ]]; then
    log ERROR "QUARANTINE_RECOVERY=REFUSED reason=OS_MISMATCH backup=${q}"
    return 1
  fi

  # Prefer quarantine-bundled pins/manifest ownership when live copies are missing.
  pins_hop="$(read_live_pins_hop)"
  manifest_hop="$(read_live_manifest_hop)"
  if [[ -z "$pins_hop" && -f "${q}/previous-pins.env" ]]; then
    pins_hop="$(read_kv_file_field "${q}/previous-pins.env" PIN_HOP || true)"
  fi
  if [[ -z "$pins_hop" && -f "${q}/pins.env" ]]; then
    pins_hop="$(read_kv_file_field "${q}/pins.env" PIN_HOP || true)"
  fi
  if [[ -z "$manifest_hop" && -f "${q}/previous-client-manifest.json" ]]; then
    manifest_hop="$(sed -n 's/.*"hop"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' "${q}/previous-client-manifest.json" 2>/dev/null | head -1)"
  fi
  if [[ -n "$pins_hop" && "$pins_hop" != "$PREVIOUS_HOP_PIN_NAME" && "$pins_hop" != "focal-to-jammy" ]]; then
    log ERROR "QUARANTINE_RECOVERY=REFUSED reason=PIN_OWNER_UNKNOWN hop=${pins_hop} backup=${q}"
    return 1
  fi

  set +e
  current_hop_mutation_evidence_present
  mut_rc=$?
  set -e
  if [[ "$mut_rc" -eq 0 ]]; then
    log ERROR "QUARANTINE_RECOVERY=REFUSED reason=MUTATION_EVIDENCE backup=${q}"
    return 1
  fi
  if [[ "$mut_rc" -eq 2 ]]; then
    # Ambiguous live markers without previous-hop pins → refuse blind restore.
    if [[ "$pins_hop" != "$PREVIOUS_HOP_PIN_NAME" && "$manifest_hop" != "$PREVIOUS_HOP_PIN_NAME" ]]; then
      log ERROR "QUARANTINE_RECOVERY=REFUSED reason=AMBIGUOUS_MUTATION_EVIDENCE backup=${q}"
      return 1
    fi
  fi
  if detect_upgrade_already_running; then
    log ERROR "QUARANTINE_RECOVERY=REFUSED reason=ACTIVE_RUNNER backup=${q}"
    return 1
  fi
  # Contradictory current-hop mid-states must not exist beside a blank state.
  local mid
  for mid in CONFIGURING PREPARING_FOCAL UPGRADING_FOCAL_TO_JAMMY REBOOT_PENDING REBOOTING \
    POST_BOOT_VERIFY FAILED_AFTER_PACKAGE_TRANSITION; do
    if [[ -f "$(hostpath ${STATE_ROOT}/runner_stage)" ]] \
      && grep -qx "$mid" "$(hostpath ${STATE_ROOT}/runner_stage)" 2>/dev/null; then
      log ERROR "QUARANTINE_RECOVERY=REFUSED reason=CONTRADICTORY_RUNNER_STAGE=${mid} backup=${q}"
      return 1
    fi
  done

  log INFO "QUARANTINE_RECOVERY_CANDIDATE=${q}"
  log INFO "QUARANTINE_RECOVERY_STATE=${st}"
  # Restore previous-hop terminal into the live state file atomically, then accept handoff.
  mkdir -p "$(dirname "$(hostpath "$STATE_FILE")")"
  if ! write_state_atomic "$st"; then
    log ERROR "QUARANTINE_RECOVERY=REFUSED reason=RESTORE_WRITE_FAILED"
    return 1
  fi
  log INFO "QUARANTINE_RECOVERY=RESTORED_PREVIOUS_HOP_STATE"
  log INFO "QUARANTINE_RECOVERY_SOURCE=${q}"
  return 0
}

handle_existing_state() {
  local st ver
  st="$(read_state)"
  ver="$(read_os_field VERSION_ID)"
  case "$ver" in
    24.04|26.04)
      die "$EC_OS" "this one-hop script refuses OS ${ver}; use a later hop tool after validation"
      ;;
  esac
  if [[ "$ver" == "22.04" ]]; then
    if [[ "$st" == "COMPLETED_JAMMY" ]]; then
      log INFO "already COMPLETED_JAMMY — nothing to do"
      exit 0
    fi
    # Previous-hop terminal on Jammy is a contradiction — fail closed.
    if [[ "$st" == "$PREVIOUS_HOP_TERMINAL_STATE" ]]; then
      log ERROR "HOP_HANDOFF_VALIDATION=FAIL"
      log ERROR "HOP_HANDOFF_REJECT_REASON=OS_VERSION_MISMATCH"
      log ERROR "PREVIOUS_HOP_STATE=${st}"
      log ERROR "CURRENT_OS=${ver}"
      die "$EC_STATE" "FAIL_PREVIOUS_HOP_HANDOFF_REJECTED (state=${st} os=${ver})"
    fi
    log INFO "Jammy with state='${st}' — running post-boot verification only"
    if [[ -x "$(hostpath "$POSTBOOT_PATH")" ]]; then
      bash "$(hostpath "$POSTBOOT_PATH")"
      exit $?
    fi
    die "$EC_STATE" "Jammy host but post-boot helper missing; manual validation required"
  fi

  # Live systemd/process evidence wins even if state file is stale.
  if detect_upgrade_already_running; then
    refuse_duplicate_upgrade
  fi

  # Case B: blank/missing live state + quarantined COMPLETED_FOCAL evidence.
  if [[ -z "$st" ]]; then
    if try_recover_previous_hop_state_from_quarantine; then
      st="$(read_state)"
    else
      return 0
    fi
  fi

  case "$st" in
    ""|PREFLIGHT|READY_FOR_CONFIRMATION) return 0 ;;
    CONFIGURING|PREPARING_FOCAL)
      # Stale preparing/configuring without live runner/service/DRO → diagnose, do not MONITOR_ONLY.
      if allow_live_systemctl && ! live_upgrade_evidence_present; then
        handle_stale_pre_dro_state "$st"
        # After classification, fall through like FAILED for safe-resume assessment.
        st="$(read_state)"
        if [[ "$st" == "FAILED_PRE_DRO_STALE" || "$st" == "FAILED_PRE_DRO" || "$st" == "FAILED" ]]; then
          log INFO "previous state=${st}; assessing safe resume"
          if assess_safe_resume_from_failed; then
            write_state "READY_FOR_RESUME"
            log INFO "state transition ${st} -> READY_FOR_RESUME (safe pre-mutation resume)"
            return 0
          fi
          log ERROR "stale/terminal pre-DRO failure; refusing automatic upgrade start"
          log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS:-UNCLASSIFIED}"
          die "$EC_STATE" "STALE_STATE_RECOVERY_REQUIRED (state=${st})"
        fi
      fi
      refuse_duplicate_upgrade
      ;;
    UPGRADING_FOCAL_TO_JAMMY|REBOOT_PENDING|REBOOTING|POST_BOOT_VERIFY|POST_UPGRADE_VERIFY)
      refuse_duplicate_upgrade
      ;;
    FAILED_AFTER_PACKAGE_TRANSITION|FAILED_POST_TRANSACTION)
      log ERROR "FAIL_PARTIAL_RELEASE_TRANSITION_DETECTED: previous state=${st}; refusing automatic resume"
      log ERROR "RELEASE_UPGRADE_PACKAGE_TRANSITION_STARTED=true"
      log ERROR "ROLLBACK_ELIGIBLE=NO"
      log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS:-PACKAGE_TRANSITION_OR_UNKNOWN}"
      log ERROR "log: ${LOG_FILE}"
      die "$EC_STATE" "FAIL_PARTIAL_RELEASE_TRANSITION_DETECTED (state=${st})"
      ;;
    FAILED|BLOCKED|FAILED_PRE_DRO|FAILED_PRE_DRO_STALE|FAILED_BEFORE_PACKAGE_TRANSITION)
      log INFO "previous state=${st}; assessing safe resume"
      if assess_safe_resume_from_failed; then
        # Clear FAILED so confirmation + reconfigure can proceed; do not auto-start DRO.
        write_state "READY_FOR_RESUME"
        log INFO "state transition FAILED -> READY_FOR_RESUME (safe pre-mutation resume)"
        return 0
      fi
      log ERROR "FAIL_PARTIAL_RELEASE_TRANSITION_DETECTED: previous state=${st}; refusing automatic resume"
      log ERROR "PREVIOUS_FAILURE_CLASS=${PREVIOUS_FAILURE_CLASS:-UNCLASSIFIED}"
      log ERROR "log: ${LOG_FILE}"
      if [[ -z "$TEST_ROOT" ]]; then
        dpkg --audit || true
        apt-get check || true
      fi
      die "$EC_PARTIAL_TRANSITION" "FAIL_PARTIAL_RELEASE_TRANSITION_DETECTED"
      ;;
    READY_FOR_RESUME)
      log INFO "state READY_FOR_RESUME — continuing preflight for re-confirmation"
      return 0
      ;;
    COMPLETED_FOCAL)
      # Inherited previous-hop terminal success — validate and hand off into this hop.
      accept_previous_hop_terminal_state "$st"
      return 0
      ;;
    COMPLETED_JAMMY)
      # Target-hop terminal on non-Jammy OS is a contradiction (Jammy handled above).
      log ERROR "FAIL_STATE_OS_CONTRADICTION: state=COMPLETED_JAMMY but OS=${ver}"
      die "$EC_STATE" "FAIL_STATE_OS_CONTRADICTION (state=COMPLETED_JAMMY os=${ver})"
      ;;
    *)
      local corrupt_dest
      corrupt_dest="$(hostpath ${BACKUP_ROOT}/corrupt-state-$(date -u '+%Y%m%dT%H%M%SZ'))"
      mkdir -p "$corrupt_dest"
      cp -a "$(hostpath "$STATE_FILE")" "$corrupt_dest/state" 2>/dev/null || true
      die "$EC_STATE" "unrecognized/corrupt state='${st}' preserved at ${corrupt_dest} (not deleted)"
      ;;
  esac
}


main() {
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --mirror-base)
        MIRROR_BASE="${2:-}"; shift 2 || die "$EC_USAGE" "--mirror-base requires URL"
        ;;
      --mode)
        case "${2:-}" in
          os-only|OS_ONLY|OS_ONLY_PHASE1)
            UPGRADE_MODE="OS_ONLY_PHASE1"
            ;;
          *)
            die "$EC_USAGE" "unsupported --mode '${2:-}' (Phase 1 supports: os-only)"
            ;;
        esac
        shift 2 || die "$EC_USAGE" "--mode requires value"
        ;;
      --help|-h) usage; exit 0 ;;
      --detach)
        DETACH_AFTER_HANDOFF=1; shift ;;
      --preflight-only)
        DRY_PREFLIGHT_ONLY=1; shift ;;
      *)
        die "$EC_USAGE" "unknown argument: $1"
        ;;
    esac
  done

  # Test harness hooks — keep logical paths; hostpath() prefixes TEST_ROOT at access.
  TEST_ROOT="${DP_OFFLINE_TEST_ROOT:-}"
  STATE_ROOT="/opt/aelladata/os-upgrade/offline"
  STATE_FILE="${STATE_ROOT}/state"
  HISTORY_FILE="${STATE_ROOT}/hop_history"
  LOG_FILE="/var/log/aella/offline_os_upgrade.log"
  BACKUP_ROOT="${STATE_ROOT}/backups"
  ENV_DEFAULT_FILE="/etc/default/stellar-offline-os-upgrade"
  PIN_ENV_FILE="${STATE_ROOT}/pins.env"
  RUNNER_PID_FILE="${STATE_ROOT}/runner.pid"
  HOLDS_DIR="${STATE_ROOT}/critical-holds"
  CURRENT_HOP_ENV_FILE="${STATE_ROOT}/current-hop.env"
  META_RELEASE_FILE="/etc/update-manager/meta-release"
  KEYRING_PATH="/etc/apt/trusted.gpg.d/stellar-offline-focal-to-jammy.gpg"
  LEGACY_APT_KEYRING_PATH="$KEYRING_PATH"
  DISTUPGRADE_SOURCES_PATH="${STATE_ROOT}/distupgrade-target.sources.list"
  RUNNER_PATH="/usr/local/sbin/stellar-offline-os-upgrade-runner"
  POSTBOOT_PATH="/usr/local/sbin/stellar-offline-os-upgrade-postboot"

  # Default Phase 1 mode (explicit env override for tests).
  if [[ "${DP_OFFLINE_UPGRADE_MODE:-}" == "OS_ONLY_PHASE1" || "${DP_OFFLINE_UPGRADE_MODE:-}" == "os-only" ]]; then
    UPGRADE_MODE="OS_ONLY_PHASE1"
  fi
  UPGRADE_PHASE=1

  ensure_log_dir
  maybe_enable_control_flow_debug
  # Multi-hop: inspect/accept previous-hop terminal BEFORE loading transaction flags.
  # Loading bionic-to-focal markers into b2f globals causes false CURRENT_HOP_MUTATION.
  handle_existing_state
  load_current_hop_identity_vars || true
  load_release_upgrade_started_flag_for_current_hop
  detect_partial_release_transition

  local work
  work="$(mktemp -d /tmp/stellar-offline-upgrade.XXXXXX)"
  # shellcheck disable=SC2064
  trap "main_exit_trap '$work'" EXIT
  decode_embedded_assets "$work"

  # Phase 1 path: OS preflight -> (confirm) -> OS upgrade. Product stages not called.
  run_os_preflight "$work"
  assert_preflight_ready_state

  if [[ "$DRY_PREFLIGHT_ONLY" -eq 1 ]]; then
    log INFO "preflight-only requested — no confirmation, no persistent changes"
    # Intentional success with READY_FOR_CONFIRMATION — disable silent-exit guard.
    _OS_PREFLIGHT_ENTERED=0
    exit 0
  fi

  prompt_confirmation
  local upgrade_rc=0
  set +e
  run_os_upgrade "$work"
  upgrade_rc=$?
  set +e
  if [[ "$upgrade_rc" -ne 0 ]]; then
    # Terminal / handoff failure: never emit success handoff or post-upgrade validation.
    CLIENT_HANDOFF_RESULT="${CLIENT_HANDOFF_RESULT:-FAIL}"
    CLIENT_EXIT_REASON="${CLIENT_EXIT_REASON:-BACKGROUND_UPGRADE_FAILED}"
    log ERROR "CLIENT_HANDOFF_RESULT=${CLIENT_HANDOFF_RESULT}"
    log ERROR "CLIENT_EXIT_REASON=${CLIENT_EXIT_REASON}"
    _OS_PREFLIGHT_ENTERED=0
    trap - EXIT
    rm -rf "$work"
    exit "$upgrade_rc"
  fi
  run_os_post_upgrade_validation

  # Handoff (+ optional interactive progress monitor) completed inside commit_and_start.
  # Upgrade runner continues under systemd independently of this client process.
  _OS_PREFLIGHT_ENTERED=0
  trap - EXIT
  rm -rf "$work"
  exit "$EC_OK"
}

main "$@"
